(61, 'BTU-E3EF88AF', 1, 'Mr.', 'PUNOBYIN', 'MOSES PUNOBRE TIBIL', 'mpunobyin@yahoo.com', '+233241121010', 'BOLGATANGA S.H.S,\r\nP.O BOX 176,\r\nBOLGATANGA, GHANA', 'YINDURI', 'YINDURI', 'Upper East', 'GHANAIAN', 'CHRISTIANITY', 'married', 'ELIZABETH TINDAN', 'UPPER EAST REGIONAL HOSPITAL, BOLGATANGA', '1. YINTOMYA ARCHER TIBIL PUNOBYIN-23-07-2022\r\n\r\n2. ENGSOMMA ARCHER TIBIL PUNOBYIN-17-11-2024', NULL, 'GHA-715808405-6', '1990-03-26', 'male', 'Master\'s Degree (MPhil.)', 'UNIVERSITY FOR DEVELOPMENT STUDIES', 1, NULL, 'As a professional teacher grounded in medical laboratory practice, and an aspiring lawyer with a background in biomedical science and health law, I am committed to advancing medical laboratory education. My focus is on imparting knowledge on the medico-legal implications of laboratory practice, the legal and regulatory framework of laboratory operations, and opportunities in biomedical entrepreneurship.', 'no', 'no', NULL, 'no', NULL, 'I enjoy spending my free time reading, playing with, and teaching my children. It keeps me grounded and constantly reminds me of the value of clear communication and patience.', 'IMMEDIATELY', 'As a professional teacher grounded in medical laboratory practice, and an aspiring lawyer with a background in biomedical science and health law, I am committed to advancing medical laboratory education. My focus is on imparting knowledge on the medico-legal implications of laboratory practice, the legal and regulatory framework of laboratory operations, and opportunities in biomedical entrepreneurship. \r\n\r\nMy interdisciplinary training positions me to contribute meaningfully to technical university education by preparing students who are competent in practice, aware of legal obligations, and capable of driving innovation in the biomedical sector.', 'MR. JONATHAN AWONONG', 'TEACHER', 'HEAD OF DEPARTMENT, SCIENCE', 'Bolgatanga S.H.S, P. O Box 176, WINKOGO.', '0244856117', NULL, 'MR. JOSEF KRIS AKUBAH', 'EDUCATIONAL ADMINISTRATOR', 'DIRECTOR', 'GREAT VICTORY ACADEMY, \r\nP. O Box 176, \r\nBOLGATANGA', '02401222200', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_E3EF88AF_cv_6a142a6e6fd536.32568509.pdf', 'BTU CV-1.pdf', 'pending', NULL, '154.161.41.3', '2026-05-25 10:54:38', '2026-06-07 23:59:41', 'BTU_E3EF88AF_photo_6a142a6e6fd598.98430751.jpg', 'passport copy.jpg'),
(62, 'BTU-D224F7B2', 15, 'Ms.', 'DOWUONA', 'ALEXANDRA NORLEY', 'salexied@yahoo.com', '0244985680', 'DEPARTMENT OF BASIC EDUCATION, UNIVERSITY OF EDUCATION, WINNEBA. P. O. BOX WB 25. WINNEBA', 'WINNEBA', 'OSU KINKAWE - ACCRA', 'Central', 'GHANAIAN', 'CHRISTIAN', 'single', NULL, NULL, 'RAEL NANA AMA AGYEIWAA YANKSON - 8TH DECEMBER, 2012', 'P0014847558', 'GHA-720222204-1', '1980-06-27', 'female', 'Master\'s Degree (MPhil.)', 'UNIVERSITY OF EDUCATION, WINNEBA', 11, NULL, 'My experience as a Chief Administrative Assistant is relevant to this position because I have sixteen years of experience in the administrative field. It has equipped me with strong administrative, communication, organizational and record management skills. with my experience coordinating office activities, preparing reports, handling confidential information and supporting management in achieving institutional goals. these skills together with my ability to work effectively with staff and stakeholders makes me well prepared to contribute efficiently to academic and administrative operation as an Assistant Registrar.', 'no', 'no', NULL, 'no', NULL, 'Event planning and Implementation\r\nReading and exploring the internet\r\nWriting and Journaling\r\nTime management games', 'Immediately', NULL, 'PROF. CHARLES KWESI KOOMSON', 'LECTURER', 'FORMER HEAD OF DEPARTMENT', 'DEPARTMENT OF INTERGRATED SCIENCE\r\nUNIVERSITY OF EDUCATION, WINNEBA', '0244729714', 'ckkoomson@uew.edu.gh , charleskkoomson@gmail.com', 'DR MRS NELLY ADJOA SAKYI-HAGAN', 'LECTURER', 'HEAD OF DEPARTMENT', 'DEPARTMENT OF INTEGRATED SCIENCE EDUCATION\r\nUNIVERSITY OF EDUCATION, WINNEBA', '0205477918', 'nsakyihagan@uew.edu.gh, maamekuumah@yahoo.com', 'DR ERNEST I. D. NGMAN-WARA', 'LECTURER', 'FORMER HEAD OF DEPARTMENT', 'DEPARTMENT OF INTEGRATED SCIENCE EDUCATION\r\nUNIVERSITY OF EDUCATION, WINNEBA', '0244150836', 'immaare@yahoo.com', 'BTU_D224F7B2_cv_6a142f1653b474.72943492.pdf', 'alexa cv.pdf', 'pending', NULL, '41.74.94.16', '2026-05-25 11:1