(92, 'BTU-672E4ED8', 14, 'Mr.', 'SUWIE', 'MOHAMMED SADAT', 'mssuwie@gmail.com', '0244184663', 'ISLAMIC SHS, P. O. BOX 1393, ADUM-KUMASI', 'WA', 'WA', 'Upper West', 'GHANAIAN', 'ISLAM', 'married', 'MARIZUKA ABUBAKARI', 'C/O ISLAMIC SHS P.O.BOX 1393, KUMASI', 'IMRAN NUNTAA SUWIE - 15/01/2019\r\nKHALIFAH SUNGWAE SUWIE - 07/05/2022\r\nRUMAISA MWNENBANG SUWIE - 16/07/2024', 'GHA-716530671-6', 'GHA-716530671-6', '1994-09-03', 'male', 'Master\'s Degree (Other)', 'AKENTEN APPIAH MENKAH UNIVERSITY OF SKILLS TRAINING AND ENTREPRENEURIAL DEVELOPMENT', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'READING RELIGIOUS BOOKS AND PLAYING VIDEO GAMES', 'I MONTH', 'I WORK AS A FULL TIME TEACHER AND A PART TIME AUDIT STAFF.', 'DR. FRANK YAO GBADAGO', 'LECTURER', 'HEAD OF ACCOUNTING DEPARTMENT, AAMUSTED', 'AAMUSTED, P. O. BOX 1277, KUMASI', '0242824124', NULL, 'DOUGLAS AGYENIM BOATENG', 'AUDITOR', 'AUDIT MANAGER', 'MBA ASSOCIATES, P. O. BOX KS 8227, ADUM-KUMASI', '0242507914', 'douglasaboateng@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_672E4ED8_cv_6a15b91ca802f4.90160433.pdf', 'CURRICULUM VITAE - MOHAMMED SADAT SUWIE.pdf', 'pending', NULL, '154.160.1.221', '2026-05-26 15:15:40', '2026-06-07 23:59:41', 'BTU_672E4ED8_photo_6a15b91ca80350.42857550.jpeg', 'SMS PASSPORT.jpeg'),
(93, 'BTU-B8870098', 8, 'Mr.', 'Frimpong', 'George', 'fgee2@yahoo.com', '+233246672196', 'Post Office Box KS 13453. Adum-Kumasi, Ashanti Region', 'Juaben', 'Juaben', 'Ashanti', 'Ghanaian', 'Christianity', 'married', 'Mrs. Mary Owusu Frimpong', 'Post Office Box KS 13453. Adum-Kumasi, Ashanti Region', NULL, 'P0016222695', 'GHA-717316135-6', '1984-06-02', 'male', 'Master\'s Degree (MPhil.)', 'University of Skills Training and Entrepreneurial Development', 11, 'The influence of Implementation of Ghana\'s integrated financial management information system in senior high schools', 'With my practice as a Chartered Accountant and Chartered Tax Practitioner in a research institute, I am highly equipped to prepare students through teaching and coaching for the business world.\r\nI also have a Post Chartered Diploma in Public Financial Management and a certificate in the International Public Sector Accounting Standards, which I believe would help me deliver effectively if I am offered the opportunity to teach as a Lecturer.', 'no', 'no', NULL, 'no', NULL, 'Learning, listening to music (Adadam), cooking, fast learner, and having fruitful discussion.', '1 month. This will enable me to prepare and formally part ways with my current employer', 'I am a qualified Chartered Accountant and Chartered Tax Practitioner. I also have a Post Chartered Diploma in Public Financial Management and a certificate in the International Public Sector Accounting Standards, which I believe would help me deliver effectively if I am offered the opportunity to teach as a Lecturer.', 'Mr. Samuel Lartey Odame,', 'Accountancy', 'Head, Accounts Department', 'Post Office Box KS 13453. Adum-Kumasi, Ashanti Region', '0202411006', 'samuelodame3@gmail.com', '1.	Ms. Dina Ansaa Okyere', 'Auditor', 'Head, Internal Audit', 'Post Office Box KS 13453. Adum-Kumasi, Ashanti Region', '0203748984/054490344', 'afuaokyere@yahoo.com', '2.	Dr Richard Owusu- Afriyie', 'Lecturer/Auditing', 'Lecturer', 'Post Office Box KS 13453. Adum-Kumasi, Ashanti Region', '0244418800', 'richardowusuafriyie@ymail.com', 'BTU_B8870098_cv_6a15bf74df3c33.48742778.pdf', 'George Frimpong CV 2026.pdf', 'pending', NULL, '102.69.223.89', '2026-05-26 15:42:44', '2026-06-07 23:59:41', 'BTU_B8870098_photo_6a15bf74df3c72.47192703.jpg', 'Passport pic White Background.JPG');
