(110, 'BTU-39D79E4C', 3, 'Mr.', 'AKANBONGA', 'AGUUYA MAXWELL', 'maxwell.akanbonga14@gmail.com', '0244714510', 'BOLGATANGA TECHNICAL UNIVERSITY, POST OFFICE BOX 767, BOLGATANGA, GHANA.', 'KATANGA', 'ZUARUNGU', 'Upper East', 'GHANAIAN', 'CHRISTIAN ( CATHOLIC)', 'single', NULL, NULL, NULL, 'P0035303700', 'GHA-715893952-9', '1991-01-07', 'male', 'Master\'s Degree (Other)', 'BOLGATANGA TECHNICAL UNIVERSITY', 5, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'READING AND RESEARCH, LISTENING TO MUSIC  AND PLAYING SOCCER', 'IMMEDIATELY', NULL, 'PROFESSOR PETER OSEI BOAMAH', 'PROFESSOR', 'PRO-VICE CHANCELLOR', 'BOLGATANGA TECHNICAL UNIVERSITY, POST OFFICE BOX 767, BOLGATANGA, GHANA.', '0241076993', 'pierrodecota@gmail.com', 'MR. JOSEPH APODI', 'SENIOR LECTURER', 'SENIOR LECTURER( FORMER HOD)', 'BOLGATANGA TECHNICAL UNIVERSITY, POST OFFICE BOX 767, BOLGATANGA, GHANA.', '0249307161', 'joseph@bolgatu.edu.gh.com', 'Professor Isaac Gibberson Dukuh', 'PROFESSOR', 'SENIOR LECTURER', 'BOLGATANGA TECHNICAL UNIVERSITY, POST OFFICE BOX 767, BOLGATANGA, GHANA.', '0208562135', 'isaacgdukuh@yahoo.com', 'BTU_39D79E4C_cv_6a16f82040f8d0.39739546.pdf', 'AGRIC ENGEERING CERT.pdf', 'pending', NULL, '154.161.246.87', '2026-05-27 13:56:48', '2026-06-07 23:59:41', 'BTU_39D79E4C_photo_6a16f82040f924.71568927.jpg', 'passport_001.jpg'),
(111, 'BTU-09A94585', 6, 'Mr.', 'ANOBYA', 'DANIEL', 'anobyad@gmail.com', '0557993301', 'BOLGATANGA TECHNICAL INSTITUTE, POST OFFICE BOX 295', 'BOLGATANGA', 'GAMBIBGO', 'Upper East', 'GHANAIAN', 'Christian', 'married', 'ANATIA LETICIA', 'WORLD LIGHT TEMPLE, BOX 349', 'ADONGO RACHEL - 12/01/2011\r\nADONGO ROSEMOND - 05/04/2016\r\nADONGO RICHMAOND - 29/12/2019\r\nADONGO - RAPHEAL - 14/06/2022', 'P0010295526', 'GHA-718031818-7', '1992-09-23', 'male', 'Master\'s Degree (Other)', 'UNIVERSITY OF EDUCATION, WINNEBA', 11, NULL, 'I was appointed as a part-time Lecturer by the University during 2023/2024 academic year during which I discharge my duties perfectly. I was allocated four different courses by the HOD.', 'no', 'no', NULL, 'no', NULL, 'Reading \r\nFootball\r\nResearch', 'Immediately', NULL, 'HON. AZAM ALOSIBA', 'PUBLIC SERVANT', 'RETAIRED REGIONAL DIRECTOR OF POPULATION COUNCEL, UPPER EAST', 'WORLD LIGHT TEMPLE, BOX 349', '0209955792', 'azamalosiba@gmail.com', 'REV. THOMAS APANA', 'EDUCATIONALIST', 'HEADMASTER, TONGO SENIOR HIGH SCHOOL', 'TONGO SENIOR HIGH SCHOOL, BOX 30', '0244179293', 'apanathomas@yahoo.com', 'PASTOR EMMANUEL ABOTA', 'PASTOR', 'REGIONAL PASTOR OF WORLD LIGHT TEMPLE', 'WORLD LIGHT TEMPLE, BOX 349', '0207519662', NULL, 'BTU_09A94585_cv_6a170598a09040.20416156.pdf', 'CURRICULUM VITAE.pdf', 'pending', NULL, '74.244.119.103', '2026-05-27 14:54:16', '2026-06-07 23:59:41', 'BTU_09A94585_photo_6a170598a09084.27504382.jpg', 'passport 26.jpg'),
(112, 'BTU-F2E5E90B', 10, 'Mr.', 'SACKITEY', 'Peter', 'sackiteypa@gmail.com', '+233598267772', 'Osu Troas Street\r\nAccra, Ghana\r\nP.O. Box 19872, Accra-North, Accra\r\nDigital Address: GA-082-6568', 'Kumasi', 'Mepe', 'Volta', 'Ghanaian', 'Christianity', 'married', 'Priscilla Appiah Agyekum', 'Accra', 'SACKITEY Agbenyega Giovanni  (22/12/2025)', NULL, 'GHA-727624070-9', '1994-06-28', 'male', 'Master\'s Degree (MPhil.)', 'Kwame Nkrumah University of Science and Technology (KNUST)', 3, '• LoDaPro: Combining Local Detail and Global Projection for Improved Image Quality Assessment Using EfficientNet and Vision Transformer. https://doi.org/10.51519/journalisi.v7i3.1186                                  \r\n\r\n• Multimodal Malware Detection under Adversarial and Obfuscated Conditions Using \r\nResNet-50 and MLP Encoders with Contrastive Learning and Adaptive Cross-Modal \r\nFusion. https://doi.org/10.60097/ACIG/219075       \r\n                             \r\n• SRM-DPCNN: A Lightweight SRM-Guided Dual-Path CNN for Steganographic Image Detection on Edge Devices                                                                                                               — Under Review  \r\n\r\n• Sequence-Based Multiclass Malware Detection Using CNN and Bidirectional LSTM Networks.                                                                                                                        \r\n\r\n                                                                                                                                   — Under Review', 'My teaching experience spans Information Security, Operating System Security, Networks and Data Communications, Computer Architecture and Organization, Cybersecurity Risk Management, Computing Ethics, Data and Network Security, Application Security, and Ethical Hacking. My teaching philosophy emphasizes participatory and hands-on learning, integrating theoretical foundations with practical application through laboratory sessions, real-world projects, and discussions.', 'no', 'no', NULL, 'no', NULL, 'Playing and Watching Football', '2 weeks', NULL, 'Dr. Ahene Emmanuel', 'Lecturer', 'Senior Lecturer (KNUST)', 'Kwame Nkrumah University of Science and Technology, Kumasi, Ghana', '+233 203 434 503', 'aheneemmanuel@knust.edu.gh', 'Dr. Michael Mark Addae', 'Lecturer', 'HOD, Health &amp; Allied Sciences', 'Baldwin University College, Accra, Ghana\r\nOsu Troas Street\r\nAccra, Ghana\r\nP.O. Box 19872, Accra-North, Accra\r\nDigital Address: GA-082-6568', '+233246242047', 'dr.maddaem@gmail.com', 'Dr. Pratt Koomson', 'Cyber Security Manager', 'Head of Cyber Security,    Ghana Water Head Office', 'Accra, Ghana Water Head Office', '+2330244879188', 'prattkoomson@gmail.com', 'BTU_F2E5E90B_cv_6a1707de49a350.20807357.pdf', 'BSc_certificate.pdf', 'pending', NULL, '154.161.38.10', '2026-05-27 15:03:58', '2026-06-07 23:59:41', 'BTU_F2E5E90B_photo_6a1707de49a394.14839669.jpg', 'PassPort Pic.jpg'),
(113, 'BTU-4D42FC90', 3, 'Mr.', 'Achuliwor', 'Rockyfeller', 'rockyfeller@gmail.com', '0245368691', 'Our Lady of Lourdes Girls\'\' Senior High School \r\nBox 5o\r\nNavrongo', 'Navrongo', 'Navrongo', 'Upper East', 'Ghanaian', 'Christianity', 'divorced', NULL, NULL, 'Achuliwor Ajegewe Riquelme \r\nAchuliwor Atulam Richelle \r\nAchuliwor Anedam Riley-Rembert', NULL, 'GHA-715855265-0', '1982-11-15', 'male', 'Master\'s Degree (MPhil.)', 'Kwame Nkrumah University of Science and Technology', 5, NULL, 'My experience is very relevant to to position applied for in that the duties and responsibilities of a lecturer and very similar if not the same to what I do as a teacher. This and my experience in the research area as evidenced during my masters degree research where I combined field experiment and laboratory analysis.', 'no', 'no', NULL, 'no', NULL, 'Reading articles about scientific research \r\nWorking with a team in the field \r\nWatching European soccer matches \r\nWatching and or listening to parliamentary debate', 'Immediately', 'My strongest weapon is teaching methodology. I have a unique way of letting students understand what I teach irrespective of the technicality of the material involved.', 'Professor Gordana Kranjac-Berisavljevic', 'Lecturing', 'Senior Lecturer', 'West African Center for Water, Irrigation and Sustainable Agriculture (WACWISA)\r\nUniversity for Development Studies -Tamale \r\nBox TL 1350', '0244467142', 'novagordanak@ gmail.com', 'Dr. Robert Niayale', 'Lecturing', 'Head of Department, Vertinary Medicine', 'University for Development Studies \r\nBox TL 1350\r\nTamale', '0245368549', 'niayalerobert@gmail.com', 'Mrs. Mary Akampoi Amana', 'Teaching', 'Headmistress, Our Lady of Lourdes Girls&#039;&#039; Senior High', 'Our Lady of Lourdes Girls\'\' Senior High School\r\nBox 50\r\nNavrongo', '0551486711', 'adatuweyeichiga@gmail.com', 'BTU_4D42FC90_cv_6a170fc456f469.04548714.pdf', 'Master of Philosophy Cert (3) (1).pdf', 'shortlisted', '', '102.176.65.73