(136, 'BTU-28265BA4', 13, 'Mr.', 'Philip', 'Ayelikar', 'payelikar@isevolutionsconsult.com', '+233200942085', NULL, 'Bolgatanga', 'Bolgatanga', 'Upper East', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, 'GHA-723388865-4', 'GHA-723388865-4', '1997-08-08', 'male', 'HND', 'Sunyani Technical University', 5, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Reading\r\nTechnology\r\nSports\r\nMusic', '1 week', NULL, 'Manuel Adjei', 'Software Engineer', 'Chief Technical Officer', 'IS Evolutions Consult Ltd\r\nAccra - Ghana', '?233 539274956?', 'madjei@isevolutionsconsult.com', 'Ali Eric Ayine', 'Teacher', 'Head of Department', 'Bolgatanga Technical Institute\r\nBolgatanga - Ghana', '233 244845857', 'eric.ayine@gmail.com', 'Mrs. Faustina Teni Awuni', 'Administrator', 'Administrator', 'Tongo District Hospital\r\nTongo - Ghana', '233 20422567', NULL, 'BTU_28265BA4_cv_6a1823f16f9bc4.82800196.pdf', 'Ayelikar Philip Resume.pdf', 'pending', NULL, '102.176.77.163', '2026-05-28 11:16:01', '2026-05-28 11:16:01', 'BTU_28265BA4_photo_6a1823f16f9c08.24036008.jpeg', 'Philip Ayelikar.jpeg'),
(137, 'BTU-B127C135', 15, 'Mr.', 'Baah', 'Kwaku Jnr', 'kwakubaahjr@gmail.com', '+233207918049', '10 McCarthy Hill, Accra, Ghana', 'Accra', 'Accra', 'Greater Accra', 'Ghana', 'Christian', 'single', NULL, NULL, NULL, NULL, NULL, '1979-06-20', 'male', 'Master\'s Degree (Other)', 'Unity College', 7, '1. Recruitment Issues- Maine Game Warden Service\r\n2. Agricultural Laws in Sub Saharan Africa', 'Dear Hiring Committee,\r\n\r\nI am writing to express my interest in the Assistant Registrar position at Bolgatanga Technical University. With a strong academic foundation in law, mediation, and conservation law enforcement, complemented by extensive professional experience in administration, compliance, and academic support, I am confident in my ability to contribute effectively to the Registry and the University’s broader mission.\r\n\r\nIn my role as Administrative Specialist II at the University of Maine System, I managed daily operations of the Registrar’s Office, overseeing student registration systems, academic records, and compliance processes. I implemented university-wide policies, coordinated with government agencies, and supported staff development initiatives—ensuring accuracy, efficiency, and a high-quality student experience. These responsibilities sharpened my skills in administration, policy implementation, and human resource support, directly relevant to assisting the Registrar in managing BTU’s administrative and HR functions.\r\n\r\nAs a Judicial Clerk in Baltimore City Juvenile Court, I applied regulatory knowledge, managed sensitive documentation, and communicated effectively with judges, attorneys, and the public. This role demanded precision, discretion, and professionalism under pressure—qualities I bring to academic administration. My mediation background, including certification as an International Accredited Civil/Commercial Mediator, further strengthened my ability to resolve issues, foster collaboration, and maintain fairness in complex environments.\r\n\r\nI am particularly motivated by the opportunity to contribute to BTU’s mission of advancing technical education and institutional transformation. I am eager to apply my skills in administration, compliance, and stakeholder engagement to support the Registrar’s office in delivering efficient services and strengthening the University’s governance structures.\r\n\r\nThank you for considering my application. I look forward to the opportunity to discuss how my background and expertise align with the Assistant Registrar role and Bolgatanga Technical University’s vision.\r\n\r\nSincerely,\r\nKwaku Baah Jnr', 'no', 'no', NULL, 'no', NULL, 'Hiking, swimming, kayaking, cycling, skiing, running, yoga, etc.', 'Immediately', 'N/A', 'Karin', 'Registrar', 'Registrar', 'University of Southern Maine, USA', '+001 2077805230', 'karin.pires@maine.edu', 'Leticia Gholson', 'Manager- Circuit Court', 'Manager', '300 N. Gay St. Baltimore, MD USA 21202', '+001 4432632362', 'leticia.gholson@mdcourts.gov', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_B127C135_cv_6a1830ea237332.15953805.pdf', 'Resume1.pdf', 'pending', NULL, '154.161.117.203', '2026-05-28 12:11:22', '2026-06-07 23:59:41', 'BTU_B127C135_photo_6a1830ea237393.68761045.jpeg', 'IMG_9319.jpeg'),
(138, 'BTU-CBEA9D29', 13, 'Mr.', 'SULEMANA', 'ABDULAI', 'abdulaisulemana343@yahoo.com', '+233540477937', 'UGLC, BOX 23\r\nTAMALE.', 'LANGA', 'LANGA', 'Northern', 'GHANAIAN', 'ISLAM', 'married', 'YAKUBU BARIKISU', 'TAMALE', 'SULEMANA FATIMA SUGLO - 07/12/2024', 'GHA-714680051-0', 'GHA-714680051-0', '1990-04-16', 'male', 'Master\'s Degree (Other)', 'UTAS', 5, 'BEGINNERS LADDER PUBLISHED BY LAP LAMBERT ACADEMIC PUBLICATION AND KINDLE DIRECT PUBLICATION', 'HAVING WORKED CLOSELY WITH THE COLLEGE PRINCIPAL AND THE IT TEAM, I HAD THE OPPORTUNITY TO TEACH DBS STUDENTS AND ASSISTED STUDENTS WITH SERVICES REGARDING THE SAKAI LEARNING MANAGEMENT SYSTEM LOGIN AND NAVIGATION CHALLENGES. IN LIGHT OF THE ABOVE, I STRONGLY BELIEVE THAT SUCH EXPERIENCE WILL BE RELEVANT TO ME WHEN I AM GIVEN THE CHANCE TO WORK AS A SENIOR ICT ASSISTANT.', 'no', 'no', NULL, 'no', NULL, 'COMPUTING AND RESEARCH', '1 Month', NULL, 'DR. MOSES Y. NAMOOG', 'LECTURER', 'PRINCIPAL', 'UGLC, BOX 23\r\nTAMALE.', '0244220988', 'mynamoog@ug.edu.gh', 'Yakubu Yussif Abubakari', 'BANKER', 'RISK, COMPLIANCE AND AML OFFICER', 'UGLC, BOX 23\r\nTAMALE.', '0559256999', 'ayyussif@bonzaliruralbank.com', 'YINYEH OPHELIUS', 'TEACHING', 'LECTURER', 'UGLC, BOX 23\r\nTAMALE.', '0246240888', 'Ophelius24@gmail.com', 'BTU_CBEA9D29_cv_6a1831e92ed5c6.83326633.pdf', 'SULEMANA ABDULAI CURRENT CV 2026.pdf', 'pending', NULL, '143.105.209.165', '2026-05-28 12:15:37', '2026-06-07 23:59:41', 'BTU_CBEA9D29_photo_6a1831e92ed608.64378192.jpg', 'IMG-20231107-WA0017.jpg');
