(142, 'BTU-C8544E82', 14, 'Mr.', 'Zumankyere', 'Desmond Grasie', 'grasiedz@gmail.com', '+233543961255', 'Lawra Senior High School, P. O. Box 22, Lawra- Upper West Region, Ghana', 'Tizza, Jirapa Municipal', 'Daffiama- Tuori', 'Upper West', 'Ghanaian', 'Christianity', 'single', NULL, NULL, NULL, 'P0015367576', 'GHA-715455965-9', '1989-06-19', 'male', 'Professional Certificate', 'Institute of Chartered Accountants Ghana', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Reading business and financial publications\r\nLeadership and mentoring activities\r\nOrganizing events and programs\r\nPublic speaking\r\nChurch/fellowship leadership activities', 'Immediately', 'Please note that I successfully completed the Institute of Chartered Accountants, Ghana (ICAG) professional examinations in the March 2026 diet and have therefore qualified as a Chartered Accountant. However, the official induction and graduation ceremony is scheduled for October 2026, after which my certificate will be issued.\r\n\r\nIn place of the certificate, I have attached my official ICAG transcript as evidence of qualification and successful completion of the programme.', 'Hulede Abraham Aryee', 'Accountant', 'Accountant', 'Lawra Senior High School, P. O. Box 22, Lawra, Upper West Region', '0209021551', 'huledeabraham@gmail.com', 'Dr Moses Dumayiri', 'Lecturer', 'Senior Lecturer &amp; Quality Assurance Officer,', 'School of Business, University of Business and Integrated Development Studies, Wa, Upper West Region', '0246 755 969', 'mdumayiri@uds.edu.gh', 'Mr. Cletus Asoogo', 'Chartered Insurance Broker', 'Area Manager', 'SIC Life Insurance Co. Ltd, Tamale', '0244 131 621', 'asoogocletus@yahoo.com', 'BTU_C8544E82_cv_6a1846b03aef04.45392673.pdf', 'CV DESMOND ZUMANKYERE.pdf', 'pending', NULL, '154.161.123.193', '2026-05-28 13:44:16', '2026-05-28 13:44:16', 'BTU_C8544E82_photo_6a1846b03aef52.14502257.jpg', 'passport 1.jpg.jpg'),
(143, 'BTU-A4460D0F', 1, 'Mr.', 'Addae', 'Richard Addae', 'r.kudzo10@gmail.com', '+233557902272', 'Richard Kudzo Addae, Keta Senior High Technical School, P. O. Box kw122, Dzelukope, Keta', 'Hohoe', 'Leklebi Duga', 'Volta', 'Ghanaian', 'Christianity', 'married', 'Blessing Amekudzi', 'b.amekudzi11@gmail.com', 'Amos Anket Addae - 10/06/2010\r\nPhyllis Seyram Addae - 28/05/2020', NULL, 'GHA-713641102-1', '1987-09-28', 'male', 'Master\'s Degree (MPhil.)', 'Kwame Nkrumah University of Science and Technology, Kumasi', 7, 'Manuscripts under review in a high-profile peer-reviewed scientific journal:\r\n1. Production and evaluation of Chicken IgY antibodies induced by different adjuvants against Echis ocellatus venom.\r\n2. Proteomic analysis of snake venom obtained from Naja melanoleuca in Ghana.', 'My teaching, research, and laboratory experience are highly relevant to the position advertised. I have experience mentoring undergraduate students in research and laboratory procedures, which has strengthened my teaching and supervisory skills. My laboratory experience includes protein quantification, PCR analysis, cell viability assays, IgY purification and venom toxicity studies, which equipped me with strong practical and technical competence. In addition, my MPhil and ongoing PhD research in Biochemistry at KNUST have enhanced my analytical and scientific writing skills, enabling me to contribute effectively to teaching, practical laboratory training, and research activities.', 'no', 'no', NULL, 'no', NULL, 'Reading and watching football', 'I would assume immediately within the time-frame specified by the university.', NULL, 'Prof. Caleb Kesse Firempong', 'Lecturer', 'Head of Department', 'Kwame Nkrumah University of Science and Technology, Kumasi,\r\nCollege of Science,\r\nDepartment of Biochemistry and Biotechnology', '+233208243995', 'calebuse@yahoo.com', 'Prof. Fareed Kow N. Arthur', 'Lecturer', 'Lecturer', 'Kwame Nkrumah University of Science and Technology, Kumasi,\r\nCollege of Science,\r\nDepartment of Biochemistry and Biotechnology.', '+233558101447', 'fareedarthur@yahoo.com', 'Amegashie Anthony', 'Teacher', 'Head of Science Department', 'Keta Senior High Technical School, P. O. Box kw122, Dzelukope, Keta.', '+233507741918', 'amegashieanthony1974@gmail.com', 'BTU_A4460D0F_cv_6a18479eeffcd8.61782507.pdf', 'RICHARD KUDZO ADDAE CV_MEDICAL LABORATORY.pdf', 'pending', NULL, '154.161.136.107', '2026-05-28 13:48:14', '2026-06-07 23:59:41', 'BTU_A4460D0F_photo_6a18479eeffd34.99430758.jpeg', 'R. K. ADDAE PASSPORT PICTURE.jpeg'),
