(158, 'BTU-EF3BB47C', 2, 'Mr.', 'NABWOMYA', 'DABIL ERNEST', 'ernestnabwomya16@gmail.com', '+233 242688092', 'Deeper Christian Life Ministry, P.O. Box 358, Bolgatanga – Upper East Region, Ghana.', 'GAARE-TONGO', 'GAARE', 'Upper East', 'GHANAIN', 'CHRISTIAN', 'married', 'VIDA NAOH AGANA', 'Deeper Christian Life Ministry, P.O. Box 358, Bolgatanga – Upper East Region, Ghana.', 'CONRAD YINMOYA NABWOMYA, 24/01/2021\r\nEMPRESS-CHIKA YINSONGMANE NABWOMYA 27/08/2022', 'P0017846587', 'GHA-715563668-1', '1983-09-07', 'male', 'Master\'s Degree (MPhil.)', 'SD Dombo University of Business and Integrated Development Studies (SDD-UBIDS), Wa 2021 – 2024', 7, 'Peer-Reviewed Journal Publication\r\nAmosah, J., Lukman, T., &amp; Nabwomya, E. D. (2023). Assessing Indigenous and Modern Adaptation Strategies to Climate Change among Legumes Producers in Bongo District. American Journal of Evironment and limate. https://doi.org/10.54536/ajec.v2i2.1584.\r\nMANUSCRIPTS UNDER REVIEW\r\n	The Role of Local Knowledge Systems in Disaster Management (Journal of Geography – University of Ghana)\r\nCONFERENCE PRESENTATION\r\nBridging Climate Change and Mitigation Strategies among Smallholder Farmers. Presented at the 4th Research and Development Conference, SDD-UBIDS, 2024.', 'My academic background in Project Management and Community Development, combined with a Postgraduate Diploma in Education, has equipped me with both the theoretical knowledge and pedagogical competence necessary for effective teaching at the tertiary level. Over the years, I have taught Economics, Social Structure of Ghana, Development Theories, and Research Methods at both secondary and tertiary levels. Through these teaching experiences, I have adopted participatory approaches such as group discussions, case study analysis, practical assignments, and student presentations to improve understanding and classroom engagement.', 'no', 'no', NULL, 'no', NULL, 'Reading \r\nListening to Music', '2 Weeks', NULL, 'AMOSAH JONAH (PhD)', 'LECTURER', 'SENIOR LECTURER', 'University of Business and Integrated Development Studies\r\nP. O Box 64 wa Upper West Region Ghana', '+233244454552', 'jamosah@ubids.edu.gh', 'Tahiru Lukman', 'Development Consultant', 'Chief Executive Officer of Ideapath Consult', 'Ideapath Consult  Limited \r\nP. O Box 19 Wa- Upper West Region', '+233 209154057', 'lukmantahiru@rocketmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_EF3BB47C_cv_6a1895c5a36163.10016696.pdf', 'NABWOMYA\'S CV.pdf', 'pending', NULL, '102.176.101.19', '2026-05-28 19:21:41', '2026-06-07 23:59:41', 'BTU_EF3BB47C_photo_6a1895c5a361a9.77419222.jpg', 'NABWOMYA.jpg'),
(159, 'BTU-72F3CAE1', 2, 'Mr.', 'Amoah', 'Isaac Anagdor', 'mmabilaike7@gmail.com', '+233204475255', 'C/o Gambibgo Community Day Senior High School \r\nP. O. Box 224\r\nBolga East - UE/R', 'Bolgatanga', 'Kongo', 'Upper East', 'Ghanaian', 'Christian', 'married', 'Konlan Malinka Jennifer', 'UB - 0003 - 1772', 'Nagraug Yineboma Kimani (10-01-2026)', NULL, 'GHA-716029142-2', '1990-01-01', 'male', 'Master\'s Degree (MPhil.)', 'C. K. Tedam Univeristy of Technology and Applied Sciences', 2, NULL, 'With extensive experience in teaching, I think I can guide my students with my in-depth knowledge by breaking large concepts into smaller bits for learners to comprehend. With my learner-centred approach, students will benefit from.', 'no', 'no', NULL, 'no', NULL, 'Researching and playing football.', 'Immediately', 'always ready to learn', 'Dr. Anaba Oswin', 'Lecturer', 'Head of Department of Liberal Studies', 'Bolgatanga Technical University \r\nP. O. Box 767 \r\nSumbrungu - Bolgatanga\r\nUpper East Region', '0244574332', 'oanaba@bolgatu.edu.gh', 'Prof. Christian John Etwire', 'Lecturer', 'Head of Mathematics Department', 'University of Technology and Applied Sciences \r\nP. O. Box 24 \r\nNavrongo \r\nUpper East Region', '0246013140', 'cetwire@cktutas.edu.gh', 'Mr. James Adaebsah', 'Teacher', 'Assistant Head of Academics', 'Gambibgo Community Day Senior High School \r\nP. O. Box 224\r\nBolga East - UE/R', '0244114383', 'adaebsahjames@gmail.com', 'BTU_72F3CAE1_cv_6a189e5c53d083.67229062.pdf', 'Certificates.pdf', 'pending', NULL, '102.176.32.199', '2026-05-28 19:58:20', '2026-06-07 23:59:41', 'BTU_72F3CAE1_photo_6a189e5c53d0e8.27131165.jpeg', '20220527113117706.jpeg'),
(160, 'BTU-A9CDC4C6', 1, 'Mr.', 'Alagpulinsa', 'Justin Yaw', 'justinalagpulinsa@yahoo.com', '+233246557649', 'Amiah Hospital \r\nP. O. Box 302\r\nBolgatanga', 'Chuchuliga', 'Nawaasa', 'Upper East', 'Ghanaian', 'Christianity', 'single', NULL, NULL, NULL, 'P0053081765', 'GHA-727815063-1', '1990-04-07', 'male', 'Master\'s Degree (MPhil.)', 'C.K Tedam University of Technology and Applied Sciences', 2, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Reading and listening to news', '2 weeks', NULL, 'Professor James Abugri', 'Lecturer', 'Dean, School of Chemical and Biochemical Sciences', 'C. K. Tedam University of Technology and Applied Sciences \r\nP. O. Box 24\r\nNavrongo', '+233244994359', 'jabugri@cktutas.edu.gh', 'Dr Samuel Kofi Tchum', 'Biomedical Scientist', 'Regional Biomedical Scientist', 'Kintampo Health Research Center \r\nGhana Health Service\r\nKintampo North.', '+233244923774', 'kofi.tchum@kintampo-hrc.org', 'Dr Charles Nkansah', 'Lecturer', 'Head of Haematology Department', 'University for Development Studies \r\nP. O. Box TL1350\r\nTamale - Dungu', '+233247626378', 'cnkansah@uds.edu.gh', 'BTU_A9CDC4C6_cv_6a189f779ef6a1.51196817.pdf', 'Curriculum Vitae_Justin1.pdf', 'shortlisted', '', '102.176.95.170', '2026-05-28 20:03:03', '2026-06-12 23:06:18', 'BTU_A9CDC4C6_photo_6a189f779ef6d6.63237906.jpg', '1000000418.jpg'),
(161, 'BTU-3B3C697A', 10, 'Mr.', 'Anabire', 'Anthony', 'ayorigo1986@gmail.com', '+233554870640', 'Box 464\r\nBolgatanga UER\r\n\r\nQ5V5+9G, Bolgatanga', 'Bolgatanga', 'Yorogo', 'Upper East', 'Ghanaian', 'Christian', 'married', NULL, NULL, NULL, 'P0056650981', 'GHA-715292604-4', '1986-07-24', 'male', 'Master\'s Degree (Other)', 'University of Strathclyde, Glasgow, UK', 2, 'Agambire, R. J., Mensah, R., &amp; Anabire, A. (2022). Digitization and the performance of MSME: The perspective of Ghana post COVID-19. In SME financing approaches and strategies: Global perspective (pp. 39–48). National Institute for Micro, Small and Medium Enterprises. ISBN: 97881-957897-1-9', 'My teaching, research, and professional experience are highly relevant to the position I am applying for. I hold an MSc in Advanced Computer Science with Data Science from the University of Strathclyde, Glasgow, where I gained advanced knowledge in data science, machine learning, software development, and computational research.\r\nI am currently engaged in academic and research-related roles at Regentropfen University College in Ghana and at the Bolgatanga Technical University (BTU), where I contribute to teaching support, academic development, and research activities. These roles continue to strengthen my experience in higher education, particularly in delivering effective instruction, supporting student learning, and engaging in academic research collaborations.\r\nPreviously, through my roles as a Postgraduate Teaching Assistant, Computer Laboratory Assistant, and Research Assistant at the University of Strathclyde, I supported undergraduate teaching, laboratory practical sessions, formative assessments, research activities, and online learning platforms. These experiences strengthened my teaching, technical, and research capabilities in higher education.\r\nIn addition, I have over ten years of experience teaching ICT and Computing in Ghana at both the High school and the Junior high school, including lecturing and supervising students at tertiary-level institutions. My expertise includes programming in python, databases, computer networks, machine learning, data visualization, and educational technology.\r\nFurthermore, my professional training at the Ghana-India Kofi Annan Centre of Excellence in ICT, together with my academic exposure to higher education engagement, soft skills development, and data governance, has equipped me with strong communication, leadership, teamwork, and academic management skills essential for effective teaching, research, and institutional development.', 'no', 'no', NULL, 'no', NULL, 'football and reading Tech news', '2 weeks', NULL, 'James Kok konjaang (PhD)', 'Lecturing', 'Head Of Department', 'Department of Computing  and Information Technology\r\nBolagatanga Technical University \r\nBox 767\r\nBolgatanga', NULL, 'dujasco11@gmail.com', 'Rev. Augustine Owusu-Addo (PhD)', 'Educationist', 'Dean of the Faculty of Education', 'Catholic University of Ghana \r\nP.O Box 363  \r\nSunyani', NULL, 'aoaddo@cug.edu.gh', 'Andrew Abel (PhD)', 'Lecturing', 'Snr Lecturer', 'Strathclyde Chancellor’s Fellow\r\nUniversity of Strathclyde Glasgow\r\nUnited Kingdom', NULL, 'andrew.abel@strath.ac.uk', 'BTU_3B3C697A_cv_6a18cf9e654335.60346015.pdf', 'anthonyAnabire_CV_.pdf', 'shortlisted', '', '154.161.101.132', '2026-05-28 23:28:30', '2026-06-12 23:35:09', 'BTU_3B3C697A_photo_6a18cf9e654385.03503428.jpg', '4450_010841.jpg'),
(162, 'BTU-3638A9DF', 14, 'Ms.', 'Afriyie', 'Joyce Osei', 'aafriyie430@gmail.com', '+233201144035', 'P. O. Box AN 2357, Kumasi, Ghana', 'Kumasi', 'Kumasi', 'Ashanti', 'Ghanaian', 'Christianity', 'married', 'Stephen Asare', 'P. O. Box AN 2357, Kumasi', 'Kwadwo Opoku Asare - 25 September, 2006\r\nKwabena Afriyie Asare - 24 May, 2011', NULL, 'GHA-716787642-0', '1974-10-10', 'female', 'Professional Certificate', 'Institute of Chartered Accountants Ghana', 11, NULL, 'I am currently working as audit senior, with Richard Owusu-Afriyie and Associates, Kumasi.  This has really equipped me with real-world Auditing and Accounting application.   I have led  audit team to audit and perform other accounting services like financial statements preparation, tax planning and others for many community banks, non-financial companies and private universities across Ghana.  \r\nAs a teacher, I have taught Financial Accounting, Cost Accounting, English Language and Text Processing.  I was the head of Languages Department at Kofi Agyei Senior High School for three years, member of the guidance and counselling committee and staff secretary.  This has given me insight about Accounting and had also helped me in developing good communication skills, critical thinking ability. I am confident, that my education, knowledge and practical experience has prepared me enough to do well as Accountant.', 'no', 'no', NULL, 'no', NULL, 'Singing, writing and reading', '1 month', 'I am the current internal auditor for The Methodist Church Ghana, Buokrom-Estate Circuit', 'Mr. Kingsley Anning', 'Auditor', 'Audit Manager', 'P. O. Box AH 15, Kumasi, Ghana', '0241033478', 'anningkotoko@yahoo.com', 'Rev. Dr. Alfred Atakora', 'Lecturer', 'Lecturer', 'P . O. Box 854, Kumasi, Ghana', '0244955350', 'alfred.atakora@kstu.edu.gh', 'Mr. Ebenezer Ofosu Aboagye', 'Teaching', 'Headmaster', 'P. O. Box AN 2471, Kumasi, Ghana', '0243659581', 'kofiagyeishs1991@gmail.com', 'BTU_3638A9DF_cv_6a18d03e711b45.42122177.pdf', 'CV JOYCE OSEI AFRIYIE.pdf', 'pending', NULL, '102.176.65.88', '2026-05-28 23:31:10', '2026-05-28 23:31:10', 'BTU_3638A9DF_photo_6a18d03e711bc6.67194121.jpg', 'IMG_20260528_232245.jpg'),
