(165, 'BTU-6CBFEDDA', 15, 'Ms.', 'Abubakari', 'Rashidatu Anthonete', 'abubakarianthonete@gmail.com', '+233533816818', 'C% Fountain Gate Chapel - Desert Pastures, Bolgatanga. Upper East Region.', 'Navrongo,', 'Brifoh- lawra District', 'Upper East', 'Ghananian', 'Christain', 'single', NULL, NULL, NULL, NULL, NULL, '1990-09-14', 'female', 'Master\'s Degree (Other)', 'University of Professional Studies, Accra', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Cooking and Baking', '3weeks', NULL, 'KAYODE WAHAB', 'ASC MANAGER', 'ASC MANAGER', 'Trannsion Technology Ghana Ltd, Accra', '0242857429', 'Kayode.wahab@carlcare.com', 'Souleymane Nia-Dinkings', NULL, 'MD', 'Dynasty Consulting - USA', '+1 901-649-7585', 'simmie1519@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_6CBFEDDA_cv_6a19354d41b2e8.54430522.pdf', 'Assistant_Registrar_CV_Rashidatu_Abubakari.pdf', 'pending', NULL, '102.176.77.139', '2026-05-29 06:42:21', '2026-06-07 23:59:41', 'BTU_6CBFEDDA_photo_6a19354d41b326.71038464.jpeg', 'DSC_6059.jpeg'),
(166, 'BTU-75966D44', 8, 'Mr.', 'Dogbire', 'Emmanuel Sobil', 'sobilism85@gmail.com', '+233508167556', 'Ghana Broadcasting Corporation\r\nP.O.Box 43\r\nBolgatanga\r\nUpper East Region', 'Nangodi', 'Nangodi', 'Upper East', 'Ghanaian', 'Christian (Catholic)', 'married', 'Nang Evelyn Mwinkum', 'Ghana Broadcasting Corporation P.O.Box 43 Bolgatanga, Upper East Region', 'Dogbire-Sobil Reign Yensong-12/10/2020\r\nDogbire-Sobil Renee Naamaami-15/11/2024', 'P001086024X', 'GHA-712402295-5', '1990-11-05', 'male', 'Master\'s Degree (MPhil.)', 'University of Technology and Applied Science', 0, 'Dogbire, E. S., &amp; Abonongo, J. (2026). Volatility modeling, persistence and half-life measures of selected financial equities on the Ghana stock exchange. Innovation in Computer and Data Sciences. https://doi.org/10.64389/icds.2026.02167', 'My publication titled “Volatility Modeling, Persistence and Half-life Measures of Selected Financial Equities on the Ghana Stock Exchange” is relevant to a lecturer position in Finance and Accounting because it focuses on financial market analysis, stock price behavior, risk measurement, and econometric modeling within the Ghana Stock Exchange context. The study demonstrates my ability to apply quantitative and statistical techniques in analyzing financial data, which is essential in teaching courses such as Financial Management, Investment Analysis, Financial Markets, Corporate Finance, Econometrics, and Research Methods.\r\nAdditionally, the publication contributes to knowledge in finance by examining market volatility and persistence in equity returns, which are important concepts in portfolio management, risk assessment, and investment decision-making. The research also reflects my capacity for academic research, scholarly writing, and data-driven analysis, which are key competencies required of a university lecturer in Finance and Accounting.', 'no', 'no', NULL, 'no', NULL, 'Reading and football', 'Immediately', 'I am currently pursuing a Doctor of Philosophy at University of Technology and Science', 'Dr. John Abonongo', 'Lecturer', 'Senior Lecturer', 'University of Applied Science and \r\nTechnology, Navrongo \r\n adoham5006@gmail.com\r\n 0540745006', '0249297656', 'jabonongo@cktutas.edu.gh', 'Mr. Abraham Adongo', 'Forester', 'Human Resource Manager', 'Ghana Forestry Commission\r\nP.O.Box 232\r\nSefwi-Wiawso, Western North,\r\nGhana', '0540745006', 'adoham5006@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_75966D44_cv_6a195892606679.36896009.pdf', 'Dogbire E. Sobil_CV.pdf', 'pending', NULL, '102.176.77.249', '2026-05-29 09:12:50', '2026-06-07 23:59:41', 'BTU_75966D44_photo_6a1958926066d0.64502753.jpg', 'JPEC PIC.jpg'),
