(168, 'BTU-97D0F501', 2, 'Mr.', 'Quansah', 'Abraham', 'quansahabraham48@gmail.com', '+233546067032', 'Takoradi', 'Takoradi', 'Takoradi', 'Western', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, NULL, 'GHA730892283-8', '1993-12-31', 'male', 'Master\'s Degree (Other)', 'Ohio University', 2, NULL, 'During my studies and professional engagements, I developed strong instructional and\r\nmentoring abilities, working with diverse groups of students to help them achieve their\r\nacademic goals. I am particularly passionate about making Mathematics practical and\r\naccessible, encouraging students to think analytically and apply concepts to real-world\r\nsituations.\r\nI would be honored to bring my knowledge, enthusiasm, and commitment to your organization.', 'no', 'no', NULL, 'no', NULL, 'Watching science documentaries, football', 'Immediately', NULL, 'Kwaku Darkwah', 'Professor', 'Teaching', 'Knust', '0207187522', 'fordarkk@gmail.com', 'Singh Prem', 'Professor', 'Teaching', NULL, '+19087205242', 'psinghms@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_97D0F501_cv_6a1960631e4e87.42295893.pdf', 'Abraham Resume.pdf', 'pending', NULL, '154.160.11.55', '2026-05-29 09:46:11', '2026-06-07 23:59:41', 'BTU_97D0F501_photo_6a1960631e4ec6.63559621.jpg', 'DSC_0048.JPG'),
