(178, 'BTU-C4E2D85B', 13, 'Mr.', 'AMPONSAH', 'OMENAKO GEORGE', 'obede44@gmail.com', '233244766580', NULL, 'New Tafo Akim', 'Akuapim Akropong', 'Eastern', 'Ghanaian', NULL, 'single', NULL, NULL, NULL, NULL, 'GHA-721208338-2', '1989-06-16', 'male', 'Bachelor\'s Degree', 'University for Development Studies', 11, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Listening to music', '1 week', NULL, 'John Boakye', 'Lecturer, Jahan College, Wa', 'ICT Lecturer', NULL, '0551170370', 'johnboakye@gmail.com', 'Rev Theophilus Nyameba Dadzie', 'Nyamebasusu Enterprise', 'Manager', NULL, '0242113031', 'nyamebasusu@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_C4E2D85B_cv_6a19cb9c42a5a9.56459802.pdf', 'GEORGE_OMENAKO_AMPONSAH___CV_2060 .pdf', 'pending', NULL, '154.161.165.101', '2026-05-29 17:23:40', '2026-06-07 23:59:41', 'BTU_C4E2D85B_photo_6a19cb9c42a603.83813917.jpg', 'ghanacard.jpg'),
(179, 'BTU-B0E54FE9', 13, 'Mr.', 'AMPONSAH', 'OMENAKO GEORGE', 'obede44@gmail.com', '233244766580', NULL, 'New Tafo Akim', 'Akuapim Akropong', 'Eastern', 'Ghanaian', NULL, 'single', NULL, NULL, NULL, NULL, 'GHA-721208338-2', '1989-06-16', 'male', 'Bachelor\'s Degree', 'University for Development Studies', 11, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Listening to music', '1 week', NULL, 'John Boakye', 'Lecturer, Jahan College, Wa', 'ICT Lecturer', NULL, '0551170370', 'johnboakye@gmail.com', 'Rev Theophilus Nyameba Dadzie', 'Nyamebasusu Enterprise', 'Manager', NULL, '0242113031', 'nyamebasusu@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_B0E54FE9_cv_6a19cd0c58bfa1.50691631.pdf', 'GEORGE_OMENAKO_AMPONSAH___CV_2060 .pdf', 'pending', NULL, '197.251.240.95', '2026-05-29 17:29:48', '2026-06-07 23:59:41', 'BTU_B0E54FE9_photo_6a19cd0c58bff6.55395937.jpg', 'ghanacard.jpg'),
(180, 'BTU-4B8900FA', 2, 'Mr.', 'Adongo', 'Abraham-Magsiah', 'adoham5006@gmail.com', '0540745006', 'ST. Francis of Assisi Catholic Church\r\nP. O .Box 339\r\nBolgatanga-Sumbrungu\r\nUpper East Region', 'Bolgatanga', 'Bolgatanga', 'Upper East', 'Ghanaian', 'Christian', 'married', 'Ivy Alagmah Anyebaase', NULL, NULL, NULL, 'GHA-716549187-8', '1989-09-06', 'male', 'PhD', 'University of Ghana', 7, '1. Contract Farming and Children\'s Education: Evidence From Maize Producers in Ghana (published in Q1 Journal - Sustainable Development. 8.2 Impact Factor)\r\n2. Four manuscripts under review in reputable journals', 'My background offers a strong and relevant foundation for a lectureship in the Department of Liberal Studies. What makes my profile particularly suitable is the blend of interdisciplinary academic training, extensive research practice, and direct experience facilitating learning for diverse student groups, including international cohorts.\r\n\r\nThe Department of Liberal Studies typically requires instructors who can connect the humanities and social sciences to broader developmental, ethical, and civic questions, exactly where my doctoral training in Development Studies at the University of Ghana’s ISSER becomes valuable. My coursework in development theories, Sociology, poverty analysis, political economy, and quantitative qualitative research etc. equips me to teach core liberal studies modules such as political economy of Ghana, social research methods, or contemporary development issues. The M.Phil. in Development Management and the BA in Integrated Community Development further reinforce his ability to bridge theory and practical application.\r\n\r\nTeaching relevance is not merely academic for me. Since 2023, I have served as an Academic and Research Seminar Leader for Kulturstudier and Oslo Metropolitan University, coordinating seminars and field research programs for Scandinavian students at the University of Cape Coast. I have supervised student dissertations and facilitated field research presentations - tasks nearly identical to what a liberal studies lecturer does when guiding project work and classroom discussions. This role demonstrates my ability to manage culturally diverse classrooms, foster critical thinking, and assess student performance.\r\n\r\nBeyond pedagogy, my work experience with the Forestry Commission, Ghana Statistical Service, and USAID-ADVANCE shows a professional who understands stakeholder negotiations, community engagement, and report writing at high levels. These are practical competencies that liberal studies students at a technical university need: writing policy briefs, analyzing household dynamics, and understanding governance structures. My 2024 authored report on household dynamics for the Ghana Statistical Service is a concrete example of applied research that can enrich course content.\r\n\r\nLeadership roles such as Vice President of the Doctoral Researchers Association and PhD Class President also point to organizational competence and the ability to manage group dynamics which is essential for curriculum coordination and student advising. With DAAD scholarships and international training from the University of Bonn and the University of Western Cape, Abraham brings a globally informed perspective without losing local relevance.\r\n\r\nIn short, my combination of research depth, cross-cultural teaching experience, and field-based development practice makes me a fitting candidate to deliver liberal studies content that is both intellectually rigorous and practically grounded for technical university students.', 'no', 'no', NULL, 'no', NULL, 'Travelling, football, watching or reading News items, etc.', '1 month', 'I have submitted my PhD thesis and waiting defense.\r\nI have two MPhil Degrees relating to development.\r\n\r\nI am a DAAD scholarship holder/alumni and hope to liaise with DAAD to partner with BTU on research grants and scholarships for students', 'Prof. Eric Oduro- Ofori', 'Lecturer', 'Associate Professor', 'Department of Planning\r\nKNUST\r\nKumasi', '0545607442', 'odurooforieric@yahoo.com', 'Dr. Simon Kanlisi Kaba', 'Lecturer', 'Senior Lecturer and HOD', 'Department of Organizational Studies and Development.\r\nUBIDS\r\nWa - Upper West Region.', '0545067421', 'skanlisi@uds.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_4B8900FA_cv_6a19cea7dedf93.21877861.pdf', 'CV_AbrahamAdongo_2026 05 28.pdf', 'shortlisted', '', '154.161.50.0', '2026-05-29 17:36:39', '2026-06-12 23:23:58', 'BTU_4B8900FA_photo_6a19cea7dee016.40004479.jpg', 'Passport Pic_New.jpg'),
(181, 'BTU-D1383CEB', 13, NULL, 'Ugbosanmi', 'James Adelaja', 'jamesonyemi@gmail.com', '+233548849140', '#6 Folk Street, Cfc Estate, Dome', 'Lagos', 'Lagos', 'Greater Accra', 'Nigerian', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1990-05-25', 'male', 'Professional Certificate', 'Ghana-India Kofi Annan Centre of Excellence in ICT (GI-KACE)', 5, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Technology &amp; Innovation\r\nTravel\r\nPeople &amp; Culture\r\nSoccer', '3 - 4 weeks', NULL, 'Rev. Ing. Hector Adjetey Boye', 'Civil Engineer &amp; Development Policy and Planning', 'Quality Control Manager  SANDHURST-AEC, LLC', 'Linkedin Profile:\r\nhttps://www.linkedin.com/in/hector-boye-b0282614/', NULL, NULL, 'Rev. Henry Awuku-Asante', 'Business Support /Facilities Manager &amp; Mechanical Engineer', 'Business Support /Facilities Manager', 'Linkedin Profile:\r\nhttps://www.linkedin.com/in/henry-awuku-asante-12076976/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_D1383CEB_cv_6a19d5a3973853.72926176.pdf', 'James_Adelaja_CV_BTU.pdf', 'pending', NULL, '41.155.55.84', '2026-05-29 18:06:27', '2026-05-29 18:06:27', 'BTU_D1383CEB_photo_6a19d5a3973894.19388325.jpg', 'james-photo.jpg'),
(182, 'BTU-D45BF0EF', 13, 'Mr.', 'YAKUBU', 'JAMES KUMBENI', 'kumbeni@live.com', '+233248453533', 'HGT A/G CHURCH\r\nP. O. BOX 581\r\nBOLGATANGA', 'BAARE', 'BAARE', 'Upper East', 'GHANAIAN', 'CHRISTIANITY', 'married', 'SAMAN ROSE NBAN', 'HGT A/G CHURCH, P. O. BOX 581, BOLGATANGA', 'KPALIMMAN KUMBENI—SEPTEMBER 5, 2023', 'P0016052765', 'GHA-715576573-6', '1996-04-09', 'male', 'Master\'s Degree (Other)', 'UNIVERSITY OF TECHNOLOGY &amp; APPLIED SCIENCES, NAVRONGO', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Cycling, Swimming, Touring, Volunteering', 'IMMEDIATELY', NULL, 'PROF. EDWARD Y. BAAGYERE', 'LECTURER', 'ACADEMIC DEAN', 'ACADEMIC DEAN \r\nSchool of Computing and Information Sciences,\r\nDepartment of Computer Science,\r\nUniversity of Technology and Applied Sciences,\r\nNavrongo, Ghana', '+233 24 999 0362', 'ebaagyere@cktutas.edu.gh', 'BLAISE BAMAANUORE BAYOR', 'HEALTH TUTOR', 'PRINCIPAL', 'THE PRINCIPAL\r\nCollege of Nursing and Midwifery, Tano Dumasi,\r\nNyinahin, Ashanti Region', '+233 24 485 1951', 'bbblaise77@yahoo.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_D45BF0EF_cv_6a19de32af12a6.68107020.pdf', 'CV_James Kumbeni Yakubu.pdf', 'shortlisted', '', '143.105.209.90', '2026-05-29 18:42:58', '2026-06-12 22:36:54', 'BTU_D45BF0EF_photo_6a19de32af1305.55689137.jpg', 'Passport Picture.JPG'),
(183, 'BTU-AC5E6089', 15, 'Mr.', 'Ahasu', 'Emmanuel Kwame', 'emmanuelahasu@yahoo.com', '+233246212181', 'P. O. Box AF 28\r\nAda Foah', 'Kasseh, Ada', 'Awate Dzifadzi', 'Volta', 'Ghanaian', 'Christian', 'married', 'Deborah Gidiglah', 'The Church of Pentecost, P. O. Box 46, Bedeku, Ada', 'Caleb Makafui Dzonto - 23/04/2015\r\nDorcas Mawufemor Dzonto - 18/04/2017', 'P0007201451', 'GHA-001218611-8', '1982-08-21', 'male', 'Master\'s Degree (MPhil.)', 'University of Education, Winneba', 7, 'Ahasu, E.K., et al. (2024). Role of community resources in education planning and delivery in Ghana.\r\n\r\nZang, P.L., et al. (2024). Socio-economic characteristics of education and learning aspiration: Mechanism of impact.\r\n\r\nAhasu, E.K. (2022). Parental involvement in pupils\' education and its effects on their academic achievement: A case study in the Ada East District of Ghana', 'My thorough understanding of curriculum, combined with a student-centred mindset and strong communication skills, makes me a valuable asset to the role of Assistant Registrar.\r\n\r\nMy experience in report writing, policy application, and attention to detail provides a solid foundation upon which I am confident I can excel in this tertiary institution role.\r\n\r\nMy previous role as Headmaster has well-prepared me for academic administration, including the management of academic calendars, timetabling, and team coordination. I have accumulated substantial administrative expertise, with proficiency in institutional technology systems and a strong commitment to organizational ethics. Additionally, I am experienced in student monitoring, research supervision, and taking decisive initiative when required.', 'no', 'no', NULL, 'no', NULL, 'Reading academic literature and education policy, volunteering in community mentorship programs, and participating in professional development workshops to stay current with trends in higher education administration.', '1 month is preferable', 'I am currently a PhD Candidate at the University of South Africa (UNISA). My studies are conducted entirely via distance mode and will therefore not interfere with the responsibilities of this position in any way.', 'Prof. Kwame Odei Tettey', 'Senior Lecturer', 'PhD candidate advisor', 'P. O. Box 25\r\nWinneba', '0542121550', 'ktettey@outlook.com', 'Dr. Moses Paafio Kwao', 'Lecturer', 'Assistant Registrar', 'Family Health University \r\nP. O. Box TS 669\r\nTeshie -Accra', '0243012185', 'mpkwao@fhu.edu.gh', 'Mr. Samuel Nii Okai', 'Human Resource', 'Unit Head, Human Resource Management and Development', 'P. O. Box AF 28, Ada Foah', '0209911636', 'gesdedaeaat@yahoo.com', 'BTU_AC5E6089_cv_6a19e063de90d0.08693641.pdf', 'CV_EMMANUEL KWAME AHASU_BUT.pdf', 'pending', NULL, '154.161.35.159', '2026-05-29 18:52:19', '2026-06-07 23:59:41', 'BTU_AC5E6089_photo_6a19e063de9110.11164294.jpeg', 'WA_1780003327339.jpeg'),
(184, 'BTU-50C0430D', 10, 'Mr.', 'YAKUBU', 'JAMES KUMBENI', 'kumbeni@live.com', '+233248453533', 'HGT A/G CHURCH\r\nP. O. BOX 581\r\nBOLGATANGA', 'BAARE', 'BAARE', 'Upper East', 'GHANA', 'CHRISTIANITY', 'married', 'SAMAN ROSE NBAN', 'HGT A/G CHURCH, BOX 581, BOLGATANGA', 'KPALIMMAN KUMBENI—SEPTEMBER 5, 2023', 'P0016052765', 'GHA-715576573-6', '1996-04-09', 'male', 'Master\'s Degree (Other)', 'UNIVERSITY OF TECHNOLOGY &amp; APPLIED SCIENCES, NAVRONGO', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Cycling, Swimming, Touring, Volunteering', 'IMMEDIATELY', NULL, 'PROF. EDWARD Y. BAAGYERE', 'LECTURER', 'ACADEMIC DEAN', 'School of Computing and Information Sciences,\r\nDepartment of Computer Science,\r\nUniversity of Technology and Applied Sciences,\r\nNavrongo, Ghana', '+233 24 999 0362', 'ebaagyere@cktutas.edu.gh', 'BLAISE BAMAANUORE BAYOR', 'HEALTH TUTOR', 'PRINCIPAL', 'THE PRINCIPAL\r\nCollege of Nursing and Midwifery, Tano Dumasi,\r\nNyinahin, Ashanti Region', '+233 24 485 1951', 'bbblaise77@yahoo.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_50C0430D_cv_6a19e3091696e4.26493816.pdf', 'CV_James Kumbeni Yakubu.pdf', 'pending', NULL, '143.105.209.90', '2026-05-29 19:03:37', '2026-06-07 23:59:41', 'BTU_50C0430D_photo_6a19e309169733.46627113.jpg', 'Passport Picture.JPG'),
(185, 'BTU-9120D8CE', 2, 'Mr.', 'Adongo', 'Abraham-Magsiah', 'adoham5006@gmail.com', '0540745006', 'ST. Francis of Assisi Catholic Church\r\nP. O .Box 339\r\nBolgatanga-Sumbrungu\r\nUpper East Region', 'Sumbrungu-Bolgatanga', 'Sumbrungu-Bolgatanga', 'Upper East', 'Ghanaian', 'Christian', 'married', 'Ivy Alagmah Anyebaase', NULL, NULL, NULL, 'GHA-716549187-8', '1989-09-06', 'male', 'PhD', 'University of Ghana', 7, '1. Contract Farming and Children\'s Education: Evidence From Maize Producers in Ghana, 2026 (Published in a Q1 Journal - Sustainable Development. 8.2 Impact Factor.\r\n2. Four manuscripts currently under review by reputable journals', 'My background offers a strong and relevant foundation for a lectureship in the Department of Liberal Studies. What makes my profile particularly suitable is the blend of interdisciplinary academic training, extensive research practice, and direct experience facilitating learning for diverse student groups, including international cohorts.\r\n\r\nThe Department of Liberal Studies typically requires instructors who can connect the humanities and social sciences to broader developmental, ethical, and civic questions, exactly where my doctoral training in Development Studies at the University of Ghana’s ISSER becomes valuable. My coursework in development theories, Sociology, poverty analysis, political economy, and quantitative qualitative research etc. equips me to teach core liberal studies modules such as political economy of Ghana, social research methods, or contemporary development issues. The M.Phil. in Development Management and the BA in Integrated Community Development further reinforce his ability to bridge theory and practical application.\r\n\r\nTeaching relevance is not merely academic for me. Since 2023, I have served as an Academic and Research Seminar Leader for Kulturstudier and Oslo Metropolitan University, coordinating seminars and field research programs for Scandinavian students at the University of Cape Coast. I have supervised student dissertations and facilitated field research presentations - tasks nearly identical to what a liberal studies lecturer does when guiding project work and classroom discussions. This role demonstrates my ability to manage culturally diverse classrooms, foster critical thinking, and assess student performance.\r\n\r\nBeyond pedagogy, my work experience with the Forestry Commission, Ghana Statistical Service, and USAID-ADVANCE shows a professional who understands stakeholder negotiations, community engagement, and report writing at high levels. These are practical competencies that liberal studies students at a technical university need: writing policy briefs, analyzing household dynamics, and understanding governance structures. My 2024 authored report on household dynamics for the Ghana Statistical Service is a concrete example of applied research that can enrich course content.\r\n\r\nLeadership roles such as Vice President of the Doctoral Researchers Association and PhD Class President also point to organizational competence and the ability to manage group dynamics which is essential for curriculum coordination and student advising. With DAAD scholarships and international training from the University of Bonn and the University of Western Cape, Abraham brings a globally informed perspective without losing local relevance.\r\n\r\nIn short, my combination of research depth, cross-cultural teaching experience, and field-based development practice makes me a fitting candidate to deliver liberal studies content that is both intellectually rigorous and practically grounded for technical university students.', 'no', 'no', NULL, 'no', NULL, 'Travelling, Listen/watching News, Football etc.', '1 month', 'I have submitted my PhD Thesis awaiting defense, Legon.\r\nI hold 2 MPhil Degrees with extensive field research experiences and ethics\r\n\r\nI am a DAAD-Germany &amp; Kulturstudier-Norway scholarship holder/alumni (MPhil &amp; PhD); if given the opportunity as a lecturer, I intend liaising with such bodies to partner with BTU for grants and scholarships for scholarships.', 'Prof. Eric Oduro- Ofori', 'Lecturer', 'Associate Professor', 'Department of Planning\r\nKwame Nkrumah University of Science and Technology (KNUST)\r\nKumasi', '0545607442', 'odurooforieric@yahoo.com', 'Dr. Simon Kanlisi Kaba', 'Lecturer', 'Senior Lecturer and HOD', 'Department of Organizational Studies and Development\r\nUniversity of Business and Integrated Development Studies\r\nWa\r\nUpper West Region.', '0545067421', 'skanlisi@uds.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_9120D8CE_cv_6a19edfe827591.80097305.pdf', 'CV_AbrahamAdongo_2026 05 28.pdf', 'pending', NULL, '154.161.50.0', '2026-05-29 19:50:22', '2026-06-07 23:59:41', 'BTU_9120D8CE_photo_6a19edfe8275d2.86949585.jpg', 'Passport Pic_New.jpg'),
(186, 'BTU-785DF1E6', 13, 'Mr.', 'FUSHEINI', 'ABUBAKARI', 'mrfusheiniabubakari@gmail.com', '+233200988971', 'NT-0428-6108', 'YENDI', 'TAMALE', 'Northern', 'GHANAIAN', 'ISLAM', 'married', 'MOHAMMED ZENAB SUHUYINI', 'NT-0428-6108', NULL, 'P0037751565', 'GHA-714903232-3', '1992-04-10', 'male', 'Bachelor\'s Degree', 'TAMALE TECHNICAL UNIVERSITY', 7, NULL, 'My academic background and professional experience closely align with the requirements of the Senior ICT Assistant position. I hold both an HND and a Bachelor’s Degree in Information Technology from Tamale Technical University, and I am currently pursuing a Master’s Degree in Artificial Intelligence. This academic journey has equipped me with strong knowledge in computer systems, networking, software development, database systems, and ICT management.\r\n\r\nProfessionally, I have worked as an IT Support Technician and IT Support Officer at reputable institutions including DOCUTECH Ghana Limited and the University for Development Studies. In these roles, I provided technical support, installed and maintained hardware and software systems, assisted in network and internet operations, troubleshot technical issues, and supported users to ensure smooth ICT operations.\r\n\r\nAdditionally, I have hands-on experience in website and software development using technologies such as HTML, CSS, JavaScript, PHP, and MySQL. My experience in both technical support and software-related tasks makes me capable of contributing effectively to system maintenance, ICT infrastructure support, and software implementation responsibilities required for this role.\r\n\r\nI am also a disciplined, service-oriented, and highly motivated individual with good communication and teamwork skills. I am passionate about using technology to improve institutional efficiency and contribute positively to organizational goals.', 'no', 'no', NULL, 'no', NULL, 'Watching documentaries and educational content\r\nExploring “How Things Work” and technology-related videos\r\nFollowing football highlights, tactical analysis, and expert discussions\r\nEngaging with comparative religion discussions and debates', '1 MONTH', 'I am a highly motivated Information Technology student who strongly believes that national development can be achieved through a pragmatic educational curriculum, discipline, innovation, and integrity.\r\n\r\nI am currently pursuing a master’s degree in Artificial Intelligence at the Tamale Technical University, with a strong passion for leveraging technology and innovation to solve real-world problems and contribute to national development.', 'Prof. Kennedy Kubuga', 'Lecturer', 'Senior Lecturer', NULL, '+233244887736', 'kkubuga@tatu.edu.gh', 'Dr. Yakubu Abdul-Wahab Nawusu', 'Lecturer', 'Senior Lecturer', NULL, '+233246392966', 'nabdul wahab@tatu.edu.gh', 'Prof. Gordana Kranjac Berisavljevic', 'Director', 'WACWISA, University for Development Studies', NULL, '+233244467142', 'novagordanak@gmail.com', 'BTU_785DF1E6_cv_6a19f46a5bd1f4.63873312.pdf', 'BTECH TRANSCRIPT_.pdf', 'shortlisted', '', '154.161.136.181', '2026-05-29 20:17:46', '2026-06-12 22:37:10', 'BTU_785DF1E6_photo_6a19f46a5bd236.23517302.jpg', 'PASSPORT PIC.jpg'),
(187, 'BTU-453885F4', 3, 'Mr.', 'Ayamga', 'Anthony Kagbire', 'barista.ayamga@gmail.com', '+233247271001', 'College of Health, Nalerigu. P. O. Box 10, Nalergu-NER', 'Bolgatanga', 'Bolgatanga', 'Upper East', 'Ghanaian', 'Christianity', 'married', 'Charity Kaloh Avuyem', 'Ghana Immigration Service. North East regional Office, Nalerigu.', '1. Ayamga Nelson Nsolebina (29/08/2019)\r\n2. Ayamga Newton Sumpaana (29/08/2019)\r\n3. Ayamga Thelma Abisiyine (15/04/2023)', 'P0034034110', 'GHA-715139152-0', '1988-11-21', 'male', 'Master\'s Degree (MPhil.)', 'University for Development Study', 7, '1. Pre- and postnatal factors associated with child growth in the first 2 years of life: A cross-sectional analysis. https://onlinelibrary.wiley.com/doi/10.1155/adph/3768676', 'My expertise in Academic Teaching, Mentorship, and Assessment equips me with the ability to effectively deliver lectures, guide students academically, supervise practical work, and assess student performance using appropriate pedagogical approaches. This is essential in developing competent agricultural professionals.\r\n\r\nMy competence in LMS and E-learning Platforms supports modern teaching and learning by facilitating online instruction, digital content delivery, student engagement, and assessment, thereby enhancing blended and technology-driven education.\r\n\r\nExperience in Research Supervision and Scientific Writing positions me to mentor students in research methodology, proposal development, project supervision, and scientific report writing, contributing to evidence-based practice and academic excellence.\r\n\r\nMy understanding of Curriculum Development enables me to contribute meaningfully to the design, review, and implementation of competency-based curricula that align with current trends and practical demands in education.', 'no', 'no', NULL, 'no', NULL, 'Teaching and learning', 'Immediately', NULL, 'Dr. Mahama Saaka', 'Nutritional epidemiologist', 'Senior Lecturer', 'University for Development Studies. \r\nDepartment of Nutritional Sciences. \r\nSchool of Allied Health Sciences.\r\nTamale Campus. P. O. Box TL1880', '0207061136', 'msaaka@gmail.com', 'Mr. Prince Imoro Issah', 'Registrar', 'Grants Officer', 'Tamale Technical University. P. O. Box 3E.R Tamale- Ghana', '0246238232', 'prince@tatu.edu.gh', 'Mr. James Attah Aglah', 'Senior Health Information Officer', 'Technical Advisor', 'GIZ Capital Place,. Block A Patrice Lumumba Street, Accra Ghana.', '0248747130', 'Email: jamesaglah@gmail.com', 'BTU_453885F4_cv_6a19f6b684b305.87435422.pdf', '1CV_AYAMGA K. ANTHONY (1) (1).pdf', 'pending', NULL, '154.161.232.93', '2026-05-29 20:27:34', '2026-06-07 23:59:41', 'BTU_453885F4_photo_6a19f6b684b358.79651801.jpeg', 'A. K. AYAMGA.jpeg'),
(188, 'BTU-2C46B2B3', 8, 'Mr.', 'Aboagye', 'James', 'jamesaboagye84@gmail.com', '+233555430505', 'C/o P. O. Box OH 4141\r\nKasoa.\r\nCentral region', 'Accra', 'Japekrom', 'Bono', 'Ghanaian', 'Christian', 'married', 'Elizabeth Abedu', 'C/o P. O. Box OH 4141', 'Melroy Nana Benefo; 14th April 2019\r\nHarriet Awo Yeboah; 26th October 2022', 'P0020799470', 'GHA-718151704-4', '1984-10-10', 'male', 'Master\'s Degree (MPhil.)', 'University of Education, Winneba', 7, NULL, 'I am business accounting graduate with the zeal to teach and assist developments in the field of finance, accounting, management, and business economics. With facilitating abilities in specific subjects; tax accounting, research methods and techniques, corporate reporting, management accounting, auditing and assurance, accounting theory and practice. \r\nI have some years of experience as a High School Teacher, during which I assisted and prepared students in accounting practice for their final examinations. I also have expertise in teaching methods, classroom management, slide preparation and presentation, modern teaching and learning technology, bookkeeping practices, budgeting, auditing, financial statements analysis, tax filing, and payroll accounting. \r\nI am proficient in Quick book accounting software, Microsoft Word, Excel, Statistics Package for Social Sciences (SPSS), Smart-PLS, and data handling. These have prepared me enough to occupy the accounting and finance lecturer position in University of Energy and Natural Resources. Through my Master of Philosophy studies, I have gained advanced skills and knowledge in teaching methods and have become more focused and persistent towards final goals set. As a team leader of my master’s class, I was able to drive all my colleagues towards a common goal of meeting our deadlines for term papers and assignments. \r\nI am self-disciplined, observe high-level integrity and have confidence in my duties as a facilitator. I have always developed a passion and desire for teaching, especially mentoring accounting students to comprehend the recent developments in International Financial Reporting Standards (IFRS), and other financial accounting reporting standards.', 'no', 'no', NULL, 'no', NULL, 'Problem solving, Football', 'Immediately', 'As a graduate who have worked at both corporate and academics level with Masters degree by research in Accounting, I am highly ready to pursue life long learning which would always keep me current in the accounting profession as a researcher if I am given the opportunity as a lecturer in your reputable institution. By so doing, I would also keep impacting students with current accounting knowledge and skills which are required by the job market.', 'Mavis Pobbi (PhD)', 'Lecturer', 'Head of Department', 'C/O P.O. Box 25\r\nWinneba Ghana', '(233) 0244563795', 'mpobbi@uew.edu.gh', 'Charles Omane-Adjekum', 'Lecturer', 'Graduate school coordinator', 'C/O P.O. Box 25\r\nWinneba Ghana', '(233) 0248721836', 'coadjekum@uew.edu.gh', 'James Otabil', 'Lecturer', 'Exams officer (Pharmacy Department)', 'C/O P.O. Box WU 177\r\nGomoa Fetteh\r\nCentral region', '(233) 0545752382', 'jamesotabil@kaafuni.edu.gh', 'BTU_2C46B2B3_cv_6a19fd94af95e3.00056623.pdf', 'JAMES_ABOAGYE_Resume (1) UENR.pdf', 'pending', NULL, '154.161.183.44', '2026-05-29 20:56:52', '2026-06-07 23:59:41', 'BTU_2C46B2B3_photo_6a19fd94af9628.05269674.jpg', 'DOC-20260507-WA0014._202605071503_1.jpg'),
(189, 'BTU-312C1C0B', 4, 'Mrs.', 'AYAABA', 'AZUMAH', 'azumahayaaba@gmail.com', '552844367', 'POST OFFICE BOX, 338\r\nBOLGATANGA', 'PUSIGA', 'PUSIGA', 'Upper East', 'GHANAIAN', 'CHRISTIANITY', 'married', 'DAMANGIB GODWIN', 'GODWINS HSE, SOKABIISI BOLGATANGA', 'GADDIEL YADAPAAK KONLAN, 12 JANUARY 2022\r\nGAVIN YENPAAB KONLAN, 21 JANUARY 2024', 'GHA– 71540337– 77', 'GHA– 71540337– 77', '1994-07-06', 'female', 'Master\'s Degree (MPhil.)', 'USTED', 3, 'NONE', 'My experience relates strongly to the position of Lecturer in Fashion because I have over five years of experience teaching Fashion Design and Garment Construction, delivering both theoretical and practical training in pattern drafting, sewing techniques, garment construction, and textile studies. I hold a BSc in Fashion Design and Textiles Education and I am currently pursuing an MPhil in Fashion Design and Textiles. My experience in teaching, student mentorship, assessment, and academic leadership has equipped me with the skills required to effectively train and support students at the tertiary level.', 'no', 'no', NULL, 'no', NULL, 'READING', 'One month', 'Although I am yet to complete my MPhil in Fashion Design and Textiles, I am currently at the final stage of the programme and preparing for my viva examination in June 2026. My academic background, combined with over five years of teaching experience in fashion design and garment construction and my leadership experience as a Headmistress, has equipped me with the knowledge, skills, and competence required to perform effectively as a Lecturer in Fashion.\r\n\r\nI respectfully request the opportunity to be invited for an interview, where I can further demonstrate my suitability for the position and discuss in greater detail how I can contribute to the growth and success of the department.', 'Abugrago Edward Ndego', 'CIVIL CERVANT', 'COORDINATOR, KCL BAWKU', NULL, 'Tel: 0244933062', NULL, 'James Nzeykye', 'CONSULTANT, PUBLIC SPEAKER', 'CEO', 'POST OFFICE BOX 278', '0243521419', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_312C1C0B_cv_6a1a0738e774f5.32447416.pdf', 'my CV.pdf', 'shortlisted', '', '154.161.41.210', '2026-05-29 21:38:00', '2026-06-12 23:37:18', 'BTU_312C1C0B_photo_6a1a0738e77534.03405220.jpg', 'PASSPORT.jpg'),
(190, 'BTU-6C9597FB', 13, NULL, 'Akosua Ahimah Bondzie Simpson', 'Sarah', 'ahimahbondzie99@gmail.com', '0550662935', 'P.O.Box KN 827 \r\nKaneshie - Accra', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1999-07-04', 'female', 'Bachelor\'s Degree', 'Takoradi Technical University', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Nakotey Solomon Ayertey', NULL, 'Head of Department,  Chief Revenue Officer', NULL, '0244247478', NULL, 'Joseph Danso', NULL, 'Senior Lecturer of Applied Science Department', NULL, '0208172765', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_6C9597FB_cv_6a1a10eaae52d1.61656260.pdf', 'Sarah Bondzi Simpson _CV.pdf', 'pending', NULL, '154.161.112.81', '2026-05-29 22:19:22', '2026-06-07 23:59:41', 'BTU_6C9597FB_photo_6a1a10eaae5324.47644195.jpeg', 'IMG_3431 (1).jpeg'),
