(193, 'BTU-402DDE2D', 4, 'Ms.', 'Mensah', 'Liberty Arthur', 'bettymensah51@gmail.com', '0546302934', 'Nakore, Wa.', 'Accra', 'Abandze', 'Central', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, NULL, 'GHA-718983335-3', '1994-10-26', 'female', 'Master\'s Degree (MPhil.)', 'KNUST', 7, NULL, 'My experience as a fashion tutor and practical examiner has equipped me with the teaching and mentoring skills needed to effectively contribute as a lecturer in fashion.', 'no', 'no', NULL, 'no', NULL, 'Traveling and trying out new recipes', '10days', NULL, 'Prof Osuanyi Quaicoe Essel', 'Lecturer', 'Professor', 'UEW, Winneba.', '0208990892', 'eyensempii@gmail.com', 'Prof Benjamin K. Asinyo', 'Lecturer', 'Associate Professor', 'KNUST, Kumasi.', '0243284886', 'asinyoboss.knust.edu.gh', 'Br Godwin S. Kuu-ireme', 'Tutor', 'Headmaster', 'Nandom, Upper West Region.', '0208773381', 'kuusaag@gmail.com', 'BTU_402DDE2D_cv_6a1a6ab7795b40.32437108.pdf', 'Liberty_Arthur_Mensah_CV manual.pdf', 'shortlisted', '', '154.161.252.102', '2026-05-30 04:42:31', '2026-06-12 23:37:11', 'BTU_402DDE2D_photo_6a1a6ab7795b81.30250600.jpg', 'IMG-20260527-WA0021.jpg'),
