(198, 'BTU-AF80A95B', 11, 'Mr.', 'AKADUMAH', 'SIMON AWUYUURE', 'simonakadumah@gmail.com', '0550583025', 'C/o ISMAEL AYAMGA\r\nPOST OFFICE BOX 295\r\nBOLGATANGA', 'BOLGATANGA', 'BOLGATANGA', 'Upper East', 'GHANAIAN', 'CHRISTIAN', 'married', 'JULIANA ABOYA', 'BOLGATANGA-TINDONMOLIGA', 'TESIA AWUYUURE-28TH JUNE, 2011\r\n\r\nKAVIER AWUYUURE- 1ST JANUARY, 2014\r\n\r\nXAVIER AWUYUURE-7TH NOVEMBER, 2018', NULL, 'GHA-722767958-3', '1985-07-28', 'male', 'Other', 'ANGLICAN JUNIOR HIGH SCHOOL', 0, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'ENTERTAINMENT', '1 WEEK', NULL, 'PROSPER AMIYINE', 'AMBULANCE SERVICE PERSONNEL', NULL, NULL, '0244944649', NULL, 'JULIANA ABOYA', 'TRADER', NULL, NULL, '0536459613', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_AF80A95B_cv_6a1ae850f07c91.66695792.pdf', 'CV AND LICENSE.pdf', 'pending', NULL, '102.176.40.227', '2026-05-30 13:38:24', '2026-05-30 13:38:24', 'BTU_AF80A95B_photo_6a1ae850f07cd5.33888978.jpg', 'WhatsApp_Image_2026-05-30_at_2.08.57_PM__1_-removebg-preview.jpg'),
(199, 'BTU-90E07014', 2, 'Mr.', 'Ayimbire', 'John Deporres', 'lydiadeporres@gmail.com', '0245280694', 'GE-259-4856\r\nFlamingo Valley, Ecomog Street\r\nHaatso, Accra', 'Accra', 'Zuarungu', 'Upper East', 'Ghanaian', 'Christian', 'married', 'Lydia Ayesina Amolga', 'GE- 259- 4856', 'Ezekiel Ayinimi Ayimbire 03-08-2020\r\nJudah  Ayinimi Ayimbire  20-09-2009', NULL, 'GHA712455559-3', '1977-10-31', 'male', 'Master\'s Degree (Other)', 'University of California Berkeley', 11, NULL, NULL, 'no', NULL, NULL, 'no', NULL, 'Reading , Research and Story telling', '1 month', 'I have other working experience as part of internship both local and international captured in my CV.', 'Prof. Michael J. Watts', 'Academic &amp; Educator', 'Development Consultant &amp; Professor Emeritus', 'N/A', '+1-617-253-3073', 'mwatts@berkeley.edu', 'Dr. Clara Beeri Kasser-Tee', 'Legal Practitioner and Lecturer', 'Managing Partner Kasser-Tee Law Firm', 'University of Ghana \r\nLaw Faculty, Legon\r\nAccra.', '+233 24 435 0266', 'ckkasser-tee@ug.edu.gh', 'Prof. Ernest kofi Abotsi', 'Legal Practitioner and Educator', 'Dean Faculty of law UPSA', 'The office of Dean of Law Faculty\r\nUniversity of professional Studies Accra', '+233 303 937 544 or ', 'ernest.abotsi@upsa.edu.gh', 'BTU_90E07014_cv_6a1aeb7b9dfb76.96216623.pdf', 'final saviour pdf.pdf', 'pending', NULL, '154.161.52.147', '2026-05-30 13:51:55', '2026-06-07 23:59:41', 'BTU_90E07014_photo_6a1aeb7b9dfbc1.63156352.jpg', '20260529_164104.jpg'),
(200, 'BTU-7F5DF420', 11, 'Mr.', 'AKADUMAH', 'SIMON AWUYUURE', 'simonakadumah@gmail.com', '0550583025', 'C/o ISMAEL AYAMGA\r\nPOST OFFICE BOX 295\r\nBOLGATANGA', 'BOLGATANGA', 'BOLGATANGA', 'Upper East', 'GHANAIAN', 'CHRISTIAN', 'married', 'JULIANA ABOYA', 'BOLGATANGA-TINDONMOLIGA', 'TESIA AWUYUURE-28TH JUNE, 2011\r\nKAVIER AWUYUURE- 1ST JANUARY, 2014\r\nXAVIER AWUYUURE-7TH NOVEMBER, 2018', NULL, 'GHA-722767958-3', '1985-07-28', 'male', 'Other', 'ANGLICAN JUNIOR HIGH SCHOOL', 0, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'ENTERTAINMENT', '1 WEEK', NULL, 'PROSPER AMIYINE', 'AMBULANCE SERVICE PERSONNEL', NULL, NULL, '0244944649', NULL, 'JULIANA ABOYA', 'TRADER', NULL, NULL, '0536459613', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_7F5DF420_cv_6a1aebd68a5961.75701707.pdf', 'CV AND LICENSE.pdf', 'pending', NULL, '102.176.40.227', '2026-05-30 13:53:26', '2026-05-30 13:53:26', 'BTU_7F5DF420_photo_6a1aebd68a59a2.41295159.jpg', 'WhatsApp_Image_2026-05-30_at_2.08.57_PM__1_-removebg-preview.jpg'),
(201, 'BTU-DE782806', 15, 'Mr.', 'Dery', 'Andrews', 'derbie.simple@gmail.com', '+233 247 615 424', 'C/o Queen of Peace Catholic Church,\r\nP.O. Box MD 89,\r\nMadina, Accra.', 'Tuopare', 'Nandom', 'Upper West', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, NULL, 'GHA-715401924-5', '1988-07-16', 'male', 'Master\'s Degree (MPhil.)', 'University of Bergen, Norway', 5, 'Two books to my credit:\r\n1. Signposts to Effective Studies and Academic Excellence for Students, 2021\r\n2. Signposts to Effective Career and Financial Planning, 2022', 'I have worked in both academia and industry. I will apply the experiences culminated to ensure the successful execution of my mandate.', 'no', 'no', NULL, 'no', NULL, '-Reading and upgrading knowledge on productivity, leadership, corporate governance\r\n-Writing of scholarly discourses/articles\r\n-Giving motivational talks etc', '2 weeks', 'I am highly organized, innovative, and digitally savvy. I am teachable, open to new ideas, and have a teamwork spirit.', 'Joseph Yaw Yeboah', 'Lecturer', 'Senior Lecturer', 'Department of Geography and Rural Development,\r\nKwame Nkrumah University of Science and Technology, Kumasi.', '+233 24 499 1367', 'jyyeboah.cass@knust.edu.gh', 'Dr. Michael Asigbaase', 'Lecturer', 'Senior Lecturer', 'Department of Forest Science,\r\nUniversity of Energy and Natural Resources,\r\nSunyani.', '+233(0) 508 168 737', 'Michael.Asigbaase@uenr.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_DE782806_cv_6a1af43f305305.97869981.pdf', 'ACADEMIC CURRICULUM VITAE-MR ANDREWS DERY.pdf', 'pending', NULL, '154.160.22.71', '2026-05-30 14:29:19', '2026-06-07 23:59:41', 'BTU_DE782806_photo_6a1af43f305343.06271610.jpg', 'Capture_02357 (1).JPG'),
(202, 'BTU-89E084EA', 6, 'Mr.', 'Ayimbire', 'John Deporres', 'lydiadeporres@gmail.com', '0245280694', 'GE- 259-4856\r\nFlamingo Valley Ecomog Street\r\nHaatso,  Accra', 'Zuarungu', 'Zuarungu', 'Upper East', 'Ghanaian', 'Christian', NULL, NULL, NULL, 'Ezekiel Ayinimi Ayimbire 05-08-2020\r\nJudah Ayinimi Ayimbire 20-09-2009', NULL, 'GHA712455559-3', '1977-10-31', 'male', 'Master\'s Degree (Other)', 'University of California Berkeley', 11, NULL, 'My experience as a private tutor for university graduates preparing for entrance to  professional law studies is a good fit as I have the experience of handling both fresh Senior high School students and graduate students.\r\nMy legal  knowledge and conflict resolution skills can not be over emphasised as it will come in handy to an environment such as  yours.\r\nMy  multi-displinary knowledge and training puts me in a better position to handle many disciplines such as different areas of law, communication amongst others.', 'no', 'no', NULL, 'no', NULL, 'Reading,research and story telling', '1 month', 'I actually completed class work for a PhD without the final research.Thusvi advanced to candidacy but was unable to complete the program due to family emergency at the time.\r\nI have other work experience both local and international not captured in this application but contained in my CV.', 'Prof. Michael J. Watts', 'Development Consultant &amp; Educator', 'Development Consultant &amp; Professor Emeritus', NULL, '+1-617-253-3073', 'mwatts@berkeley.edu', 'Dr. Clara Beeri Kasser-Tee', 'Legal Practitioner and Lecturer', 'Managing Partner Kasser-Tee Law Firm', 'University of Ghana Law Faculty\r\nLego, Accra', '+233 24 435 0266', 'ckkasser-tee@ug.edu.gh', 'Prof. Ernest kofi Abotsi', 'Legal Practitioner and Educator', 'Dean Faculty of law UPSA', 'The office of the Dean\r\nUniversity of Professional Studies Accra', '+233 303 937 544 or ', 'ernest.abotsi@upsa.edu.gh', 'BTU_89E084EA_cv_6a1aff673f0eb6.63038968.pdf', 'final saviour pdf.pdf', 'shortlisted', '', '154.161.52.147', '2026-05-30 15:16:55', '2026-06-12 23:44:57', 'BTU_89E084EA_photo_6a1aff673f0f04.14502382.jpg', '20260529_164104.jpg'),
(203, 'BTU-04587F72', 6, 'Mr.', 'OGGAH', 'ERIC NKRUMAH', 'ericoggah2@gmail.com', '+233541087469', 'JAMAN SOUTH MUNICIPAL ASSEMBLY, POST OFFICE BOX 5, DROBO -BONO REGION', 'BIMBILLA', 'SABOBA', 'Northern', 'GHANAIAN', 'CHRISTIAN', NULL, NULL, NULL, NULL, NULL, 'GHA-714425184-0', '1992-03-06', 'male', 'Master\'s Degree (MPhil.)', 'University of Skills Training and Entrepreneurial Development-Kumasi', 7, NULL, 'My previous experience as a teacher has enabled me to translate complex construction concepts into digestible lessons, assess student progress effectively, and maintain a safe, productive learning environment. My prior role as a Teaching Assistant at Accra Technical University gave me direct insight into the delivery of university-level curricula.\r\nMy current role as a Quantity Surveyor will ensure my teaching is grounded in current industry practice. I can guide students through the entire project lifecycle from tender document preparation and bill of quantities production to interim valuations and final payment certificates. This practical insight directly enhances student employability.', 'no', 'no', NULL, 'no', NULL, 'listening to music', '1 month', NULL, 'Prof. Peter Paa-Kofi Yalley', 'Lecturer', 'Professor', 'Department of Construction Technology and Management Education\r\nUniversity of Skills Training and Entrepreneurial Development – Kumasi\r\nPost Office Box 1277, Kumasi', '+233248115763 / +233', 'ppkyalley@aamusted.edu.gh', 'Mr. David Amedegbe – Doe', 'Lecturer', 'Senior Lecturer', 'Accra Technical University, \r\nDepartment of Building Technology, Accra, Ghana.\r\nPost Office Box GP 561, Accra', '+233248944204', 'davidadoe@gmail.com, damedegbe-doe@apoly.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_04587F72_cv_6a1b1a333bf301.05015117.pdf', 'CV ERIC NKRUMAH OGGAH .pdf', 'pending', NULL, '154.161.190.153', '2026-05-30 17:11:15', '2026-06-07 23:59:41', 'BTU_04587F72_photo_6a1b1a333bf355.60464864.jpg', 'eric pic.jpg'),
(204, 'BTU-EC6A7536', 1, 'Mr.', 'Adda Balinia', 'Richmond', 'richmondadda@gmail.com', '+233546356019', 'post office box 31, Navro Pio\'s palace, Navrongo', 'Navrongo', 'Navrongo', 'Upper East', 'Ghanaian', 'African Tradition', 'married', 'Gifty Adda', 'post office box 31, navro pio palace', NULL, NULL, NULL, '1994-08-06', 'male', 'Master\'s Degree (MPhil.)', 'University of Technology and Applied Sciences', 3, 'Dassah, S. D., et al. (2025). Malaria and typhoidal co?infection among febrile patients in Northern Ghana. BMC Infectious Diseases. (Relevant: parasitology, co?infection diagnostics)\r\n\r\nAdda, R. B. et al. (2025). Profiling the Immune Response to the Duffy Binding?Like 5 (DBL5) Domain of VAR2CSA in Pregnancy?Associated Malaria. medRxiv. (Immunology, malaria diagnostics)', 'My background combines hands?on laboratory experience (sample processing, quality control, biosafety) with advanced quantitative and genomic analysis of infectious diseases. As a Research Officer at Navrongo Health Research Centre, I have processed and analysed samples for Lassa fever, malaria, typhoid, enteroviruses, and antimicrobial resistance. I have applied molecular and genomic methods (WGS, GPS Pipeline) for serotyping and pathogen surveillance. As a part?time Assistant Lecturer, I have taught biostatistics and epidemiology – essential subjects for Medical Laboratory Technology students to understand diagnostic test validation, disease surveillance, and research methods. I am eager to develop and deliver practical, evidence?based laboratory science curricula, supervise student projects, and contribute to the university’s research output in clinical diagnostics and public health.', 'no', 'no', NULL, 'no', NULL, 'Writing and research, reading scientific literature (especially infectious disease diagnostics and antimicrobial resistance), mentoring students, football, and community health volunteering.', 'Immediately', 'In addition to my role as Research Officer &amp; Biostatistician, I currently serve as a Part?time Assistant Lecturer at the School of Public Health, University of Technology and Applied Sciences, Navrongo (Navrongo, Upper East Region, Ghana). My teaching responsibilities include:\r\n\r\n1. Delivering lectures in Biostatistics and Introductory Epidemiology to undergraduate public health students.\r\n\r\n2. Developing assessments, examinations, and mentoring students on research projects and health data analysis.\r\n\r\n3. Covering topics directly relevant to Medical Laboratory Technology, such as diagnostic test evaluation, disease surveillance, and interpretation of laboratory data.\r\n\r\nThis teaching experience, combined with my hands?on laboratory background in infectious disease research, positions me to effectively contribute to the Medical Laboratory Technology department.', 'Prof. Abugri James', 'Associate Professor', 'Dean, School of Biochemical Sciences', 'University of Technology and Applied Sciences, Navrongo, Upper East Region, Ghana', '+233 24 499 4359', 'ajames@cktutas.edu.gh', 'Dr. Felix Ajuah Achana', 'Senior Lecturer', 'Senior Lecturer, School of Public Health', 'University of Technology and Applied Sciences, Navrongo, Upper East Region, Ghana', '+233 597243241', 'agafeuk@gmail.com', 'Dr. Sylvester Dassah', 'Senior Lecturer', 'Senior Lecturer, School of Biochemical Sciences', 'University of Technology and Applied Sciences, Navrongo, Upper East Region, Ghana', '+233 24 300 5950', 'sddassah@cktutas.edu.gh', 'BTU_EC6A7536_cv_6a1b288d7e5de5.06471012.pdf', 'Richmond_Balinia_Adda_CV_BTU.pdf', 'pending', NULL, '154.161.246.148', '2026-05-30 18:12:29', '2026-06-07 23:59:41', 'BTU_EC6A7536_photo_6a1b288d7e5e39.97085473.jpg', 'passport_size pic_page-0001.jpg'),
(205, 'BTU-F137D165', 13, 'Mr.', 'Sarkodie', 'Daniel Nyarko', 'dsarkodienyarko@gmail.com', '+233548974517', 'Post Office Box 1445,\r\nSunyani.', 'Sunyani', 'Sunyani', 'Bono', 'Ghanaian', 'Christianity', 'single', NULL, NULL, NULL, NULL, 'GHA-726033802-9', '1997-01-21', 'male', 'Bachelor\'s Degree', 'University of Cape Coast', 3, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'I love listening to music and playing the saxophone.', '2 weeks', NULL, 'Albert Mends', 'Software Engineer', 'Senior Software Engineer', NULL, '0249107812', 'albertments@gmail.com', 'Isaac Osafo', 'Software Engineer', 'Senior Software Engineer', NULL, '0557824143', 'isaac.osafo@azubiafrica.org', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_F137D165_cv_6a1b32d40eb334.73142812.pdf', 'Daniel_Nyarko_Sarkodie_Certificate.pdf', 'pending', NULL, '154.161.101.58', '2026-05-30 18:56:20', '2026-06-07 23:59:41', 'BTU_F137D165_photo_6a1b32d40eb389.33682885.jpg', 'Daniel_Sarkodie.jpg'),
(206, 'BTU-5290EEFB', 2, 'Dr.', 'Akugre', 'Thomas Awinba', 'akugrethomas@gmail.com', '+233246173494', 'Zebilla Senior High/Technical School,  Post Office Box 9', 'Bulinga', 'Bulinga', 'Upper East', 'Ghanaian', 'Christian', 'married', 'Clementina Lariba Awuah', 'Narigu Primary School, Post Office Box 8, Zebilla.', 'Julius Azumah Akugri - 19/11/2004\r\nAmy Awinsum Akugre - 28/08/2009\r\nJeremy Azakwin Mbazor Akugre - 23)10/2013\r\nJethro Awinmi-i Akugre - 01/08/2017\r\nAngel Awintumiah Akugre - 14/04/2021\r\nAnna Awinzusum Akugre - 26/10/2023\r\nJovan Wingatkobug Akugre - 15/10/2025', 'GHA- 716096744-0', 'GHA- 716096744-0', '1982-10-23', 'male', 'PhD', 'University of Technology and Applied Sciences', 11, 'Akugre T. A. and Nantomah K. (2019). On some properties of the real matrix-variate Gamma function, International Journal of Mathematics And its Applications, 7(2) (2019) 97-103.\r\n\r\nT.A. Akugre, K. Nantomah, and M. M. Iddrisu, (2023). On Certain Properties of a Degenerate Sigmoid Function, European Journal of Mathematical Analysis, 3(17) (2023), 1-10.\r\n\r\nT.A. Akugre, K. Nantomah, and M. M. Iddrisu, (2024). On Some Properties of the Degenerate Hyperbolic Functions, Journal of Mathematical Analysis and Modeling, 4(3), 26-40.\r\n\r\nT.A. Akugre, K. Nantomah, and M. M. Iddrisu, (2024). On Some Properties of the Degenerate Exponential Function, Communications in Mathematics and Applications, .', 'Teaching in both basic and second cycle institutions for twenty two years puts me in a better position to teach in the  level', 'no', 'no', NULL, 'no', NULL, 'Reading and reaching', 'Two weeks', NULL, 'Prof. Kwara Nantomah', 'Lecturing', 'Director of Academic Planning and Quality Assurance', 'University of Technology and Applied Sciences, \r\nPost Office Box 24, \r\nNavrongo, Upper East Region, Ghana.', '0208298678/024365768', 'knantomah@cktutas.edu.gh', 'Prof. Mohammed Muniru Iddrisu', 'Lecturing', 'Principal, Faculty of Physical Sciences', 'University for Development Studies, \r\nPost Office Box TL1350, \r\nTamale, Northern Region, Ghana', '0243642642/020996285', 'mmuniru@uds.edu.gh', 'Dr. Shaibu Osman', 'Lecturing', 'Lecturer', 'School of Basic and Biomedical Sciences, \r\nDepartment of Basic Sciences, PMB31.  \r\nHo, Volta Region. \r\nGhana.', '0246343568/050110232', 'sosman@uhas.edu.gh', 'BTU_5290EEFB_cv_6a1b6eab50e681.09557699.pdf', 'Dr_Thomas_Awinba_Akugre_CV BTU.pdf', 'shortlisted', '', '102.176.75.127', '2026-05-30 23:11:39', '2026-06-12 23:22:27', 'BTU_5290EEFB_photo_6a1b6eab50e6d1.13378463.jpg', '294515.jpg'),
(207, 'BTU-CC7482FE', 13, 'Mr.', 'DENNIS', 'TERENCE NANA', 'terencenanadennis140@gmail.com', '+233240170710', 'P.O.BOX DT 2777, ADENTA WEST\r\nACCRA', 'Suhum', 'Greater Accra', 'Eastern', 'Ghanaian', 'Christian', 'married', 'Joycelyn Aboagye', '10 HALLELUYAH BROADWAY', 'Terencia Yirenkyiwaa Dennis', 'P0019370873', 'GHA-712030235-5', '1990-10-17', 'male', 'Master\'s Degree (Other)', 'University of Ghana', 7, NULL, 'Knowledge Transfer: Teaching experience demonstrates your ability to explain complex ICT concepts clearly, train staff, and build digital literacy across the organization.\r\n\r\nCapacity Building: Shows you can mentor junior staff or interns, ensuring continuity and skill development within the ICT unit.\r\n\r\nCommunication Skills: Teaching sharpens your ability to simplify technical issues for non-technical stakeholders, a critical skill for ICT support roles.\r\n\r\nProblem-Solving: Research experience highlights your analytical skills in diagnosing ICT challenges and proposing innovative solutions.\r\n\r\nEvidence-Based Practice: Ability to apply data-driven insights when recommending ICT tools, policies, or upgrades.\r\n\r\nInnovation: Research fosters creativity and adaptability, ensuring you can keep pace with evolving ICT trends and technologies.\r\n\r\nTechnical Expertise: Professional ICT work shows hands-on experience in system administration, troubleshooting, and infrastructure management.\r\n\r\nOperational Continuity: Demonstrates your ability to maintain uptime, manage assets, and ensure smooth ICT operations.\r\n\r\nCollaboration: Professional practice proves your capacity to work across departments, aligning ICT services with organizational goals.', 'no', 'no', NULL, 'no', NULL, 'FOOTBALL AND CODING', 'IMMEDIATELY', 'Commitment to ICT Growth  \r\nExpress dedication to continuous learning, professional certifications, and staying updated with emerging technologies.\r\n\r\nTeamwork &amp; Leadership  \r\nMention your ability to collaborate across departments, mentor junior staff, and contribute to a positive ICT culture.\r\n\r\nProblem-Solving Mindset  \r\nHighlight resilience in troubleshooting complex ICT issues, even under pressure, ensuring minimal downtime.\r\n\r\nOperational Continuity  \r\nEmphasize your experience in maintaining ICT systems during disruptions (e.g., internet outages, device failures).\r\n\r\nDocumentation &amp; Handover  \r\nStress your ability to produce clear, structured documentation that ensures smooth transitions and continuity.\r\n\r\nEthics &amp; Confidentiality  \r\nReinforce your commitment to safeguarding sensitive data and adhering to ICT security protocols.', 'H.E. MOHAMED NASHEED', 'Fmr S-G for CVF/V20 and Fmr President of Maldives', 'SECRETARY-GENERAL', 'MALDIVES', '+447432849865', 'MNASHEED@GMAIL.COM', 'DR ERIC TWUM', 'IOEA AND IGGS GHANA', 'CEO', 'OYARIFA, ACCRA', '0263597635', 'Eric.k.twum@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_CC7482FE_cv_6a1b8876e4d3a8.63462492.pdf', 'TERENCE NANA _DENNIS_CVV.pdf', 'pending', NULL, '102.176.95.39', '2026-05-31 01:01:42', '2026-06-07 23:59:41', 'BTU_CC7482FE_photo_6a1b8876e4d3f9.14636458.jpg', 'passpic.jpg'),
(208, 'BTU-C9E9259D', 2, 'Mr.', 'Anadem', 'Jeffrey Ayambodi', 'jeffanadem9@gmail.com', '+233245587377', 'Opku Ware School,\r\nP.O.Box 849,\r\nKumasi-Santasi,\r\n0245587377.', 'Sandema', 'Sandema', 'Upper East', 'Ghanaian', 'Christianity', 'single', NULL, NULL, NULL, NULL, 'GHA-716673157-9', '1992-12-29', 'male', 'Master\'s Degree (MPhil.)', 'Kwame Nkrumah University of Science and Technology', 7, NULL, 'My teaching career includes one year service as a teaching and research assistant at Kwame Nkrumah University of Science and Technology. In this role, I successfully delivered full time lectures in post-secondary mathematics to medical and allied health science students, operations research to statistics and actuarial science students, optimization, algebra and ordinary differential equations to mathematics students under the supervision of Professor Charles Sebil and Professor Joseph Ackora-Prah. I also organized tutorials, prepared teaching materials and graded assessments on behalf of Professor Charles Sebil. This tertiary level teaching experience is augmented by over six years of experience as a mathematics teacher at Obuasi Senior High Technical School and Opoku Ware Senior High School. This has helped me to master pedagogy and build teaching philosophy that is centered on students’ development and practical applications of mathematical concepts to real-world problems.', 'no', 'no', NULL, 'no', NULL, 'Watching and playing football, indoor games like Draft, Reading and Research.', '1 month', 'I hold Diploma in oil and gas management, Nebosh Certificate in Occuoational Health and Safety Management, Diploma in Team and Project Management etc.', 'Charles Sebil', 'Lecturer', 'Professor of Applied Mathematics', 'Department of mathematics, \r\nOffice No.SF14\r\nKNUST- Kumasi', '0244745439', 'csebil.cos@knust.edu.gh', 'Joseph Abeiku Ackora-Prah', 'Lecturer', 'Professor of Applied Mathematics', 'Department of mathematics, \r\nOffice No.SF15\r\nKNUST- Kumasi', '0208180547', 'jaackora-prah.cos@knust.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_C9E9259D_cv_6a1bc1901704b4.55658619.pdf', 'Anadem_Curriculum_Vitae.pdf', 'shortlisted', '', '102.176.101.51', '2026-05-31 05:05:20', '2026-06-12 23:22:43', 'BTU_C9E9259D_photo_6a1bc190170517.17824554.jpg', 'GES1304798 (1).jpg'),
(209, 'BTU-EDAF5B5E', 15, 'Mr.', 'Kassim', 'Nurideen Andani', 'andanikassim6@gmail.com', '0542238994', 'Box 47, Gushegu Northern Region.', 'Gushegu', 'Gushegu', 'Northern', 'Ghanaian', 'Islam', 'married', 'Tanko Rahi', NULL, 'Fareeda Nurideen Andani (11/11/2020)\r\nKausar Maltiti Andani (06/06/2024)', NULL, 'GHA-714439619-2', '1992-06-06', 'male', 'Bachelor\'s Degree', 'Tamale Technical University', 2, NULL, 'I am coming with management and administration experience that cut accross all sectors. I also have more than 2 years teaching experience and this gives me in insight into the both teaching and non-teaching section of any academic institution.', 'no', 'no', NULL, 'no', NULL, NULL, '1 month.', NULL, 'Alhassan Shaani', 'Teacher', 'Principal, Nyong Technical Institute.', 'Box 20, Karaga.', '0243072023', NULL, 'Amadu Asana', 'Lecturer', 'Lecturer', 'Tamale Technical University.', '0203306331', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_EDAF5B5E_cv_6a1bd5f0cda076.98725153.pdf', 'Any Scanner_01_30_2026 (1).pdf', 'pending', NULL, '154.161.255.176', '2026-05-31 06:32:16', '2026-06-07 23:59:41', 'BTU_EDAF5B5E_photo_6a1bd5f0cda0b8.28167859.jpg', '1000302043.jpg'),
(210, 'BTU-5EBB30C1', 10, 'Mr.', 'GBEMU', 'JERRY', 'abovetherim2003@yahoo.com', '+233503541155', 'P.O. BOX NT 770\r\nACCRA NEW-TOWN', 'AKATSI', 'SOGAKOPE', 'Volta', 'GHANAIAN', 'CHRISTIAN', 'single', NULL, NULL, NULL, NULL, 'GHA-713894300-5', '1986-01-15', 'male', 'Master\'s Degree (MPhil.)', 'KWAME NKRUMAH UNIVERSITY OF SCIENCE AND TECHNOLOGY, KUMASI', 2, NULL, 'My academic qualifications and professional experience are highly relevant to the Lecturer position at Bolgatanga Technical University. I hold a Bachelor of Education (B.Ed.) in Computer Science, a Master of Education (M.Ed.) in Mathematics, and an MPhil in Computer Science, which have provided me with strong interdisciplinary expertise in computing, mathematics, research, and pedagogy.\r\n\r\nProfessionally, I have extensive teaching experience in Information and Communication Technology (ICT) at the Senior High School level under the Ghana Education Service (GES/CTVET), where I currently serve as both an ICT teacher and Head of Department. In this role, I am responsible for curriculum implementation, academic leadership, student assessment, departmental administration, and the supervision of teaching and learning activities. These responsibilities have strengthened my instructional, leadership, and mentoring capabilities.\r\n\r\nIn addition, I have served as a Part-Time Lecturer in the Department of Computer Science at Modal University College, Sogakope, where I taught undergraduate courses including Introduction to Computers and Introduction to Databases. This experience has provided me with direct exposure to higher education teaching, course delivery, student supervision, assessment, and academic engagement at the tertiary level.\r\n\r\nMy research training in Computer Science, particularly at the MPhil level, has equipped me with advanced skills in scientific inquiry, data analysis, research methodology, academic writing, and the application of emerging technologies to solve real-world problems. My research interests include artificial intelligence, machine learning, computer vision, pattern recognition, and educational technology, which align with contemporary developments in computing education and research.\r\n\r\nThe combination of my academic qualifications, teaching experience, departmental leadership, university-level lecturing experience, and research background has prepared me to contribute effectively to teaching, research, student mentorship, curriculum development, and community service at Bolgatanga Technical University.', 'no', 'no', NULL, 'no', NULL, 'Reading', 'I would be available to assume duty within one month of notification of appointment, subject to the ', 'I am a dedicated educator and researcher with a strong passion for teaching, academic excellence, and student development. My academic background in Computer Science and Mathematics, combined with my experience as an ICT teacher, Head of Department, and Part-Time Lecturer, has equipped me with the knowledge, leadership skills, and professional competence required to contribute meaningfully to higher education.\r\n\r\nI am committed to continuous professional development, research, innovation, and community engagement. I possess strong interpersonal, communication, and organizational skills and have demonstrated the ability to work effectively both independently and as part of a multidisciplinary team. I am particularly interested in advancing research and teaching in areas such as Artificial Intelligence, Machine Learning, Data Science, Computer Vision, and Emerging Computing Technologies.\r\n\r\nIf given the opportunity, I will contribute actively to teaching, research, curriculum development, student mentorship, and the overall growth and reputation of Bolgatanga Technical University.', 'MARFO YAW MISSAH', 'LECTURER', 'PROFESSOR', 'Department of Computer Science \r\nKwame Nkrumah University of Science And Technology\r\nKumasi Ghana', '+233 546 339 9778', 'Email: ymissah@gmail.com', 'GADDAFI ABDUL-SALAAM', 'LECTURER', 'PROFESSOR', 'Department of Computer Science \r\nKwame Nkrumah University of Science And Technology\r\nKumasi Ghana', '+233 549 893 910', 'gaddafi.ict@knust.edu.gh', 'MR. MAC-PETER DUMATONU QUARQUO', 'TEACHER/EDUCATIONIST', 'DISTRICT DIRECTOR OF EDUCATION', 'GHANA EDUCATION SERVICE\r\n\r\nADAKLU, VOLTA REGION, GHANA', '+233 246 614 325', 'macpeter26@yahoo.com', 'BTU_5EBB30C1_cv_6a1bf4de38a9b2.58407507.pdf', 'GBEMUJERRYCV2025.pdf', 'pending', NULL, '41.66.202.138', '2026-05-31 08:44:14', '2026-06-07 23:59:41', 'BTU_5EBB30C1_photo_6a1bf4de38aa17.59649435.jpg', 'GBEMUJERRY.jpg'),
(211, 'BTU-17EBBF98', 15, 'Mr.', 'Akortia', 'Ebenezer', 'ebenezerakortia99@gmail.com', '0542849358', NULL, 'Greater Accra', NULL, 'Greater Accra', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, NULL, NULL, '1996-07-09', 'male', 'Master\'s Degree (Other)', 'Kwame Nkrumah University of Science &amp; Technology', 3, NULL, NULL, 'no', 'yes', 'I was born with four finger on both hands.ie i dont have a middle fingers but i am able to use my hands to do everything effectively.', 'no', NULL, 'Reading, Watching documentaries, Travelling,', 'Immediately', NULL, 'Ms Belinda Dabanka', 'Human Resource Manager', 'HR Associate', NULL, '+233 55 931 1611', NULL, 'Micheal Akrong', 'IT Consultant', NULL, NULL, '+233 244 233 612', 'makrong@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_17EBBF98_cv_6a1c016b78d5f2.57332190.pdf', 'ACMA CGMA CERTIFICATE.pdf', 'pending', NULL, '154.161.179.147', '2026-05-31 09:37:47', '2026-06-07 23:59:41', 'BTU_17EBBF98_photo_6a1c016b78d646.71458302.jpg', '1676981902130.jpg'),
(212, 'BTU-C3E4E0AF', 11, 'Mr.', 'Amagyei', 'Jackson Nana Kwadwo', 'jamegyei@gmail.com', '+233244511247', 'Box 6 Kwabeng-Bomaa', 'Accra', 'Bomaa', 'Eastern', 'Ghanaian', NULL, 'married', 'Franklina Vouri', NULL, 'Jeremiah Ofori Amagyei, 15th November, 2025.', NULL, 'GHA-719302973-5', '1987-05-18', 'male', 'Bachelor\'s Degree', 'University of Ghana, Legon', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Soccer and research', '1 month', NULL, 'Engineer Solomon Adi', 'Teaching', 'Lecturer', 'Cape Coast Technical University.\r\nBox AD 50\r\nCape Coast, C/R', '+233 24 366 4375', 'solomon.adi@cctu.edu.gh', 'Kwasi Oware', 'Transportation', 'Transport Officer, Electoral Commission Ghana', NULL, '+233 54 933 6507', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_C3E4E0AF_cv_6a1c304c4d70d9.57474349.pdf', 'Updated resume Jackson 3docx-1.pdf', 'pending', NULL, '154.161.166.2', '2026-05-31 12:57:48', '2026-06-07 23:59:41', 'BTU_C3E4E0AF_photo_6a1c304c4d7138.51726900.jpg', 'Passport photo N.jpg'),
(213, 'BTU-D0D3A46C', 6, 'Mr.', 'Siita', 'Rauf', 'rauffroko@gmail.com', '+233-243925988', 'Sweet Mother Academy \r\nPost Office Box, 62\r\nWa Upper West Region', 'Wa', 'Wa', 'Upper West', 'Ghanaian', 'Islam', 'married', 'Nazeefata Yussif', 'Sweet Mother Academy  Post Office Box 62 Wa Upper West Region', 'Naheed Hinah Froko Rauf                                                       20/06/2018\r\nYussif KanyiriFroko Rauf                                                          14/09/2015\r\nSuaad Junuo Rauf                                                                    20/10/2009\r\nFatimaa Kyihilung Froko Rauf                                                  24/10/2013\r\nWajeeha Sungyoung Froko Rauf                                              11/05/2020', 'P0025538624', 'GHA-715473282-7', '1979-10-09', 'male', 'Master\'s Degree (MPhil.)', 'Akenten Appiah-Menka University of Skills Training and Entrepreneurial Development', 11, 'An Examination of a Unethical Practices in the Construction Sector: The Case of Government Projects in the Wa Metropolis.\r\nVol.15 No.2 (2025): Journal of Construction Project Management and Innovation', 'Hands-on classroom experience across basic and pre-tertiary levels has built strong competencies in lesson planning, curriculum delivery, and student assessment all directly transferable to lecturing.\r\nLeading a Drawing Department developed the ability to simplify complex technical concepts, design schemes of work, and mentor colleagues qualities essential for effective teaching and departmental contribution at the tertiary level.\r\nProfessional practice in Technical and Creative Drawing brings real industry relevance to teaching, bridging theory and practice in line with the demands of quality TVET education.\r\nReflective teaching practice and curriculum engagement over the years have cultivated an inquiry-driven approach, a firm foundation for academic research and scholarly growth as a lecturer.', 'no', 'no', NULL, 'no', NULL, 'Industrial field work, Research and Travelling', 'Approximately, one month', 'Has a published journal article on unethical practices in the construction sector in the Wa Metropolis, featured in the Journal of Construction Project Management and Innovation (Vol.15, No.2, 2025), demonstrating active research engagement and academic writing ability.\r\nHolds both an MTech in Construction Technology Education and an MPhil in Construction Management a strong dual qualification combining pedagogy and technical depth, directly suited for lecturing in a TVET institution.\r\nIndustrial attachment with A&amp;QS Consortium Limited provides real-world construction industry experience, allowing teaching to be grounded in practical, professional context.\r\nExperience as Assembly Member and Works Subcommittee Chairman reflects civic responsibility, project oversight, and community development awareness qualities that enrich a lecturer\'s broader professional profile.\r\nMultiple workshops in CBT curriculum, procurement management, and skills training demonstrate a commitment to staying current a key trait for any lecturer in a fast-evolving technical field.', 'Dr. Patrick Nyaaba Ayambire', 'Teaching', 'Lecturer, Department of Electrical and Electronic Engineering Education', 'University of Skills Training and Entrepreneurial Development (USTED)\r\nPost Office Box, 1277\r\nAhsanti Region', '+233-552424305', 'pnayambire@aamusted.edu.gh', 'Engr S.A. Razak Batong (MGhIS)', 'Teaching', 'Lecturer', 'Quantity Surveyor and Procurement Specialist\r\nHomeland Resources Limited\r\nP. O. Box CT 2021    \r\nCantonment-Accra', '+233-240269339', 'maara44@gmail.com', 'Prof Moses Naiim Fuseini', 'Teaching', 'Senior Lecturer', 'University of Business and Integrated Studies (UBIDS)\r\nP.O Box  64\r\nWA', '+233- 205782074', 'moses.fuseini@ubids.edu.gh', 'BTU_D0D3A46C_cv_6a1c4278d57837.92580761.pdf', 'M.PHILS CERTIFICATE.pdf', 'pending', NULL, '154.161.49.70', '2026-05-31 14:15:20', '2026-06-07 23:59:41', 'BTU_D0D3A46C_photo_6a1c4278d57889.45893760.jpeg', 'SIITA RAUF.jpeg'),
(214, 'BTU-1A04625A', 14, NULL, 'Agyemang', 'Douglas', 'douglasagyemang257@gmail.com', '+233556383347', NULL, 'Sunyani', 'Accra', 'Greater Accra', 'Ghanaian', NULL, 'single', NULL, NULL, NULL, NULL, NULL, '1994-11-03', 'male', 'Professional Certificate', 'Institute of Chartered Accountants, Ghana (ICAG)', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Fitness', 'Immediately', NULL, 'Dra Amin', NULL, NULL, NULL, NULL, NULL, 'Ebenezer Edilson', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_1A04625A_cv_6a1c72aaf1c629.24691737.pdf', 'DOUGLAS RESUME .pdf', 'pending', NULL, '154.161.20.146', '2026-05-31 17:40:58', '2026-05-31 17:40:58', 'BTU_1A04625A_photo_6a1c72aaf1c664.94035934.jpg', 'passport_photo_under_2MB.jpg'),
(215, 'BTU-677A988B', 15, 'Mr.', 'Hamid', 'Abdul-Wahab Adam', 'mboiwahab@gmail.com', '0541909796', 'T I Ahmadiyya Junior High School, Post Office Box 88, Bolgatanga', 'Yalugu', 'Bazua', 'Upper East', 'Ghanaian', 'Islam -Ahmadi', 'divorced', NULL, NULL, 'Shurda Namning Abdul-Wahab 27/12/2011\r\nSuad Mabun Abdul-Wahab  09/09/2014', 'P0013119680', 'GHA-715452320-1', '1978-06-22', 'male', 'Other', 'UDS', 11, 'Written thesis', 'As a headmaster for over 12 years and with my qualifications in information technology and training &amp; development, I have gained extensive experience in administration, leadership, records management, staff supervision, and stakeholder engagement. My role involves coordinating academic and administrative activities, preparing reports, managing institutional records, and ensuring compliance with organisational policies.\r\nMy academic background in IT has equipped me with strong skills in data management, digital record-keeping, information systems, and the effective use of technology in administration. Additionally, my training and development studies have enhanced my abilities in staff capacity building, programme coordination, research, monitoring and evaluation, and organisational development.\r\nOver the years, I have worked closely with staff, parents, community leaders, and government agencies, strengthening my communication, teamwork, problem-solving, and interpersonal skills. These experiences have prepared me to contribute effectively to the administrative, academic, and operational functions of an assistant registrar position. I have also gained extensive experience as the leader of headteachers at the Bolgatanga municipal level and now the regional chairman of the Conference of Heads of Basic Schools (COHBS) in the Upper East region, where I had the opportunity to engage, interact, and learn from both the municipal and district and regional directors in education and other regional stakeholders. I can comfortably work as an assistant registrar at any reputable tertiary institution like Bolgatanga Technical University.', 'no', 'no', NULL, 'no', NULL, 'Reading Publication books, completing tasks, asking probing questions, researching', 'Immedtetly i gained emplyement or within a week', 'I am also a data person that i can handle the institution\'s data with confidence\r\nI am an human resourse person that i can assist the register in computation, training and development and data handling.\r\nI have the ability to establish link with other organisations that can bring development to the institution.\r\nI have experience in handling and relating with people in higher institution as i have been the regional president of the Ahmadiyya Muslim Youth for over 11 years in the upper eat and north east regions. \r\nI am currently the regional chairman of Conference of Heads of Basic Schools in the Upper East Region where i lead over 1300 Basic Schools Headteachers.', 'Prof. Issah Mohammed', 'Lecturer', 'Vice Dean', 'Office of the Vice Dean\r\nUDS Tamale Campus (Dungu/Main Campus)\r\nDepartment of Business Education, Faculty of Education\r\nPOB TL1350, \r\nTamale', '0502417991', 'mohammedabugh@mail.com', 'Prof. Amadu Musah Abudu', 'Lecturer', 'HOD', 'UDS Tamale Campus (Dungu/Main Campus)\r\nFaculty of Education (FOE)\r\nDepartment of Educational Management and Policy Studies\r\nPOB TL1350, \r\nTamale', '0208293546', 'amabudu2012@gmail.com', 'Maulvi Abass Bin Suleman', 'Missionary', 'Regional Missionary', 'Ahmadiyya Muslim Mission\r\nPost Office Box 88\r\nBolgatanga\r\nUpper East Region', '0543994776', 'ahmadiyyauppereastregion@gmail.com', 'BTU_677A988B_cv_6a1c8b798d2708.97771251.pdf', 'Master Degree.pdf', 'shortlisted', '', '154.161.125.176', '2026-05-31 19:26:49', '2026-06-12 22:48:08', 'BTU_677A988B_photo_6a1c8b798d2742.92062124.jpg', 'PICTURES.jpg');
