(266, 'BTU-7D2AE355', 3, 'Mr.', 'WRISTBERG', 'SAMUEL NII AMPONSAH', 'wristbergnii@gmail.com', '+233548168172', 'Accra', 'police Hospital, Accra', 'Cantoment', 'Greater Accra', 'Ghanaian', 'Christian', 'single', NULL, NULL, NULL, NULL, 'GHA-001052562-3', '1993-11-16', 'male', 'Master\'s Degree (MPhil.)', 'University of Ghana', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'Farming, playing baseball, and travelling', '1month', NULL, 'Emmanuel Sagoe', 'Agriculturist', 'Field Operations manager', 'Yagaba', '0244606078', NULL, 'Mr. Dela Kojo Agblata', 'Auto mechanical engineer', 'Senior technician', 'Bolgatanga', '0208270008', 'dela.agblata@gmail.com', 'Mr. B.A Boateng', 'Leturer', 'senior lecturer', 'Legon, Accra', '+233208171818', NULL, 'BTU_7D2AE355_cv_6a1f2241df8877.73407133.pdf', 'Sam Wristberg Masters certificate .pdf', 'pending', NULL, '154.161.29.31', '2026-06-02 18:34:41', '2026-06-07 23:59:41', 'BTU_7D2AE355_photo_6a1f2241df88b0.03974185.jpeg', 'Sam wristberg passport picture .jpeg'),
(267, 'BTU-DB459A0E', 2, 'Mr.', 'Emmanuel', 'Adombor', 'e.adombor@gmail.com', '+233541917591', 'College of Health, P.O. box 10, Nalerigu', 'Kpando', 'Kpando', 'Volta', 'Ghanaian', 'Christianity', 'married', 'Boateng Evelyn Boatemaa', 'P.O Box 10 Nalerigu', 'Adombor Obenewaa Adrielle-18/06/2020\r\n\r\nAdombor Othniel Adu-Amankwah-31/07/2023', NULL, 'GHA-714844328-5', '1991-08-03', 'male', 'Master\'s Degree (MPhil.)', 'University of Technology and Applied Sciences, Navrongo', 11, 'Adombor, E., Engman, G. M., &amp; Alhassan, A. (2024). Effects of COVID-19 on Living Standards of Households in the North East Region of Ghana: A Linear Mixed Effects Model Approach. Journal of Social and Economic Statistics, 13(1), 13-28.\r\n\r\nYiadom, B.K., Edusei, A.K., Boakye, A.B. and Adombor, E. (2024). Type 2 Diabetes in the Elderly in Obuasi: Management Strategies and Effect on Nutrition and Health. International Journal of Innovative Science and Research Technology (IJISRT). 2619-2629. DOI:10.38124/ijisrt/IJISRT24APR1010.\r\n\r\nAyangba, V., Awuuh, V.A., Adombor, E., Sulemani, H.B., Dzantor, E.K., Alalbilla, J.A., Ayine, N.D., Alhassan, M., &amp; Yeboah, N.O. (2023). Evidences of Widespread Hunger in Gbeo Community, North East Region, Ghana; the Determinants of Malnutrition and Susceptibility to Extreme Hunger. South Asian Research Journal of Medical Sciences.', 'My academic background and professional experience align strongly with the requirements of a Lecturer in Mathematics and Statistics. I hold an MPhil in Statistics, a BSc in Mathematics and Statistics, and an HND in Statistics, which provide me with a solid foundation in theoretical and applied mathematics, statistical modelling, probability, research methodology, and data analysis.\r\nI have extensive teaching experience at the tertiary level, currently serving as a Health Tutor at the College of Nursing and Midwifery, Nalerigu, and as a Part-Time Lecturer at the University of Cape Coast, where I teach Biostatistics, Mathematics, Research Methods, and Data Analysis. These roles have enhanced my ability to communicate complex mathematical and statistical concepts effectively to diverse groups of students.\r\nMy research activities and publications demonstrate competence in quantitative research, statistical modelling, and data-driven problem-solving. I have applied advanced statistical techniques using software such as SPSS, Stata, R, Minitab, and MATLAB in both academic and professional settings. \r\nThese qualifications, combined with my commitment to teaching, research, and academic mentorship, position me well to contribute meaningfully to the teaching, research, and community service objectives of the Department of Mathematics and Statistics.', 'no', 'no', NULL, 'no', NULL, 'Loves to play football and basketball.\r\n\r\nPlaying computer games (FIFA) at my leisure time.', 'Immediately', NULL, 'Professor Abukari Alhassan', 'Associate Professor of Statistics', 'Head of Department', 'University for Development Studies, Nyankpala Campus, P.O. BOX TL 1350 Tamale, Northern Region, Ghana.', '+233 244 520883', 'a.alhassan@uds.edu.gh', 'Dr. Gideon Mensah Engmann', 'Senior Lecturer', 'Senior Lecturer, Department of Biometry', 'University for Technology and Applied Sciences, P.O.BOX 24 Navrongo, Upper East Region, Ghana.', '0207861309', 'gengmann@cktutas.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_DB459A0E_cv_6a1f2396dd45a3.24819812.pdf', 'ADOMBOR RESUME 2026.pdf', 'pending', NULL, '154.161.115.48', '2026-06-02 18:40:22', '2026-06-07 23:59:41', 'BTU_DB459A0E_photo_6a1f2396dd4601.20116304.jpg', 'MY PHOTO.jpg'),
