(288, 'BTU-AC152534', 2, 'Dr.', 'Nusenu', 'Angela Abena', 'aanusenu@yahoo.com', '+233555341345', 'Post Office Box KF 2365, Koforidua', 'Accra', 'Agona Swedru', 'Central', 'Ghanaian', NULL, 'married', 'Dr. Shaddrack Yaw Nusenu', 'Post Office Box KF 2365, Koforidua', 'Benjamin Nusenu-1st April, 2013\r\nMeshach Martey Nusenu- 18th January, 2015', 'P0028835719', 'GHA-721465832-6', '1980-09-23', 'female', 'PhD', 'University  of  Electronic  Science  and  Technology of China', 7, 'Nusenu, Angela Abena, (2021). Value Co-creation Intention among Consumers at the \r\nBottom of the Pyramid: A Study of Rural and Community Banks in Ghana. Journal of \r\nPsychology in Africa. \r\n• Nusenu, Angela Abena. , Xiao, W., Opata, C. and Darko, D. (2019) DEMATEL Technique \r\nto Assess Social Capital Dimensions on Consumer Engagement Effect on Co-Creation. \r\nOpen Journal of Business and Management, 7, 597-615. \r\n• Nusenu, Angela Abena, Xiao, Wen, Opata, Christian Narh (2018), U&amp;G Model As an \r\nAntecedent to Ascertain Consumer Level of Participation in Online Value Co-creation \r\nIEEE 7th International Conference on Adaptive Science &amp; Technology (ICAST) Ghana. \r\n2 \r\n• Opata, Christian Narh, Wen Xiao, Nusenu, Angela Abena, Tetteh, Stephen, Tettey-Yawo- \r\nJohn. (2020). Customer Value Co-Creation in the Automobile Industry: Antecedents, \r\nSatisfaction, and Moderation. Sage Open. \r\n• Say, Joy, Hongjiang Zhao, Agbenyegah Francisca Sena, Nusenu Angela Abena, Asante \r\nBoadi, Samuel Morkpor, (2020). Regional efficiency disparities in rural and community    \r\nbanks in Ghana: A data envelopment analysis. Journal of Psychology in Africa 30(3):249- \r\n256. \r\n• Opata, Christian Narh , Wen Xiao, Nusenu, Angela Abena , Tetteh, Stephen  &amp; Evans \r\nAsante Boadi (2019), The impact of value co-creation on satisfaction and loyalty: the \r\nmoderating effect of price fairness (empirical study of automobile customers in Ghana), \r\nTotal Quality Management and Business Excellence. \r\n• Opata Christian Narh, Wen Xiao Nusenu Angela Abena (2018), The Moderating Effect of \r\nSocial Ties on Customers\' Willingness to Interact in Value Co-Creation. 10th International \r\nConference on Information Management and Engineering. \r\n• Opata,  Christian  Narh,  Xiao  wen,  Nusenu,  Angela  Abena,  Tetteh,  Stephen,  Opata, \r\nEmmanuel Sackitey (2019), Customer willingness to participate in value co-creation: The \r\nmoderating effect of social ties (empirical study of automobile customers in Ghana) \r\n• Kingful, Stephen; Nusenu, Angela Abena (2015), Teachers Motivation in Senior High \r\nSchools in Ghana: A Case of Ghana Senior High School, Journal of Education and Practice. \r\n• Bennet, Ebenezer and Kenneth, Amoah-Binfoh and Obenewaa, Amoako and Charles, \r\nRicky-Okine and Nusenu, Angela Abena, Risk (2012), Management and Its Impact on \r\nProfitability in Microfinance Institutions.', 'I hope with my background in business administration, including my doctoral education which has developed my intellectual confidence and knowledge, i can handle entrepreneurship and it related subjects the department offers.', 'no', 'no', NULL, 'no', NULL, 'singing and surfing the internet', 'Immediately', NULL, 'Dr. Joy Say', 'Teaching', 'Lecturer', 'University of Education, Winneba', '0244227744', 'jsay@uew.edu.gh', 'Regina Payin Asomani', 'Human resources', 'Assistant HR manager', 'Tema Metropolitan Assembly', '0243205656', 'asomaniregina18@gmail.com', 'Dr. Anita Antwiwaa,', 'Teaching', 'Dean', 'All Nations University  Koforidua', '0275250061/ 02474254', 'raantwiwaa@anu.edu.gh', 'BTU_AC152534_cv_6a1ffef5c171b4.63410809.pdf', 'CV.pdf', 'pending', NULL, '154.161.163.118', '2026-06-03 10:16:21', '2026-06-07 23:59:41', 'BTU_AC152534_photo_6a1ffef5c17210.48681700.jpeg', 'passport pic.jpeg'),
(289, 'BTU-47A9E058', 15, 'Mr.', 'YANBORIGYA', 'JOSEPH KPALIK', 'josephyanborigya@gmail.com', '245375850', 'BOX 561, TONGO', 'TONGO', 'TONGO', 'Upper East', 'GHANAIN', 'CHRISTIAN', 'married', 'YARIG MATILDA', 'KUMBOSIGO HEALTH CENTRE', 'YANBORIGYA YINITOMIT - 3RD APRIL, 2019\r\nYANBORIGYA YINPAALA - 26TH OCTOBER, 2022\r\nYANBORIGYA LA-AYIN - 24TH FEBRUARY, 2026', 'P0003849147', 'GHA-716318833-0', '1987-12-16', 'male', 'Master\'s Degree (Other)', 'KNUST', 7, NULL, NULL, 'no', 'no', NULL, 'no', NULL, 'READING AND COMMUNITY SERVICE', 'IMMEDIATELY', NULL, 'MR. SAMUEL TUATEBA TOYIN', 'REVENUE OFFICER', 'SENIOR REVENUE OFFICER', 'GHANA REVENUE AUTHORITY, WA STO', '0244547617', 'samuel.toyin@gra.gov.gh', 'MR. SAMUEL GOLDAN', 'AUDITOR', 'INTERNAL; AUDITOR', 'GHANA EDUCATION SERVICE, AUDIT UNIT', '0200161644', 'samuelgordan@gmail.com', 'MR. FRANCIS ADATARA', 'EDUCATIONIST', 'HEADMASTER', 'GAMBIBGO SENIOR HIGH SCHOOL, BOLGA-EAST', '0246131545', 'francisadatara@gmail.com', 'BTU_47A9E058_cv_6a2007cf2888e0.26429533.pdf', 'JOSEPH KPALIK YANBORIGYA CV.pdf', 'pending', NULL, '197.251.240.28', '2026-06-03 10:54:07', '2026-06-07 23:59:41', 'BTU_47A9E058_photo_6a2007cf288928.27606107.jpg', 'YANBORIYA  PASSPORT PICTURE.jpg'),
(290, 'BTU-6FC1FF5E', 5, 'Mr.', 'Asare', 'Collins Nana', 'cna91183@gmail.com', '+233535364165', 'P. O. Box 18227,  Adum', 'Asuom', 'Asuom', 'Eastern', 'Ghanaian', 'Christian', 'married', 'Abigail Frimpong', 'AK-404- 6235', 'Eden Bampoh Asare (10/08/19)\r\nKwame Asare Boateng (20/07/2024)', NULL, 'GHA-002931770-1', '1983-11-09', 'male', 'Master\'s Degree (MPhil.)', 'Kurukshetra University', 11, NULL, 'My academic qualifications, teaching experience, laboratory expertise, and research interests are highly relevant to the position of Lecturer in the Electrical and Electronics Engineering Department. I hold a Bachelor\'s degree in Telecommunications Engineering and a Master\'s degree in Electrical and Instrumentation Engineering, which have provided me with a strong foundation in electrical power systems, control systems, renewable energy technologies, and engineering analysis.\r\n\r\nCurrently, I serve as a Laboratory Technician at Kwame Nkrumah University of Science and Technology, where I support practical instruction, laboratory experiments, equipment maintenance, and student projects. In addition, I work as a Part-Time Lecturer at Kumasi Technical University, where I teach engineering courses, prepare instructional materials, assess students, and provide academic guidance.\r\n\r\nMy Master\'s thesis, &quot;EKF MPPT Control of Interleaved Boost Converter for PV Systems,&quot; focused on renewable energy and photovoltaic power conversion, providing me with practical and research experience in solar energy systems, maximum power point tracking techniques, power electronics, and control engineering. My broader research interests include renewable energy integration, microgrid design and optimization, smart grids, energy management systems, and the application of artificial intelligence to power and energy systems.\r\n\r\nMy teaching experience, laboratory skills, industry exposure, and research background prepare me to contribute to undergraduate teaching, laboratory supervision, curriculum development, student project supervision, and research activities in Power Systems and Renewable Energy. I am committed to advancing engineering education, conducting impactful research, and supporting Bolgatanga Technical University\'s mission to produce competent engineering professionals.', 'no', 'no', NULL, 'no', NULL, 'My hobbies include reading and exploring topics in electrical engineering, especially power systems, renewable energy, and control systems. I also enjoy working on simulation and practical engineering problems to improve my understanding of real-world applications. I spend time learning new technical tools and keeping up with developments in smart grids and power electronics. Outside of academics, I like watching footbal, listening to music and relaxing to refresh my mind.', 'At the end of this semester, From August,2026', 'I am highly committed to a career in academia and continuously developing my skills in teaching, research, and engineering practice. My experience as a Laboratory Technician at Kwame Nkrumah University of Science and Technology and Part-Time Lecturer at Kumasi Technical University has strengthened my ability to support both theoretical and practical engineering training. I am particularly interested in contributing to research and teaching in power systems, renewable energy integration, and smart grid technologies, and I am eager to contribute positively to the academic and research goals of the institution.', 'Prof. James Dzisi Gadze', 'Academic / University Lecturer', 'Professor', 'Department of Telecommunication Engineering, Kwame Nkrumah University of Science and Technology, Kumasi, Ghana', '+233 206891515', 'jdgadze.coe@knust.edu.gh', 'Dr. Ing. Adjei-Saforo Kwafo Edmund', 'Academic / University Lecturer', 'Senior Lecturer', 'Electrical/Electronic Engineering Department, Kumasi Technical University, Kumasi', '+233 242174713', 'edmund.asaforo@kstu.edu.gh', 'Jaipal Saroha Ph.D', 'Academic / University Lecturer', 'Associate Professor', 'Instrumentation Department, Kurukshetra University, Haryana, India,', '+919896076022', 'sarohajp@kuk.ac.in', 'BTU_6FC1FF5E_cv_6a20192bb8e0c0.44993920.pdf', 'BTU_CV.pdf', 'pending', NULL, '129.122.47.88', '2026-06-03 12:08:11', '2026-06-07 23:59:41', 'BTU_6FC1FF5E_photo_6a20192bb8e126.57891175.jpeg', 'WhatsApp Image 2026-05-20 at 9.41.43 AM.jpeg'),
(291, 'BTU-8EEFBD77', 16, 'Mr.', 'Hamidu', 'Inusah', 'yuhamid82@gmail.com', '+233503058173', 'Post Office Box 105\r\nNavrongo', 'Navrongo', 'Navrongo', 'Upper East', 'Ghanaian', 'Islam', 'married', 'Reina Woyongo', 'Abavana Street, Navrongo', 'Samira: 21/04/2014\r\nHisham Wunithorebu: 16/05/2021\r\nDonglabuni: 10/08/2023', NULL, 'GHA-716659833-0', '1982-08-03', 'male', 'Master\'s Degree (MPhil.)', 'Kwame Nkrumah University of Science and Technology', 11, '1. Afeliga, E., Hamidu, I. &amp; Kwame, A. (2026). ‘Comparing the frequency of quality control checks during day and night shifts on the production floor of a paper sack plant in Ghana’, E-Journal of Humanities, Arts and Social Sciences 7, no.1 159-168. https://doi.org/10.38159/ehass.20267112\r\n\r\n2. Hamidu, I. &amp; Rahman, A. (2025). ‘Sustainable packaging: Consumers’ evaluation of eco-labels in the Ghana’s packaging sector’, Sustinere: Journal of Environment and Sustainability, 9(2), 146–161. https://doi.org/10.22515/sustinere.jes.v9i2.483\r\n\r\n3. Kushiator, G., Klodzi, I., &amp; Hamidu, I. (2023). ‘Digital literacy: Teachers Challenges Integrating Graphic Design Technology in the Classroom’, SIBATIK JOURNAL: Jurnal Ilmiah Bidang Sosial, Ekonomi, Budaya, Teknologi, Dan Pendidikan, 2(11), 3541–3554. https://doi.org/10.54443/sibatik.v2i11.1452\r\n\r\nUnder Review\r\n4. Afeliga, E., Machael, A. E. Hamidu, I., Asamoah, K., Munyenyembe, H., Odis, A. I., &amp; Lavalie, E. D. M. (2025). ‘Assessing the Contributions of the Disposal Methods of Household Consumers to the Recycling Value Chain of Plastic Packaging in Ghana, Sierra Leone, and Zambia’, Journal of Material Cycles and Waste Management', 'My teaching philosophy is grounded in the belief that art and design education must be technically rigorous and culturally responsive. Over fourteen years of classroom practice, from secondary school through tertiary level, I have learned that students learn best when they can connect formal design principles to their lived visual experiences. I strive to create learning environments that honour the diverse cultural contexts students bring while equipping them with the skills and critical thinking capacities demanded by contemporary design practice.\r\nAt Awe Senior High Technical School, where I taught Graphic Design and General Knowledge in Art and served as the Head of the Department of Visual Arts, I developed and refined studio-based instructional approaches that balanced conceptual exploration with hands-on production. As a Part-Time Assistant Lecturer, I expanded this practice by teaching courses in Packaging Design, Corporate Identity, Visual Communication Principles, Computer Graphics, and Printing Techniques. Across all these contexts, I have employed instructional pedagogies that promote design thinking and problem-solving, thereby preparing students to communicate meaningfully through images and forms.\r\nI am committed to thoughtfully integrating technology into my teaching. My proficiency in Adobe Photoshop, Illustrator, InDesign, After Effects, and CorelDraw, alongside my experience supervising student projects for national examinations, informs my approach to assessment, one that values both process and outcome.', 'no', 'no', NULL, 'no', NULL, 'Farming, reading and watching documentaries.', 'One month', NULL, 'Rev. Augustine Atanga', 'Teaching', 'Headmaster of AWE SHTS', 'Post Office Box 105, Navrongo', '0208406898', NULL, 'Dr. Ismaila Moro', 'Teaching', 'Senior Lecturer', 'Department of Communication Design\r\nKwame Nkrumah University of Science and Technology', '233 205141551', 'ismoro.art@knust.edu.gh', NULL, NULL, NULL, NULL, NULL, NULL, 'BTU_8EEFBD77_cv_6a2019cf201130.86266233.pdf', 'Curriculum Vitae & Certificates.pdf', 'shortlisted', '', '154.161.249.7', '2026-06-03 12:10:55', '2026-06-12 23:30:08', 'BTU_8EEFBD77_photo_6a2019cf201190.60530738.jpg', 'Yunus passport pic.jpg'),
(292, 'BTU-6D7F32CB', 15, 'Dr.', 'Kanmiki', 'Kanluki Lambert', 'chiefkanmikikanlukilambert@gmail.com', '0246724011', 'Regional Education Office\r\nPostal Box 110\r\nBolgatanga U/E/R', 'Navrongo', 'Navrongo', 'Upper East', 'Ghanaian', 'Christianity', 'married', 'Mrs Christiana Ayinpoka Kanmiki', 'The Palace of the Saama Naba of Bongo C/o Postal Box 4 Bongo.', 'Lugard Asakiwine Kanmiki\r\nLuciana Ayewine Kanmiki\r\nLucencia Abisiyen Kanmiki', 'P0002998831', 'GHA-716204857-8', '1984-10-20', 'male', 'PhD', 'University For Development Studies', 11, NULL, 'As Head of the Quality Assurance Unit at Millar Open University, my experience aligns perfectly with the Assistant Registrar\'s role, enabling me to significantly and swiftly enhance the department with minimal oversight.', 'no', 'no', NULL, 'no', NULL, 'Community outreach and socialisation', 'immediately', 'My background in Public Administration and experience as head of quality assurance make me highly suitable for this role.', 'Dr Alfred Akapanga', 'Registrar', 'Registrar at Millar Open University', 'Millar Institute for Transdisciplinary and Development Studies \r\nPostal Box 607, Bolgatanga.', '0544133966', 'wakapanga@gmail.com', 'Professor David Millar', 'Lecturer', 'Professor and President of the Millar Open University', 'Millar Institute for Transdisciplinary and Development Studies \r\nPostal Box 607, Bolgatanga.', '0244720834', 'millarad1@yahoo.com', 'Bonaba Baba Salifu Atamale Alemyarum', 'Retired Civil servant', 'Paramount Chief of the Bongo Traditional Area.', 'Palace of the Paramount Chief of Bongo\r\nC/o Postal Box 4\r\nBongo.', '0243743969', 'bonabababa@gmail.com', 'BTU_6D7F32CB_cv_6a201ee4194ee8.80520100.pdf', 'CV_OF_Dr_KANMIKI_KANLUKI_LAMBERT_BTU.pdf', 'pending', NULL, '41.155.64.131', '2026-06-03 12:32:36', '2026-06-07 23:59:41', 'BTU_6D7F32CB_photo_6a201ee4194f30.60445391.jpg', 'Passport Of Chief Dr Kanmiki Kanluki Lambert.jpg'),
