(74, 42, 'August 202', NULL, 'Bolgatanga technical university', 'Bolgatanga Upper East Region', 'Part-time Assistant lecturer for engineering mathematics', 'As an Assistant Lecturer in Engineering Mathematics at Bolgatanga Technical University.\r\nMy main duties included teaching and facilitating courses such as Introduction to Engineering Mathematics, \r\nEngineering Mathematics I, and Engineering Mathematics II for BTech and HND students. \r\nI prepared lecture notes, tutorials, assignments, and examinations, guided students in solving engineering and applied mathematics problems, assessed students’ academic performance, and provided academic support and mentoring to students. \r\n\r\nI also contributed to the  promotion of practical application of mathematics in engineering and technology fields.', 'full-time', NULL, 0),
(75, 42, 'September,', NULL, 'Zuarungu Senior High School', 'Zuarungu Senior High School P.O.Box 133  Bolgatanga-East', 'Mathematics teacher', 'As a Mathematics Teacher at Zuarungu Senior High School, my duties included teaching core and elective mathematics subjects, preparing lesson notes and instructional materials, setting and marking assignments and examinations, supervising and guiding students academically, conducting classroom activities and workshops, invigilating examinations, and providing academic counseling and support to improve students’ performance in mathematics.', 'full-time', NULL, 1),
(76, 43, 'August 202', 'Till prese', 'Bolgatanga technical university', 'Post Office Box 767 Upper East Region Ghana', 'Part-time Assistant lecturer for engineering mathematics', 'As an Assistant Lecturer in Engineering Mathematics at Bolgatanga Technical University, my main duties included teaching and facilitating courses such as Introduction to Engineering Mathematics, Engineering Mathematics I, and Engineering Mathematics II for BTech and HND students. I prepared lecture notes, tutorials, assignments, and examinations, guided students in solving engineering and applied mathematics problems, assessed students’ academic performance, and provided academic support and mentoring.\r\n I also contributed to curriculum delivery, departmental academic activities, and promoted the practical application of mathematics in engineering and technology', 'full-time', 'For  professional development', 0),
(77, 43, 'September ', NULL, 'Zuarungu Senior High School', 'Zuarungu Senior High School P.O.Box 133  Bolgatanga-East', 'Mathematics teacher', 'As a Mathematics Teacher at Zuarungu Senior High School, my duties included \r\n1. Teaching core and elective mathematics subjects.\r\n2. Preparing lesson notes and instructional materials, setting and marking assignments and examinations.\r\n\r\n3. Supervising and guiding students academically, conducting classroom activities and workshops.\r\n4. Invigilating examinations, and providing academic counseling and support to improve students’ performance in mathematics.', 'full-time', NULL, 1),
