(172, 88, 'AUGUST,201', NULL, 'AFRIKIDS MEDICAL CENTRE', 'BOLGATANGA', 'FINANCE OFFICER', '•	Review and Audit invoice and requisition for appropriate documentation and approval prior to payment.\r\n•	Ensure obligations of organization are within terms and met in a time manner.\r\n•	Utilize integrated accounting system to ensure accuracy and completeness of transaction for reporting.\r\n•	Maintain accurate financial records by maintaining, researching and updating accounting document in files and electronic format.\r\n•	Assist with month end closing and prepare journals entries necessary to reconcile General Lager.\r\n•	Prepare and process electronic funds transaction and payment for intercompany transactions.\r\n•	Reconciled vendor statement, research and resolve invoices discrepancies and issues.', 'full-time', NULL, 0),
(173, 89, 'April, 202', 'April, 202', 'Mamprobi Gale Community Library', 'Mamprobi, Accra', 'Librarian', 'Maintain a clean, organized, and welcoming library environment.\r\nEnsure safety and appropriate behavior in the library.\r\nManage library websites, online catalogs, e-books, and digital resources.\r\nProvide training on digital tools, devices, and online safety.', '', 'Accommodation challenges', 0),
(174, 89, 'July,2024', NULL, 'Tema West Municipal Assembly', 'Lashibi, Tema', 'Principal Executive Officer', 'Providing administrative and managerial support.\r\nOverseeing record management systems.\r\nCoordinating statutory meeting and management meeting.', 'full-time', NULL, 1),
(175, 90, '11/2025-4/', 'Sept 2024', 'Hat AgriTech Lmt', 'BK28 Passion Fruit Street Amrahia-Otinibi, GM-240-2042 Accra, Ghana, Phone: +233 24 210 7818, Email: info@hatagritech.com', 'Farm Supervisor', '1. Supervised daily farm operations including land preparation, planting, irrigation, fertilizer application, pest and disease control, and harvesting activities.\r\n2. Coordinated and monitored farm workers to ensure timely completion of tasks and adherence to good agricultural practices and safety standards.\r\n3. Managed the application and inventory of agricultural inputs such as seeds, fertilizers, agrochemicals, and irrigation equipment.\r\n4. Monitored crop growth and field performance, prepared farm reports, and implemented measures to improve productivity and crop health.\r\n5. Assisted in farm planning, postharvest handling, marketing, and maintenance of farm machinery, tools, and irrigation systems to support efficient farm operations.', '', 'End of contract', 0),
(176, 90, 'Jan 2024', 'Oct 2022', 'Department of Horticulture, KNUST, Kumasi.', 'KNUST (Main Campus), PMB (Private Mail Bag), University Post Office, Kumasi, Ghana', 'Graduate Assistant', 'Assisted in the delivery of lectures, tutorials, and practical sessions in horticultural science and related agricultural courses.\r\nSupported the design, monitoring, and data collection of experimental field trials, ensuring accuracy and reliability for research analysis.\r\nMentored and supervised undergraduate students in coursework, field practicals, and final-year research projects.\r\nContributed to departmental research activities, including data processing, field observations, and report preparation.\r\nAssisted in academic assessment processes and provided technical support during teaching and learning activities.', 'full-time', 'End of service', 1),
(177, 90, 'Oct 2021', 'Oct 2025', 'Department of Horticulture, KNUST', 'KNUST (Main Campus), PMB (Private Mail Bag), University Post Office, Kumasi, Ghana', 'Teaching assistant', '1. Assisted in delivering lectures on fruit crop production, fundamentals of horticulture, and special topics \r\nin fruit crops, enhancing students’ engagement.\r\n2. Supervised and guided undergraduates and postgraduates’ students research projects, ensuring timely \r\ncompletion and quality output.\r\n3. Assisted in marking and grading, data entry and thesis review, maintaining accuracy and academic standards.', 'full-time', 'End of internship', 2),
(178, 90, 'Aug 2025', NULL, 'FarmMate Africa', 'Tetteh Ashong Street, https://farmmate.africa, ⁠Accra, Ghana', 'Intern', '1. As part of the winning team of the 2025 GNBCC Horticulture Business Challenge (HBC), completed an interned with FarmMate Africa focus on horticultural value chain improvement.\r\n2. Co-developed evidence-based pre-and postharvest loss reduction modules with my team and FarmMate \r\nAfrica. \r\n3. Researched and proposed practical postharvest interventions, including tomato puree processing, \r\ncomposting, and improved packaging systems. \r\n4. Contributed to the development of strategies that enhances farmers’ productivity, income, and food \r\nsecurity.', 'full-time', NULL, 3),
(179, 91, 'September ', NULL, 'Centre for Plant Medicine Research', 'Post Office Box 73, Mampong-Akuapem, Eastern Region, Ghana. West Africa', 'Senior Accountant (Head, Budget and Evaluation)', 'Responsible for budgeting, monitoring, and evaluation to ensure that the Centre has a well-prepared budget and also operates within its approved appropriation budget. Preparation of the budget implementation report and variance analysis. As a senior accountant, I am also responsible for preparing the Centre\'s financial statements. I am also responsible for payroll management at the Controller and Accountant General’s Department (CAGD) and for the Internally Generated Fund (IGF) staff, supervising and ensuring compliance with statutory requirements, i.e., excise duty returns, VAT returns, PAYE, withholding taxes, SSNIT, and other accounting-related duties. Moreso, I supervise the preparation of donor fund reports and also review all reconciliations (Cash and bank).', 'full-time', NULL, 0),
(180, 91, 'September ', NULL, 'Centre for Plant Medicine Research', 'Post Office Box 73, Mampong-Akuapem, Eastern Region, Ghana. West Africa', 'Accountant', 'Acting as head of the Department in the absence of the Departmental Head to oversee the administrative affairs of the department. I assist in the accurate and timely preparation of quarterly, semi-annual, and annual consolidated financial reports for management, the Board, the Ministry of Finance, and the Ministry of Health, utilizing Topaz Accounting Software. I supervise the preparation of donor fund reports and also review all reconciliations (Cash and bank). I am the secretary to the products and services costing and pricing team. I am in charge of accounts payable and receivable review. I am also responsible for payroll management at the Controller and Accountant General’s Department (CAGD) and for the Internally Generated Fund (IGF) staff, supervising and ensuring compliance with statutory requirements, i.e., excise duty returns, VAT returns, PAYE, withholding taxes, SSNIT, and other accounting-related duties.', 'full-time', NULL, 1),
(181, 91, 'February 2', NULL, 'McNeilus SDA School', 'Post Office Box 2834, Kumasi, Ashanti Region', 'Accountant (Finance Officer)', 'Responsible for the financial management of the school, preparation of terminal and annual financial reports using SunPlus Accounting Software, performing all reconciliations, accounts payables and receivables, payroll, filing of taxes, and other accounting-related duties. I was also in charge of budget preparation and performance evaluation for the school. As well as head of the stores and kitchen.', 'full-time', NULL, 2),
(182, 92, 'OCTOBER, 2', 'MAY, 2026', 'MBA ASSOCIATES, CHARTERED ACCOUNTANTS', 'KUMASI, ASHANTI REGION', 'AUDIT STAFF', '1. PREPARATION OF ACCOUNTS FOR CLIENTS\r\n2. AUDIT OF FINANCIAL REPORTS OF CLIENTS\r\n3. HANDLING CLIENT TAX MATTERS.\r\n4. REVIEWING AND SETTING UP INTERNAL CONTROL SYSTEMS', 'full-time', 'STILL AT POST', 0),
(183, 92, 'NOVEMBER 2', NULL, 'GES-ISLAMIC SENIOR HIGH SCHOOL', 'KUMASI, ASHANTI REGION', 'SUBJECT TEACHER', 'TEACHES FINANCIAL ACCOUNTING AND COST ACCOUNTING', 'full-time', NULL, 1),
(184, 93, 'September ', 'August 202', 'Centre for Plant Medicine Research', 'Post Office Box 73, Mampong-Akuapem, Eastern Region, Ghana. West Africa', 'Senior Accountant (Head, Budget and Evaluation)', 'In charge of budgeting, monitoring, and evaluation to ensure that the Centre has a well-prepared budget and also operates within its approved appropriation budget. Preparation of the budget implementation report and variance analysis. As a senior accountant, I am also responsible for preparing the Centre\'s financial statements. Moreso, I handle all the tax types (VAT, Excise duty, PAYE, withholding taxes, etc.) that the Centre is liable to pay', 'full-time', 'I was promoted to the next position', 0),
(185, 93, 'September ', 'August 201', 'Centre for Plant Medicine Research', 'Post Office Box 73, Mampong-Akuapem, Eastern Region, Ghana. West Africa', 'Accountant', 'Acting as head of the Department in the absence of the Departmental Head to oversee the administrative affairs of the department. I assist in the accurate and timely preparation of quarterly, semi-annual, and annual consolidated financial reports for management, the Board, the Ministry of Finance, and the Ministry of Health, utilizing Topaz Accounting Software. I supervise the preparation of donor fund reports and also review all reconciliations (Cash and bank). I am the secretary to the products and services costing and pricing team. I am in charge of accounts payable and receivable review. I am also responsible for payroll management at the Controller and Accountant General’s Department (CAGD) and for the Internally Generated Fund (IGF) staff, supervising and ensuring compliance with statutory requirements, i.e., excise duty returns, VAT returns, PAYE, withholding taxes, SSNIT, and other accounting-related duties.', 'full-time', 'Better offer', 1),
(186, 93, 'February 2', NULL, 'McNeilus SDA School', 'Post Office Box 2834, Kumasi, Ashanti Region', 'Accountant (Finance Officer)', 'Responsible for the financial management of the school, preparation of terminal and annual financial reports using SunPlus Accounting Software, performing all reconciliations, accounts payables and receivables, payroll, filing of taxes, and other accounting-related duties. I was also in charge of budget preparation and performance evaluation for the school. As well as, head of the stores and kitchen.', 'full-time', NULL, 2),
(187, 94, 'March 2023', NULL, 'BESSFA Community Bank PLC', 'Garu-Upper East Region', 'Assistant Internal Audit Manager', '	Internal audit and control processes\r\n	Compliance with regulatory and statutory requirements\r\n	Initiate and propose changes to inefficient, inadequate and obsolete controls for consideration by the head of internal audit.\r\n	To maintain a high level of integrity and value of service to the internal audit unit.', '', 'End of Contract', 0),
(188, 94, 'Aug 2018', NULL, 'Cargill Kokoo Sourcing Ltd', 'Tema, Free zones', 'Sourcing Clerk', '•	Conducted thorough daily and monthly bank statement reconciliations, ensuring accuracy and identifying discrepancies for prompt resolution.\r\n•	Assisted in the preparation of monthly budgets, providing valuable insights and contributing to effective financial planning.\r\n•	Administered the petty cash system, ensuring proper documentation and compliance with company policies.\r\n•	Managed electronic data processing tasks, enhancing efficiency and accuracy in financial transactions. \r\n•	Handled the secure lodgment of cash and Cheques, minimizing risks and ensuring financial integrity', 'full-time', NULL, 1),
(189, 95, '2023 till ', '2014', 'Tamale Technical University – Department of Languages and International Relations', 'Tamale Technical University, Tamale Northern Region', 'Part-time Lecturer', '•	Teach Communication Skills \r\n•	Teach English Language Usage and Creative Writing \r\n•	Examine students through assignments, mid-semester and end of semester examinations\r\n•	Provide special guidance to students who have special weaknesses\r\n•	Mentor and guide students on their academic and career plans\r\n•	Perform other duties assigned me by the Head of Department\r\n•	Research in my subject areas to be abreast with current trends', 'part-time', NULL, 0),
(190, 95, '2022', '2012', 'St. Victor’s Major Catholic Seminary', 'St. Victor’s Major Catholic Seminary, Tamale Northern Region', 'P  art-time Lecturer', '•	Teach English Grammar \r\n•	Teach Academic Writing\r\n•	Use different methods of instructions that suit learners from different backgrounds (Anglophone and Francophone) \r\n•	Assess the academic progress of seminarians \r\n•	Give special attention to seminarians who have special needs or weaknesses in academic work', 'part-time', NULL, 1),
(191, 95, '2014', 'Till Date', 'Tamale Film and Television Academy', 'Film and Television Academy, Tamale Northern Region', 'Instructor/General Manager', '•	Taught\r\n-	Commination Skills\r\n-	Script Writing\r\n-	News Gathering \r\n-	Reporting/Presenting \r\n-	Media ethics \r\n•	Ran the day-to-day administration of the academy\r\n•	Provided technical and professional advice to the Chief Executive Officer towards the progress of the school.\r\n•	Worked towards a balanced welfare for students and staff\r\n•	Served as a` spokesperson for the academy\r\n•	Supervised other employees \r\n•	Led the corporate social responsibility activities of the organisation\r\n•	Led the research activities of the organisation \r\n•	Represented the academy at programmes\r\n•	Identified and liaised with media houses within Tamale for students’ attachment', 'full-time', NULL, 2),
(192, 95, '2012', NULL, 'Discovery Television', 'Tamale, Northern Region', 'Content Provider and Reporter', '•	Worked as a content provider and reporter to Discovery Television, the first television company in Northern Ghana\r\n•	Identified and wrote scripts for interesting contents that could market the company\r\n•	Led crews to cover identified and scripted contents, and get them edited. \r\n•	Did voice-over to stories, where necessary. \r\n•	Worked with other reporters and presenters for contents that demanded more than one reporter or presenter.  \r\n•	Made the necessary contacts with persons, groups, institutions and organisations that fell within our contents before the actual days of coverage.', 'full-time', NULL, 3),
(193, 95, '2009', NULL, 'Indigenes Films', 'Tamale, Northern Region', 'Regional Reporter', '•	Worked as a reporter for the entire Northern Ghana for indigenes Films, a content provider to major television stations and production houses in Ghana\r\n•	Identified stories including documentaries that fell within the organisation’s interest area\r\n•	Wrote scripts for the identified stories and documentaries. \r\n•	Covered the identified stories and documentaries, and get them edited. \r\n•	Did a voice-over for the stories and documentaries\r\n•	Completed all tasks and submitted them timely\r\n•	Served as a leader of the crew', 'full-time', NULL, 4);
INSERT INTO `employment_entries` (`id`, `application_id`, `from_date`, `to_date`, `institution_name`, `institution_address`, `position`, `subject_work`, `nature`, `reason_for_leaving`, `sort_order`) VALUES
(194, 95, '2009', NULL, 'Business Senior High School', 'Tamale, Northern Region', 'Teacher of English/Staff Secretary/Editor of the School’s Magazine', '•	Work collaboratively with school administrators to implement intellectually challenging program that provided creative outlet for students\r\n•	Foster positive and pleasant classroom culture while maintaining learning development goals\r\n•	Enhance student comprehension by incorporating visual aids and hands-on activities into lesson plans\r\n•	Boost students’ critical thinking skills through engaging debates and group discussions\r\n•	Provide guidance and mentoring to students regarding academic, social and emotional issues\r\n•	Implement innovative assessment methods that focused on measuring student growth rather than just test scores, providing more accurate feedback on learning outcomes\r\n•	Organise extracurricular activities such as clubs and field trips to enrich students’ educational experiences outside the classroom setting\r\n•	Provide one-on-one tutoring sessions for students needing additional assistance, improving their overall academic performance\r\n•	Develop and implement variety of instructional strategies to meet diverse needs of students\r\n•	Serve as a mentor to new teachers, providing guidance on effective classroom management strategies and teaching methodologies', 'full-time', NULL, 5),
(195, 96, 'JANUARY 20', NULL, 'UNIVERSITY OF PROFESSIONAL STUDIES, ACCRA', 'GREATER ACCRA', 'PART-TIME LECTURER', 'I taught Communication skills, and Academic writing. I was involved in the following: \r\n•	Assisted in preparing course outline and other course materials\r\n•	Prepared and delivered lectures on Interpersonal Communication Skills and Academic Writing Skills.\r\n•	Graded and assessed student assignments, quizzes, and exams, and discussed modalities for improvement.\r\n•	Established and maintained good rapport with students that encouraged learning in a connected and enjoyable atmosphere.\r\n•	Participated in departmental and staff meetings\r\n•	Provided need-based guidance and counselling to students', 'full-time', NULL, 0),
(196, 96, 'September ', NULL, 'TAMALE TECHNICAL UNIVERSITY', 'NORTHERN REGION', 'PART-TIME COMMUNICATION SKILLS LECTURER', 'Key Responsibilities:\r\n•	Assist in preparing course outline and other course materials\r\n•	Prepare and deliver lectures on Communication Skills and the English language\r\n•	Grade and assess student assignments, quizzes, and exams, and discuss modalities for improvement.\r\n•	Establish and maintain good rapport with students that encourages learning in a connected and enjoyable atmosphere.\r\n•	Participate in departmental and staff meetings\r\n•	Providing need-based guidance and counselling to students', 'full-time', NULL, 1),
(197, 97, 'APRIL, 201', NULL, 'department of Agriculture', 'Box 3, c/o MoFA', 'AGRICULTURAL OFFICER', 'Provide agricultural extension services and technical guidance to farmers on modern farming practices, crop production, livestock management, and climate-smart agriculture.\r\n\r\nOrganize farmer education programmes, demonstrations, workshops, and field visits to enhance crop productivity and promote sustainable agricultural practices.\r\n\r\nFacilitate farmers’ access to agricultural inputs, government interventions, credit opportunities, and market linkages to improve livelihoods and food security.\r\n\r\nSupport the implementation of government agricultural policies, programmes, and rural development initiatives while promoting community participation and value chains and agribusiness development, among other best practices.', 'full-time', NULL, 0),
(198, 97, 'JANUARY, 2', NULL, 'GHANA STATISTICAL SERVICE', 'UPPER WEST REGIONAL STATISTICAL SERVICE OFFICE', 'NATIONAL TRAINER/DISTRICT CENSUS OFFICER, UPPER WEST REGION - WA', '1. Trained all regional and district officers in the census process\r\n2. Supervised all field training and gave refresher training to all field officers in the field\r\n3. Monitored all processes throughout the census period', 'full-time', NULL, 1),
(199, 98, '2017 TO DA', NULL, 'Bolgatanga Technical Institute', 'Bolgatanga Technical Institute. Post office box 295, Bolgatanga Upper East Region', 'HEAD OF DEPARTMENT', 'As Head of the Electrical Engineering Technology Department, I coordinate both the academic and administrative activities of the department, overseeing the learning and professional development of approximately 600 students and 8 teaching staff. My responsibilities include curriculum planning and implementation, staff supervision, student mentoring, timetable coordination, laboratory and workshop management, and ensuring high standards in teaching, safety, and practical training.\r\nOver the years, I have taught a wide range of courses, including Electrical Principles, Electrical Technology, Electrical Installation, Electrical Practical, Industrial Electronics, Electrical Circuit Theory and Analysis, and Electrical Machines and Drives. My teaching combines strong theoretical foundations with practical, hands-on learning to prepare students for real-world engineering challenges. I also taught AC/DC circuit analysis, network theorems, electronic measurements, transformers, generators, AC/DC motors, and industrial control drives, with emphasis on practical operation and maintenance.\r\nIn addition, my academic and professional interests focus on Renewable and Sustainable Energy Technologies, Energy Efficiency in Electrical Systems, Technical Education in Emerging Economies, and the integration of practical skills into engineering curricula. I am passionate about developing industry-ready graduates through competency-based technical education, innovation, and applied engineering practice.', 'full-time', NULL, 0),
(200, 99, '2015', NULL, 'BOLGATANGA SENIOR HIGH SCHOOL', 'BOX 176, BOLGA', 'FACILITATOR', 'House mistress, form teacher, social studies', 'full-time', NULL, 0),
(201, 100, 'October 20', NULL, 'Kwame Nkrumah University of Science and Technology', 'KNUST', 'PhD. Student/Teaching Assistant', 'Deliver tutorials and practical sessions for undergraduate courses: Construction \r\nTechnology, Building Materials, and Construction Project Management \r\nPrepare lecture notes, marking schemes, and technical demonstrations. \r\nSupervise undergraduate research projects and dissertations. \r\nSupport faculty research in sustainable and regenerative construction materials. \r\nConduct laboratory characterization of clay-based, fibre-reinforced composites. \r\nContribute to manuscript development and peer review activities. \r\nAssist in PhD and MPhil student research coordination.\r\nStrength of Materials\r\nPrinciples of Land Surveying\r\nSoils and Foundation Systems\r\nIntroduction to Building Measurement\r\nMeasurement\r\nCommercial Law\r\nLaw of Contract and Arbitration\r\nCivil Engineering Construction', 'full-time', NULL, 0),
