(218, 112, 'April 2023', NULL, 'Baldwin University College, Accra', 'Osu Troas Street Accra, Ghana P.O. Box 19872, Accra-North, Accra Digital Address: GA-082-6568', 'Lecturer', 'My teaching experience spans Information Security, Operating System Security, Networks and Data Communications, Computer Architecture and Organization, Cybersecurity Risk Management, Computing Ethics, Data and Network Security, Application Security, and Ethical Hacking. My teaching philosophy emphasizes participatory and hands-on learning, integrating theoretical foundations with practical application through laboratory sessions, real-world projects, and discussions.', 'full-time', NULL, 0),
(219, 112, 'Sep 2025', NULL, 'SIIMT University College. Shiv-Indian Institute of Management and Technology (SIIMT), Accra', 'Accra, Ghana', 'Adjunct Lecturer in Information Security', 'Delivering specialized courses in Information Security, with modules that include: \r\n• Risk Management in Information Systems \r\n• Distributed Networks and Security \r\n• Systems Administration and Security \r\n• Internet Protocols and Security \r\n• Digital Forensics \r\n• Ethical Hacking and Penetration Testing', 'full-time', NULL, 1),
(220, 112, 'Jan 2025', NULL, 'Kessben University College, Kumasi', 'Kumasi, Ashanti Region, Ghana', 'Adjunct Lecturer in Information Technology', 'Delivering a comprehensive curriculum in IT, with courses that include: \r\n- Introduction to Computer Engineering\r\n- Digital Circuit and Electronics \r\n- Information Security \r\nMy role focuses on developing students\' technical skills and knowledge, providing a solid \r\nfoundation for their future careers in IT.', 'full-time', NULL, 2),
