(224, 114, 'NOVEMBER, ', NULL, 'BOLGATANGA TECHNICAL UNIVERSITY', 'P.O. BOX 255, BOLGATANGA', 'PART-TIME LABORATORY TECHNICIAN', 'Preparing laboratory equipment, chemicals, specimens, and materials before practical sessions.\r\nAssisting lecturers during laboratory practicals and demonstrations.\r\nMaintaining cleanliness and safety in the laboratory.\r\nOperating, calibrating, and maintaining laboratory equipment.\r\nRecording laboratory results and keeping proper documentation.', 'full-time', NULL, 0),
(225, 115, 'FEBRUARY 2', NULL, 'QUEEN OF PEACE SENIOR HIGH SCHOOL', 'X0-0064-4848', 'TEACHING', 'Nestor Banye King Yuoni is my name. A Ghanaian educationist, researcher, and school administrator with over 15 years of experience in teaching, educational leadership, and academic research. I hold MPhil and M.Ed degrees in Educational Administration and Management, a post-graduate Diploma in Education all  from the University of Education, Winneba (UEW) and am currently pursuing a PhD in  Educational Leadership.\r\nI am currently with Queen of Peace Senior High School in Nadowli, Upper West Region, where I have served in various capacities, including teacher, facilitator, coordinator, and examiner. My research interests focus on Educational Administration and Management, policy, curriculum implementation, school leadership, and mathematics education in Ghana', 'full-time', NULL, 0),
(226, 116, 'September ', 'September ', 'Catholic Relief Services', 'Tamale', 'Senior Project Officer | Regional Lead – Volta and Oti', '•	Leading implementation of a USD 7.2 million Mastercard Foundation-funded consortium programme focused on youth employment, entrepreneurship, agricultural livelihoods, and financial inclusion across the Volta and Oti Regions of Ghana. \r\n•	Coordinating programme planning, implementation, monitoring, and reporting across six districts to ensure timely delivery against approved workplans, KPIs, and donor requirements. \r\n•	Supervising and mentoring a team of six Project Officers, strengthening technical quality, accountability, performance management, and operational efficiency across field activities. \r\n•	Facilitating multi-stakeholder coordination with district assemblies, Department of Agriculture, consortium partners, private sector actors, and community stakeholders to strengthen programme alignment and service delivery. \r\n•	Supporting programme financial planning and management through budget tracking, cash forecasting, procurement planning, compliance monitoring, and operational risk management. \r\n•	Prepared technical, operational, and donor reports to support programme monitoring, accountability, compliance, and strategic decision-making. \r\n•	Contributed to technical documentation, proposal development, implementation reporting, and preparation of programme updates for donor-funded agriculture and livelihood interventions. \r\n•	Co-developed and supported rollout of Good Agronomic Practices (GAPs) training curricula to strengthen climate resilience, productivity, and sustainable agricultural production among smallholder farmers. \r\n•	Led the technical design and implementation support for 57 small-scale irrigation systems across 18 districts, improving year-round vegetable production, water-use efficiency, and income generation for over 1,000 smallholder farmers. \r\n•	Integrated climate-smart agriculture and productive water management approaches into programme implementation to promote resilient agrifood systems, sustainable livelihoods, and evidence-based programme delivery.', 'full-time', 'Transitioned to different role', 0),
(227, 116, 'May 2024', 'April 2024', 'Catholic Relief Services', 'Bolgatanga', 'Water Sanitation and Hygiene (WASH) - Specialist', '•	Supported operational oversight of WASH and environmental management portfolios, ensuring compliance, efficiency, and partner coordination.\r\n•	Led stakeholder engagement with local authorities, traditional leaders, and community institutions.\r\n•	Contributed to proposal development, donor reporting, and implementation planning.\r\n•	Integrated financial inclusion mechanisms into service delivery models to strengthen sustainability and cost recovery.', 'full-time', 'Promoted', 1),
(228, 116, 'November 2', 'November 2', 'Catholic Relief Services', 'Bolgatanga', 'Project Officer (WASH)', '•	Coordinated community-based and district-level operations for water and resilience projects across multiple regions.\r\n•	Led design, supervision, and commissioning of water infrastructure and service delivery models.\r\n•	Pioneered Multi-Use Water Services (MUS) approaches, transforming single-purpose systems into integrated platforms supporting domestic use, irrigation, livestock, and micro-enterprises.\r\n•	Built and managed partnerships with NGOs and social enterprises, including a strategic collaboration with SAHA Global that established community water businesses operated by women entrepreneurs.\r\n•	Supported budgeting, forecasting, impact reporting, and documentation of success stories for donors and leadership.', 'full-time', 'Better opportunity', 2),
(229, 116, 'January 20', 'December 2', 'Ga West Municipal Assembly – Department of Agriculture', 'Accra', 'Assistant Agricultural Officer', '•	Delivered farmer training in Climate-Smart Agriculture, conservation tillage, irrigation management, and regenerative practices.\r\n•	Led field demonstrations on Farmer Managed Natural Regeneration (FMNR)-linked interventions, soil moisture retention, and dry-season farming.\r\n•	Conducted field reporting and supported planning processes.', 'full-time', 'Better opportunity', 3),
(230, 116, 'October 20', 'August 201', 'Geogold Engineering Services and Geoppexx Enterprise', 'Tamale', 'Supporting Hydrogeologist', '•	Led and coordinated field team activities, ensuring efficient execution of WASH projects.\r\n•	Assisted in the design, bill of quantities (BoQ) development, and review for WASH infrastructure projects.\r\n•	Supervised the construction of limited water supply systems and borehole drilling operations.\r\n•	Conducted hydrogeological surveys to inform water resource management.\r\n•	Supported logistical arrangements for field activities and provided assistance in dredging dugouts.', '', 'Service ended', 4),
(231, 116, 'September ', 'August 201', 'World Vision International', 'Tamale', 'Assistant Hydrogeologist (Voluntary National Service)', '•	Conducted desk studies, surveys, and community profiling to support the design of groundwater facilities.\r\n•	Performed geophysical surveys and water quality tests to guide drilling site selection and project success rates.\r\n•	Provided technical support in the design and construction of groundwater facilities, ensuring quality and feasibility.\r\n•	Led reconnaissance surveys for UN HABITAT WASH projects and contributed to the development of bills of quantities for infrastructure.', 'full-time', 'Service ended', 5),
(232, 116, 'September ', NULL, 'Ghana Irrigation Development Authority', 'Tamale', 'Field Officer (National Service)', '•	Scheduled and optimized irrigation to ensure efficient water use for crops.\r\n•	Trained farmers in erosion control, water management, and conservation agriculture.\r\n•	Monitored weather stations and collected climatic data for informed decision-making.\r\n•	Supported students and researchers in field trials and demonstration plots.', 'full-time', NULL, 6),
