(282, 143, 'Sept. 2015', NULL, 'Volta Regional Hospital, Hohoe', 'P. O. Box 27, Hohoe', 'Laboratory Technician', 'Miantained laboratory quality assurance and safety standards.\r\nConducted sputum microscopy and GeneXpert diagnostics for tuberculosis detection.\r\nPerformed general laboratory test and procedures.\r\nTrained medical laboratory students on intenship in general medical and molecular diagnostic techniques.', 'full-time', NULL, 2),
(283, 144, 'May 2018', NULL, 'Lawra Senior High School', 'Lawra, Upper West Region', 'Asisstant Accountant', 'Managed school finances, including fee collection, receipts issuance, and accurate record keeping \r\nPrepared financial records (cash books, ledgers) and assisted in reporting to management\r\nMonitored budgets and expenditures to ensure effective cost control \r\nSupported internal and external audits by organizing records and ensuring compliance with, Public Financial Management Act and Ghana Education Service policies\r\nUtilized ICT tools (e.g., Microsoft Excel, accounting software) for financial reporting, documentation, and client support\r\nPerformed bank reconciliations to ensure accuracy between financial records and bank statements \r\n•Ensured tax compliance and prepared/filed tax returns in accordance with Ghana Revenue Authority regulations \r\nFinance Officer | SD Dombo University Alumni', 'full-time', NULL, 0),
(284, 145, 'Jan, 2023', NULL, 'Royal Scholars Montessori', 'P.O.Box SE245-Suame Kumasi', 'School Administrator', '1. I formulate school development strategies with the aim to attain the school vision and education goals and enhance learning effectiveness.\r\n2. I draw up policies and priorities for development projects.\r\n3. I review school income and expenditure regularly to ensure that resource development is in line with the school development plan and caters for the needs of the students.\r\n4. I ensure curriculum design is in line with government education policies.', 'full-time', NULL, 0),
(285, 145, 'Jan 2017', NULL, 'Golden Bridge Educational Institute', 'Chengdu, China', 'ESL Teacher', 'As an ESL (English as a Second Language) teacher in China, I was responsible for helping students learn and improve their English communication skills. some of the main duties included: Teaching English Language Skills, Lesson Planning, Classroom Management, Assessing Students, Cultural Exchange, Participating in School Activities and Working Hours and Administration', 'full-time', NULL, 1),
(286, 145, 'Sept 2012', NULL, 'Kintampo Health Research Centre', 'Kintampo', 'Research Officer', 'As a Research Officer I was responsible for conducting, managing, and supporting research activities within an organization. Core Responsibilities included:  Conduct Research, Develop Research Plans, Data Management and Analysis, Prepare Reports and Publications, Monitor and Evaluate Projects and Stakeholder Engagement.', 'full-time', NULL, 2),
(287, 146, 'August 2, ', NULL, 'University of Ghana', 'Department of Distance Education, P. O. Box LG31, Legon, Accra', 'Principal Organiser/ Programme Officer', 'Duties/Responsibilities\r\n•	Recruit tutors for the University of Ghana distance education programmes. \r\n•	Collate and compute students’ records.\r\n•	Invigilate end-of-semester examinations\r\n•	Manage the assets under the control of my unit.\r\n•	Provide input for the preparation of the department budget.\r\n•	Assist in writing reports on distance education programmes.\r\n•	Attend to students’ inquiries and delete courses wrongly registered by students on the ITS.\r\n•	Assist students in their online registration and course selection.\r\n•	Work with Educational Technology Units on campus to design, develop, and produce courses in various multi-media delivery modes, including e-learning, videos, games, and animations.\r\n•	Develop annual financial and operational plans for the Material Development Unit.\r\n•	Ensure economic use of resources, including funds allocated to the unit, and liaise with departments to recruit course writers and organise training workshops for them.\r\n•	Supervise the writing, editing, and printing of course materials and ensure the timely delivery of instructional materials.\r\n•	Advise on the introduction of new courses.\r\n•	Take stock of instructional materials to determine needs.\r\n•	Ensure periodic reviews and updates of courses.\r\n•	Produce course brochures, periodicals, and other informational materials.\r\n•	Organise material development workshops for faculty.\r\n•	Ensure quality in the development and production of course materials.\r\n•	Submit quarterly reports to the Head of Department.', 'full-time', NULL, 0),
(288, 146, 'September,', NULL, 'Greenhill Int. School, Dome-CFC', 'Box AH2, Achimota', 'Teacher', 'Prepare lesson notes and teaching materials in line with the approved curriculum. \r\n\r\n Deliver effective teaching and learning activities to promote students’ academic development. \r\n\r\nMaintain discipline and order in the classroom to create a conducive learning environment. \r\nAssess, record, and evaluate students’ performance through tests, assignments, and examinations. \r\n\r\nProvide guidance and support to students on academic and personal matters where necessary. \r\n\r\nMark assignments and provide constructive feedback to improve students’ learning outcomes. \r\n\r\nKeep accurate records of attendance, assessments, and students’ progress.\r\n \r\nOrganize and supervise classroom activities, projects, and extracurricular programmes.\r\n \r\nEnsure the safety and welfare of students during school hours and school-related activities. \r\n\r\nCommunicate regularly with parents and guardians on students’ progress and behaviour. \r\nParticipate in staff meetings, workshops, seminars, and other professional development programmes. \r\n\r\nImplement school policies, rules, and regulations effectively. \r\n\r\nUse appropriate teaching methods and educational technologies to enhance learning. \r\n\r\nIdentify learners with special educational needs and provide the necessary support or referrals.', 'full-time', NULL, 1),
(289, 146, 'September,', NULL, 'Globen School, Tabora No 2, Accra', 'Box AN 7773, North Kaneshie', 'Teacher', 'Prepare lesson notes and teaching materials in line with the approved curriculum. \r\n\r\n Deliver effective teaching and learning activities to promote students’ academic development. \r\n\r\nMaintain discipline and order in the classroom to create a conducive learning environment. \r\nAssess, record, and evaluate students’ performance through tests, assignments, and examinations. \r\n\r\nProvide guidance and support to students on academic and personal matters where necessary. \r\n\r\nMark assignments and provide constructive feedback to improve students’ learning outcomes. \r\n\r\nKeep accurate records of attendance, assessments, and students’ progress.\r\n \r\nOrganize and supervise classroom activities, projects, and extracurricular programmes.\r\n \r\nEnsure the safety and welfare of students during school hours and school-related activities. \r\n\r\nCommunicate regularly with parents and guardians on students’ progress and behaviour. \r\nParticipate in staff meetings, workshops, seminars, and other professional development programmes. \r\n\r\nImplement school policies, rules, and regulations effectively. \r\n\r\nUse appropriate teaching methods and educational technologies to enhance learning. \r\n\r\nIdentify learners with special educational needs and provide the necessary support or referrals.', 'full-time', NULL, 2),
(290, 147, 'September,', NULL, 'Bonzali Community Bank PLC', 'Tamale', 'Head of Internal Audit', 'Provide independent assurance to the Board and Executive Management on governance, risk\r\nmanagement, internal controls, and regulatory compliance.\r\n• Develop and execute a risk-based annual internal audit plan aligned with strategic objectives,\r\nenterprise risk exposure, and regulatory expectations.\r\n• Lead internal audit engagements ensuring high-quality execution, timely reporting, and\r\nimplementation of value-adding recommendations.\r\n• Evaluate effectiveness of internal controls, financial reporting processes, and operational risk\r\nmanagement frameworks.\r\n• Identify control weaknesses, regulatory breaches, and emerging risks, and monitor remediation\r\nactions.\r\n• Review AML/RO accounts and compliance programmes in line with the Anti-Money\r\nLaundering Act, 2020 (Act 1044) and Bank of Ghana directives.', 'full-time', NULL, 0),
(291, 148, 'Jan. 2024', NULL, 'Bolgatanga Technical University', 'Bolgatanga Technical University Post Office Box 767 Sumburungu, Bolgatanga Ghana,', 'Full Stack Developer', 'Contributed to the development of the official university website, faculty sites, and Recruitment Management System. Assisted in Moodle LMS customization, File Management System implementation, and provided ICT technical support to improve digital infrastructure.', 'full-time', NULL, 0),
(292, 149, '2023 to Da', NULL, 'Bolgatanga Technical University', 'P. O. Box 767, Bolgatanga, U.E.R', 'Part-Time Lecturer', '•	Deliver high-quality lectures, tutorial sessions, and practical modules to undergraduate and Higher National Diploma (HND) students.\r\n•	Instruct core specialized courses, including Entrepreneurship, Financial Risk Management, Money and Banking, Principles of Financial Accouning, Principles of Micro Economics and Administrative Law.\r\n•	Design comprehensive course outlines, continuous assessment tests, and end-of-semester examinations in compliance with Commission for Technical and Vocational Education and Training (CTVET) guidelines.\r\n•	Provide academic counseling, supervise student group projects, and actively participate in departmental consultative meetings.', 'full-time', NULL, 0),
