(408, 194, '2019', '2019', 'ST JOHN CATHOLIC HOSPITAL', 'AKIM OFOASE', 'Head of Finance', '•	Lead the finance and administrative functions of the facility, overseeing financial reporting, budgeting, treasury, payroll, procurement, taxation, and management accounting operations. \r\n•	Prepare monthly, quarterly, and annual financial statements in compliance with IFRS and internal financial policies to support management decision-making. \r\n•	Coordinate annual budgeting and forecasting activities while monitoring budget performance and implementing corrective measures where necessary. \r\n•	Supervise Accounts Payable, Accounts Receivable, payroll, tax administration, and treasury functions to ensure operational efficiency and statutory compliance. \r\n•	Provide strategic leadership in procurement and supply chain management to enhance cost efficiency and operational continuity. \r\n•	Collaborate with auditors and regulatory stakeholders to ensure compliance with financial regulations and accountability standards. \r\n•	Support executive management in strategic planning, operational improvements, and organizational development initiatives. \r\n•	Oversee human resource administration, staff welfare, and workforce planning activities across the facility. \r\n•	Increased workforce strength from 62 employees to 120 employees within two years through strategic workforce planning and institutional expansion initiatives. \r\n•	Improved the organization’s accumulated fund (equity position) by 5.9% within a two-year period through prudent financial management and cost optimization strategies. \r\n•	Successfully prepared funding proposals that secured medical infrastructure and equipment support valued at approximately GHS 1.4 million, including a modern theatre and dispensary facility.', 'full-time', 'Transfer', 0),
(409, 194, '2018', '2018', 'Donald Richard Memorial Health Centre (National Catholic Health Service – Damongo Diocese)', 'Damongo', 'Accountant / Administrative Manager', '•	Managed the hospital’s accounting, budgeting, treasury, payroll, taxation, and statutory reporting functions. \r\n•	Prepared monthly and annual management reports and presented financial insights to diocesan leadership to support strategic decisions. \r\n•	Implemented financial controls, reconciliations, accrual accounting procedures, and expenditure monitoring mechanisms to improve financial accountability. \r\n•	Supervised administrative and human resource operations to enhance institutional efficiency and service delivery. \r\n•	Advised management on revenue improvement initiatives, cost reduction strategies, and financial sustainability measures. \r\n•	Strengthened the organization’s risk management framework and treasury control systems to improve financial governance and cash flow management.', 'full-time', 'Transfer', 1),
(410, 194, '2011', NULL, 'Kusawgu Health Centre (National Catholic Health Service – Damongo Diocese) |', 'Damongo', 'Accountant', '•	Prepared annual budgets, monitored budget variances, and implemented financial control measures to improve operational performance. \r\n•	Managed Accounts Payable, Accounts Receivable, payroll, taxation, treasury, and management accounting activities. \r\n•	Produced periodic financial statements and management reports for institutional leadership and key stakeholders. \r\n•	Supported organizational planning and operational reviews through financial analysis and performance reporting. \r\n•	Led stakeholder business review engagements focused on risk assessment, strategic planning, and operational improvement initiatives.', 'full-time', NULL, 2),
