(562, 264, '2003', NULL, 'Mon Computers (Work College)', 'Bolgatanga', 'Instructor/Technician', '1.	Train users and students on Microsoft Office and other software packages using MS Word, MS Excel, MS PowerPoint, MS Access, MS Publisher, Corel Draw etc.\r\n2.	Train users and students on dynamic website design and development using WYSIWYG, DREAMWEAVER, CSS, HTML,  JAVASCRIPT \r\n3.	Train students on programming methods such as C and C++.\r\n4.	Train students on Hardware, Networking and Wireless Networking \r\n5.	Perform software installation and troubleshooting', 'full-time', NULL, 8),
(563, 264, '2001', NULL, 'Computer World', NULL, 'Instructor/Technician', '1	Train users and students on Microsoft Office and other software packages using MS Word, MS Excel, MS PowerPoint, MS Access, MS Publisher, Corel Draw etc.\r\n2	Train users and students on dynamic website design and development using DREAMWEAVER, CSS, and HTML. And JAVASCRIPT \r\n3	Train students on programming methods such as C and C++.\r\n4	Perform software installation and troubleshooting', 'full-time', NULL, 9),
(564, 265, '2014-2026', NULL, 'TAMALE SENIOR HIGH SCHOOL', 'Tamale Senior High School.(NS025-8099)', 'Teacher / Academic Facilitator', '• Facilitated technical instruction in building technology and construction-related subjects.\r\n• Provided practical training in technical and analytical problem-solving.\r\n• Coordinated student project supervision and technical assessments.\r\n• Prepared technical reports and instructional materials.\r\n• Participated in institutional academic planning and curriculum implementation.', 'full-time', NULL, 0),
(565, 265, 'July 2015', NULL, 'Blesswiswen Ventures- Tamale', 'BOX 924, TAMALE', 'Construction Managing Director', '• Prepared AutoCAD building drawings and project documentation.\r\n• Developed Bills of Quantities (BOQ) and cost estimates.\r\n• Coordinated and supervised construction works and project activities.\r\n• Conducted project planning and construction scheduling support.\r\n• Ensured quality control and adherence to project specifications.\r\n• Interpreted technical drawings and supported project implementation.', 'full-time', NULL, 1),
(566, 265, 'JULY 2011-', NULL, 'China Harbour Engineering Company Ltd. (CHEC)-', 'SAWLA , SANANNA REGION', 'Construction Engineer (Draughtsman / Building Supervisor)', '• Prepared architectural and technical drawings using AutoCAD.\r\n• Interpreted engineering and architectural drawings for project implementation.\r\n• Conducted measurement and billing of construction works.\r\n• Supervised and coordinated construction site activities.\r\n• Monitored quality compliance and project execution processes.\r\n• Assisted in resolving technical and operational site challenges.', 'full-time', NULL, 2),
(567, 266, '1/ 10/ 202', '22/12/2022', 'Dizengoff Ghana', 'Accra', 'Seed business manager', 'Responsibilities\r\n- Sales &amp; Marketing: Generate sales pipeline, achieve targets, conduct seed demonstrations, and lead promotion activities\r\n- Stakeholder Management: Build relationships with farmers, input dealers, field promoters, and MOFA\r\n- Field Trials: Coordinate trials with key farmers, gather performance data, and document results for promotion\r\n- Strategic Planning: Develop sales strategies, budgets, trek plans, and market penetration approaches\r\n-Team Leadership: Supervise field promoters, manage recruitment, and provide team support\r\n- Events: Organize farmers\' days and seed conferences to showcase varieties and drive commercialization\r\n- Coordinate the importation and registration of current and new seed varieties.', 'full-time', NULL, 0),
(568, 266, '1/09/2019', NULL, 'Integrated Water and Agricultural Development Ghana Limited', 'Yagaba, Northeast region', 'Farm foreman', 'Responsibilities\r\n\r\nDaily Farm Operations\r\n- Supervise day-to-day farming activities (planting, irrigation, fertilization, pest management, harvesting, storage)\r\n- Ensure tasks are completed on schedule\r\n- Monitor crop conditions and report issues\r\n\r\nStaff Supervision\r\n- Supervise and coordinate farm workers and laborers\r\n- Assign daily tasks and monitor performance\r\n- Train staff on good agronomic practices\r\n- Ensure staff adhere to health and safety regulations\r\n\r\nCrop Management\r\n- Oversee seed crop production (maize, rice, soybean, cowpea, groundnut, sugarcane)\r\n- Monitor planting and harvesting schedules\r\n- Ensure proper field maintenance\r\n- Report crop health issues to Farm Manager\r\n\r\nInput &amp; Equipment Management\r\n- Ensure seeds, fertilizers, pesticides are properly stored and restocked\r\n- Schedule equipment maintenance and repairs\r\n- Monitor proper use of farm machinery\r\n\r\nDocumentation &amp; Reporting\r\n- Maintain farm activity records\r\n- Report to Farm Manager on daily operations\r\n- Document workforce attendance and productivity\r\n\r\nTraining &amp; Extension\r\n- Train smallholder farmers on good agronomic practices.\r\n- Provide technical guidance on rice/seed production', 'full-time', NULL, 1),
(569, 267, 'March 2020', NULL, 'College of Health, Nalerigu', 'P.O. Box 10, Nalerigu', 'Senior Health Tutor', 'I teach General Mathematics, Statistics, Biostatistics, Demography, Research Methodology, Data Analysis and Interpretation, Health Informatics, Computer Studies. Also, I am presently the Deputy Head, Research and Innovations Unit of the College.', 'full-time', NULL, 0),
(570, 268, 'Aug 2023 t', 'Dec 2022', 'Wofford College', 'Spartanburg, South Carolina, USA', 'Visiting Assistant Professor', '• Created materials and taught six classes in environmental studies including three with labs and field-based learning. (3 preparations)\r\n    • Led a collaborative summer research project (budget: $9,436) with three student assistants about the origin of life on icy worlds.\r\n    • Ad hoc committee chair for creating signage in our community garden and supervised the community garden student workers\r\n    • Student club advisor: United Nations of America\r\n    • Contributed to department meetings and various tasks as needed, e.g. transported department vehicle to the shop for repairs\r\n    • Attended faculty meetings and first-year faculty development activities\r\n    • Participated in prospective-student classroom observations and filming of my teaching and research for college promotion', 'full-time', 'End of contract', 0),
(571, 268, 'Jan 2020', 'Dec 2018', 'College of Micronesia, FSM - Yap Campus', 'Yap, Federated States of Micronesia', 'Instructor', '• Taught fourteen different pedagogy courses in the statewide teacher training program, for the pre-service and in-service teachers, including online undergraduate instruction\r\n    • Taught physical science and biology courses with lab components\r\n    • Taught introductory philosophy and art classes for undergraduates\r\n    • Facilitated and developed materials for student advising. Typically had 50 advisees per semester, and supported their needs. Helped students choose classes and register\r\n    • Assisted with accreditation processes with WASC to allow for distance learning for the college\r\n    • Applied for grants to support the agricultural extension program\r\n    • Chair of the Grant Review Team for the college (elected Nov. 2021) and designed our Grants Review Handbook and several administrative forms related to grants, also initiated developing a 3rd Year Certificate Program in Grantwriting for the college.\r\n    • Chair of an ad hoc employment committee for hiring a new art professor in 2023.\r\n    • Updated course outlines for classes in religion, geology and playwriting for the college\r\n    • Taught Upward Bound classes in chemistry, physics and biology to high school students in Yap, Micronesia (Jan 2020 to May 2021)\r\n    • Taught a community outreach lesson on the island of Woleai\r\n    • Taught a community outreach lesson for Early Childhood Education', 'full-time', 'End of contract', 1),
(572, 268, 'Oct 2017', 'Sep 2009', 'Ton Duc Thang University', 'Ho Chi Minh City, Vietnam', 'Lecturer &amp; Researcher', '• Taught courses and developed teaching materials for students training for jobs in labor relations and human resources\r\n    • Planned an international conference for the department\r\n    • Participated in the university\'s accreditation process\r\n    • Assisted with the hiring process for the department\r\n    • Participated in outreach for the university\r\n    • Assisted colleagues in revising research for publication\r\n    • Lived on campus and helped Vietnamese students practice English\r\n    • Revised the university\'s Wikipedia page\r\n    • Edited materials for the department website', 'part-time', 'To focus on graduate degree studies', 2),
(573, 268, 'Sep 2007', NULL, 'California State University Long Beach', 'Long Beach, California, USA', 'Teaching Associate', '• Taught undergraduate courses and developed teaching materials in geological sciences\r\n    • Assisted other teaching associates in developing their teaching practices', 'full-time', NULL, 3),
(574, 269, 'September,', NULL, 'Kintampo Senior High School', 'Box 65 Kintampo North', 'Teachere', '•	ChrisdArt Cave Inn Designer (2022 – Present) – Execute designs and printing Graphics items for individuals and organizations. Provide technical advice to clients.\r\n•	Form Master, Kintampo SHS, Kintampo (2019 – Present) – Monitored student welfare, performance, and discipline; coordinated with administration.\r\n•	Subject Head (Graphic Design), Kintampo SHS, Kintampo (2020 – Present) – Led subject planning, examinations, resource procurement, and teacher coordination.\r\n•	Safe Space Focal Person, (Sexual Harassment) Kintampo SHS. (2025-Present) \r\n•	Value Learning Community Coordinator', 'full-time', NULL, 0),
