(611, 290, 'Nov 2023', NULL, 'Twellium Industries Company Ltd', 'Kaase, Kumasi, Email: administration@twellium.com, Phone : +233242813772', 'Operator Technician', '•	Operate and Monitor the console that controls the Automatic Robotic Palletizing process to ensure \r\nproper alignment, positioning, and stacking of products, making adjustments as required to maintain\r\n accuracy and efficiency. \r\n•	Operate Robopac Stretch Wrapping equipment and assure stretch wrapping and corner boards.\r\n•	Troubleshooting operational issues following all safety protocols\r\n•	Conduct routine maintenance tasks, such as lubricating, cleaning and inspection, to ensure optimal performance and prevent equipment downtime.\r\n•	Troubleshoot equipment malfunctions and perform repairs as needed, collaborating with maintenance personnel and equipment manufacturers.\r\n•	Adhere to Safety Protocols and guidelines at all times, including the use of personal protective \r\nequipment (PPE) and adherence to lockout/tag out procedures.\r\n•	Keep a detailed record of production and equipment performance.', 'full-time', NULL, 2),
(612, 290, 'April 2016', NULL, 'Ostec IT Ghana', '3rd Floor of The Grand Oyeeman Building (near the Opeibea House) on Liberation Road in the Airport Residential Area, Accra. Email: info@ostecit.com, Phone: +233(0)302240121', 'Data Centre support engineer', '•	System Maintenance: Regularly maintain computer systems and networks for optimal performance.\r\n•	Efficiency Improvements: Identify and address power and cooling system inefficiencies.\r\n•	Network Monitoring: Ensure local and wide area networks perform at their best.\r\n•	Data Backup: Perform system backups to safeguard important data.\r\n•	Troubleshooting: Diagnose and resolve computer and network issues.\r\n•	Record Keeping: Maintain work records and provide reports to superiors.\r\n•	Customer Support: Assist clients with technical problems via phone or in person.\r\n•	Inventory Management: Keep equipment and tools in stock and readily available.\r\n•	Client Communication: Communicate with clients to set up systems and resolve issues.\r\n•	Relationship Building: Build trust with clients and collaborate with specialists.\r\n•	Supply Inventory: Manage data center supplies inventory.\r\n•	Vendor Support: Handle technical requests with third-party vendors', 'full-time', NULL, 3),
(613, 291, 'September,', NULL, 'Awe Senior High Technical School', 'P O Box 105, Navrongo', 'Teacher', 'I taught the following subjects: Graphic Design, General Knowledge in Art and Sculpture.\r\nI also performed the following duties:\r\n	Supervised teachers\r\n	Vetted lesson notes &amp; teaching notes\r\n	Supervises Visual Art students’ final WASSCE practicals / projects\r\n	Wrote reports', 'full-time', NULL, 0),
(614, 292, 'November 2', NULL, 'Millar Open University', 'Millar Institute for Transdisciplinary and Development Studies Postal Box 607 Bolgatanga.', 'Lecturer and Head of Quality Assurance.', 'Lecturer for Sociology and Society, Culture studies, and Culture and Diasporanism.\r\n\r\nSupervise, monitor, coordinate, and collate reports on the day-to-day quality of academic work, welfare, and interaction within the University.', 'full-time', NULL, 0),
(615, 292, 'Jan 2022', NULL, 'Ghana Education Service', 'Regional Education Office  Bolgatanga Box110', 'Regional Coordinator for Basic Schools in the Upper East Region', 'Ensure effective implementation of educational policies at the basic schools in the region.\r\n\r\nMonitor the supply and distribution of &quot;TLMs&quot; to basic schools in the region.\r\n\r\nCheck overstaffing and understaffing in all public basic schools in the region.\r\n\r\n Collate reports on all public basic schools in the region.', 'full-time', NULL, 1),
(616, 294, 'July 2023', NULL, 'Mandilas Ghana Limited', 'Plot 87 Spintex Road, Accra Ghana', 'Accounts Officer', 'Financial Reporting and Analysis \r\nBudgeting and Variance Analysis \r\nTax Compliance and Filing \r\nAccounts Payable and Receivable \r\nmanagement \r\nInventory management \r\nJournal entries and Ledger maintenance \r\nBank and Account Reconciliations (Foreign and Local currency)\r\nExternal Audit Support', 'full-time', NULL, 0),
