(623, 298, 'August, 20', 'May, 2026', 'Ghana Education Service', 'Awe SHTS, Box 105, Navrongo', 'Science teacher', 'The subjects I teach include; general science, agricultural science, and chemistry.\r\nI also serviced as a form master and a housemaster', 'full-time', 'I still work at UEW-CODeL Navrongo Syudy Centre as a lecturer', 0),
(624, 298, 'June, 2018', NULL, 'University of Education, Winneba (CODeL)- Navrongo Study center', 'University of Education, Winneba, College of Distance and e-Learning, Navrongo Study Center', 'Part-time Lecturer', 'The courses I lecture include, Integrated Science for both BSc. in Basic Education and Early grade.\r\nI also supervise students project works', 'full-time', NULL, 1),
