INSERT INTO `employment_entries` (`id`, `application_id`, `from_date`, `to_date`, `institution_name`, `institution_address`, `position`, `subject_work`, `nature`, `reason_for_leaving`, `sort_order`) VALUES
(626, 300, '1ST MARCH ', 'FEBRUARY 2', 'GOWRIE SENIOR HIGH TECHNICAL SCHOOL', 'GOWRIE SHTS, P. O. BOX 746, BOLGATANGA, UPPER EAST REGION.', 'ICT AND COMPUTING TEACHER', 'I have twelve (12) years of experience in the teaching field as a teacher. As an ICT and computing teacher and form master, I have the following as my duties:\r\n1.	Giving lessons in Information and Communications Technology (ICT) and computing subjects and supervising students’ classwork.\r\n2.	Preparing, assigning and correcting class exercises.\r\n3.	Administering and marking test and examinations to evaluate students’ progress\r\n4.	Preparing reports about students\' work.\r\n5.	Preparing a weekly forecast of lessons, which is the scheme of work for each semester/term in the year.\r\n6.	Preparing weekly lesson notes that are the expanded scheme of work.\r\n7.	Preparing Teaching and Learning Materials (TLMs)\r\n8.	Carrying out co-curricular activities, including field trips, sporting and cultural activities.\r\n9.	Preparing students to acquire skills.\r\n10.	Invigilation of examinations; end-of-semester examinations, the Basic Education Certificate Examination (BECE) and the West African Senior School Certificate Examination.\r\n11.	Checking of students’ behaviour and counselling them.', 'full-time', 'I has an appointment with Ghana Education Service', 0),
(627, 300, 'SEPTEMBER ', NULL, 'Bethel International Academy, Kumasi', 'Bethel International Academy, P.O. Box UP 909 KNUST - Kumasi', 'ICT TEACHER AND HEAD OF DEPARTMENT', 'Giving lessons in the Information and Communications Technology (ICT) subject and supervising students’ classwork.', 'full-time', NULL, 1),
