(10, 'Lecturer', 'Computing and Information Technology Department', 'full-time', 'Sumbrungu', 'Professors/Associate Professors/Snr. Lecturer/Lecturer: Computing and Information Technology Department\r\nTeaching\r\n1. Curriculum development \r\n2. Setting and marking of assignments and examination questions \r\n3. Invigilation of examinations \r\n4. Submission of marked scripts and results\r\n5. Supervision of students’ project work, dissertations, and theses \r\n6. Offering academic counseling to students \r\n7. Supervision of students’ internship and industrial visits', 'Professors/Associate Professors\r\nA person seeking appointment as a Professor/Associate Professor must have a terminal degree (PhD) in a relevant subject area and must have also attained the position of Professor or Associate Professor from a recognized tertiary institution at the time of application. \r\nIn addition, he/she must have:\r\ntaught for a minimum of four (4) years as Professor/Associate Professor\r\nevidence of practical and applied scientific research and industry-related innovation\r\ndemonstrated the ability to conduct independent research\r\nmembership of a recognized professional body will be an added advantage  \r\n\r\nSenior Lecturers: \r\nA person seeking appointment as a Senior Lecturer must: \r\npossess a terminal degree (PhD) in the relevant field of specialization\r\nhave taught for a minimum of four (4) years as a Senior Lecturer \r\nhave evidence of practical and applied scientific research and industry-related innovation shall require\r\ndemonstrate the ability to conduct independent research. \r\n\r\nLecturers\r\nApplicant must have a terminal degree (PhD) in a relevant subject area. Post qualification experience in a Lecturer’s grade from a recognized tertiary institution will be an added advantage.', '', '2026-06-03', 'open', 1, '2026-05-19 13:58:36'),
(11, 'Driver', 'Transport Unit', 'full-time', 'Sumbrungu', 'The Driver shall assist the Transport Officer in the overall management and administration of the Transport Section and perform duties which shall include driving, ensuring cleanliness of vehicles, repairs and maintenance of the University’s vehicles.', 'The applicant must possess a minimum of a valid Driving License ‘D’ - ‘F’ and must have at least three BECE passes. GCE ‘O’ Level/SSSCE/WASSCE Certificate shall be an added advantage.', '', '2026-06-03', 'open', 1, '2026-05-19 14:01:56'),
(12, 'Lecturer', 'Mining Engineering', 'full-time', 'Sumbrungu', 'Professors/Associate Professors/Snr. Lecturer/Lecturer: Mining Engineering\r\nTeaching\r\n1. Curriculum development \r\n2. Setting and marking of assignments and examination questions \r\n3. Invigilation of examinations \r\n4. Submission of marked scripts and results\r\n5. Supervision of students’ project work, dissertations, and theses \r\n6. Offering academic counseling to students \r\n7. Supervision of students’ internship and industrial visits', 'Professors/Associate Professors\r\nA person seeking appointment as a Professor/Associate Professor must have a terminal degree (PhD) in a relevant subject area and must have also attained the position of Professor or Associate Professor from a recognized tertiary institution at the time of application. \r\nIn addition, he/she must have:\r\ntaught for a minimum of four (4) years as Professor/Associate Professor\r\nevidence of practical and applied scientific research and industry-related innovation\r\ndemonstrated the ability to conduct independent research\r\nmembership of a recognized professional body will be an added advantage  \r\n\r\nSenior Lecturers: \r\nA person seeking appointment as a Senior Lecturer must: \r\npossess a terminal degree (PhD) in the relevant field of specialization\r\nhave taught for a minimum of four (4) years as a Senior Lecturer \r\nhave evidence of practical and applied scientific research and industry-related innovation shall require\r\ndemonstrate the ability to conduct independent research. \r\n\r\nLecturers\r\nApplicant must have a terminal degree (PhD) in a relevant subject area. Post qualification experience in a Lecturer’s grade from a recognized tertiary institution will be an added advantage.', '', '2026-06-03', 'open', 1, '2026-05-19 14:04:17'),
(13, 'Senior ICT Assistant (Software Developer)', 'ICT Directorate', 'full-time', 'Sumbrungu', 'The Senior ICT Assistant will support academic and administrative functions through the following duties:\r\n•	Software Development and Maintenance: Develop, test, and deploy web applications. Maintain and upgrade existing university systems, including legacy software, Student Information Systems (SIS), and Learning Management Systems (LMS).\r\n•	System Integration: Integrate third-party APIs and internal databases to streamline data flow across departments such as Finance Directorate, Academic Affairs Directorate and Examination Unit.\r\n•	Conduct code reviews, debugging, and performance tuning. Monitor system logs to fix bottlenecks, and implement data security best practices to protect sensitive student and research data.\r\n•	Work with faculty, staff, and IT teams to gather technical requirements. Provide technical documentation, training materials, and high-level support for complex software failures.', 'A person seeking appointment as a Senior ICT Assistant must:\r\n•	possess a minimum of a Bachelor’s Degree (or equivalent) in ICT, Computer Science, Computer Engineering, or a related discipline. Must have the following essential technical skills: Proficiency in programming languages such as Python, Java, PHP, or JavaScript (Node.js); Ability to design and manage SQL-based systems (e.g., MySQL, PostgreSQL, or SQL Server); Experience with RESTful APIs, integration techniques, and modern web frameworks like React or Angular.\r\n•	minimum of four (4) years working experience as an ICT Assistant in a comparable grade within a similar institution or organization.\r\n•	have professionalism in the area of specialization; \r\n•	have high initiative and resourcefulness; \r\n•	have high qualities of sound judgement;', '', '2026-06-03', 'open', 1, '2026-05-19 14:16:19'),
(14, 'Accountant', 'Finance Directorate', 'full-time', 'Sumbrungu, Bolgatanga', 'The accountant shall assist the Director of Finance in the overall management and administration of the office functions as provided for in the Technical University Act, 2016 (Act 922).\r\nBe analytical, critical, result-oriented, innovative, and visionary\r\nPossess hands-on ability to work independently \r\nPossess excellent communication, interpersonal, and supervisory skills\r\nPossess strong IT skills and familiarity with accounting software\r\nBe able to work under pressure to meet deadlines \r\nBe a good team player', 'A person seeking appointment as an Accountant must:\r\nbe a Chartered Accountant and hold a Master’ degree in the relevant field. \r\nhave served as an Assistant Accountant in a University or comparable grade in a similar institution/organization for at least two (2) years  \r\nbe computer literate and be conversant with accounting software applications\r\nhave ability to work independently; \r\nhave ability to work under pressure to meet deadlines', '', '2026-06-03', 'open', 1, '2026-05-19 14:18:27'),
(15, 'Assistant Registrar', 'Registry', 'full-time', 'Sumbrungu, Bolgatanga', 'Assistant Registrar\r\nThe Assistant Registrar shall assist the Registrar in all administrative, secretarial and human resource development and management matters of the University.', 'A person seeking appointment as Assistant Registrar must:\r\nhold at least a Masters’ degree preferably in Administration and Management related area. \r\nhave a minimum of two (2) year post qualification experience as Junior Assistant Registrar in a University or comparable grade in a similar institution.\r\nhave the ability to work under pressure to meet deadlines\r\nMinimum of four (4) years working experience', '', '2026-06-03', 'open', 1, '2026-05-19 14:19:15'),
(16, 'Lecturer', 'Communication Design and Applied Art Department', 'full-time', 'Sumbrungu, Bolgatanga', 'Professors/Associate Professors/Snr. Lecturer/Lecturer: Communication Design or Graphic Design\r\nTeaching\r\n1. Curriculum development \r\n2. Setting and marking of assignments and examination questions \r\n3. Invigilation of examinations \r\n4. Submission of marked scripts and results\r\n5. Supervision of students’ project work, dissertations, and theses \r\n6. Offering academic counseling to students \r\n7. Supervision of students’ internship and industrial visits', 'Professors/Associate Professors\r\nA person seeking appointment as a Professor/Associate Professor must have a terminal degree (PhD) in a relevant subject area and must have also attained the position of Professor or Associate Professor from a recognized tertiary institution at the time of application. \r\nIn addition, he/she must have:\r\ntaught for a minimum of four (4) years as Professor/Associate Professor\r\nevidence of practical and applied scientific research and industry-related innovation\r\ndemonstrated the ability to conduct independent research\r\nmembership of a recognized professional body will be an added advantage  \r\n\r\nSenior Lecturers: \r\nA person seeking appointment as a Senior Lecturer must: \r\npossess a terminal degree (PhD) in the relevant field of specialization\r\nhave taught for a minimum of four (4) years as a Senior Lecturer \r\nhave evidence of practical and applied scientific research and industry-related innovation shall require\r\ndemonstrate the ability to conduct independent research. \r\n\r\nLecturers\r\nApplicant must have a terminal degree (PhD) in a relevant subject area. Post qualification experience in a Lecturer’s grade from a recognized tertiary institution will be an added advantage.', '', '2026-06-03', 'open', 1, '2026-05-20 11:41:25');
